INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631000,1,'MongoDB 教程','MongoDB是一个流行的开源文档型数据库，它使用类似 JSON 的文档模型存储数据，这使得数据存储变得非常灵活。 MongoDB 是一个基于文档的 NoSQL 数据库，由 MongoDB Inc. 开发。 MongoDB 旨在为 WEB 应用提供可扩展的高性能数据存储解决方案。 MongoDB 是一个介于关系数据库和非关系数据库之间的产品，是非关系数据库当中功能最丰富，最像关系数据库的。','# MongoDB 教程\n\n![图片](/api/uploads/files/runoob/mongodb/mongodb-logo-2407102a13.png)\n\nMongoDB是一个流行的开源文档型数据库，它使用类似 JSON 的文档模型存储数据，这使得数据存储变得非常灵活。\n\nMongoDB 是一个基于文档的 NoSQL 数据库，由 MongoDB Inc. 开发。\n\nMongoDB 旨在为 WEB 应用提供可扩展的高性能数据存储解决方案。\n\nMongoDB 是一个介于关系数据库和非关系数据库之间的产品，是非关系数据库当中功能最丰富，最像关系数据库的。\n\n[现在开始学习 MongoDB！](https://www.runoob.com/mongodb/nosql.html)\n\n## MongoDB 特点\n\nMongoDB 的一些关键特点：\n\n- 文档导向：MongoDB 存储 BSON（二进制 JSON）文档，这些文档可以包含复杂的数据结构，如数组和嵌套对象。\n- 高性能：MongoDB 提供了高性能的数据持久化和查询能力，特别是对于写入密集型的应用。\n- 水平扩展：通过分片（sharding）技术，MongoDB 可以在多个服务器之间分布数据，实现水平扩展。\n- 高可用性：MongoDB 支持副本集（replica sets），提供数据的自动故障转移和数据冗余。\n- 灵活的聚合框架：MongoDB 提供了一个强大的聚合框架，允许执行复杂的数据处理和聚合操作。\n- 丰富的查询语言：MongoDB 的查询语言（MQL）支持丰富的查询操作，包括文本搜索、地理位置查询等。\n- 存储过程：MongoDB 支持在数据库内部执行 JavaScript 代码，允许定义和执行复杂的数据处理逻辑。\n- GridFS：对于存储大于 BSON 文档大小限制（16MB）的文件，MongoDB 提供了 GridFS，一种用于存储和检索大文件的规范。\n- 安全性：MongoDB 提供了多层次的安全特性，包括认证、授权和加密。\n- 驱动程序和工具：MongoDB 拥有广泛的驱动程序支持，适用于不同的编程语言，以及各种管理工具和可视化界面。\n- 社区和生态系统：MongoDB 拥有一个活跃的开发者社区，提供了大量的教程、文档和第三方工具。\n\nMongoDB 的这些特性使其成为一个非常灵活和功能丰富的数据库解决方案，尤其适合处理大量的半结构化或非结构化数据。\n\n## 参考地址\n\nMongoDB 官网地址：[https://www.mongodb.com/](https://www.mongodb.com/)\n\nMongoDB 官方英文文档：[https://docs.mongodb.com/manual/](https://docs.mongodb.com/manual/)\n\nMongoDB 各平台下载地址：[https://www.mongodb.com/try/download/community](https://www.mongodb.com/try/download/community)\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-tutorial.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-tutorial','MongoDB 教程 - MongoDB 教程','MongoDB是一个流行的开源文档型数据库，它使用类似 JSON 的文档模型存储数据，这使得数据存储变得非常灵活。 MongoDB 是一个基于文档的 NoSQL 数据库，由 MongoDB Inc. 开发。 MongoDB 旨在为 WEB ...',0,'PUBLISHED',2637,87,50,9,'2025-07-01 00:00:00','2025-07-01 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631001,1,'NoSQL 简介','NoSQLNoSQL = Not Only SQL ，意即"不仅仅是SQL"。 在现代的计算系统上每天网络上都会产生庞大的数据量。 这些数据有很大一部分是由关系数据库管理系统（RDBMS）来处理。 1970年 E.F.Codd\'s提出的关系模型的论文 "A relational model of data for large shared data banks"，这使得数据建模和应用程序编程更加简单。 通过应用实践证明，关系模型是非常适合于客户服务器编程，远远超出预期的利益，今天它是结构化数据存储在网络和商务应用的主导技术。','# NoSQL 简介\n\nNoSQL(NoSQL = Not Only SQL )，意即"不仅仅是SQL"。\n\n在现代的计算系统上每天网络上都会产生庞大的数据量。\n\n这些数据有很大一部分是由关系数据库管理系统（RDBMS）来处理。 1970年 E.F.Codd\'s提出的关系模型的论文 "A relational model of data for large shared data banks"，这使得数据建模和应用程序编程更加简单。\n\n通过应用实践证明，关系模型是非常适合于客户服务器编程，远远超出预期的利益，今天它是结构化数据存储在网络和商务应用的主导技术。\n\nNoSQL 是一项全新的数据库革命性运动，早期就有人提出，发展至2009年趋势越发高涨。NoSQL的拥护者们提倡运用非关系型的数据存储，相对于铺天盖地的关系型数据库运用，这一概念无疑是一种全新的思维的注入。\n\n事务在英文中是transaction，和现实世界中的交易很类似，它有如下四个特性：\n1、A (Atomicity) 原子性\n\n原子性很容易理解，也就是说事务里的所有操作要么全部做完，要么都不做，事务成功的条件是事务里的所有操作都成功，只要有一个操作失败，整个事务就失败，需要回滚。\n\n比如银行转账，从A账户转100元至B账户，分为两个步骤：1）从A账户取100元；2）存入100元至B账户。这两步要么一起完成，要么一起不完成，如果只完成第一步，第二步失败，钱会莫名其妙少了100元。\n2、C (Consistency) 一致性\n\n一致性也比较容易理解，也就是说数据库要一直处于一致的状态，事务的运行不会改变数据库原本的一致性约束。\n\n例如现有完整性约束a+b=10，如果一个事务改变了a，那么必须得改变b，使得事务结束后依然满足a+b=10，否则事务失败。\n\n3、I (Isolation) 独立性\n\n所谓的独立性是指并发的事务之间不会互相影响，如果一个事务要访问的数据正在被另外一个事务修改，只要另外一个事务未提交，它所访问的数据就不受未提交事务的影响。\n\n比如现在有个交易是从A账户转100元至B账户，在这个交易还未完成的情况下，如果此时B查询自己的账户，是看不到新增加的100元的。\n\n4、D (Durability) 持久性\n\n持久性是指一旦事务提交后，它所做的修改将会永久的保存在数据库上，即使出现宕机也不会丢失。\n\n分布式系统（distributed system）由多台计算机和通信的软件组件通过计算机网络连接（本地网络或广域网）组成。\n\n分布式系统是建立在网络之上的软件系统。正是因为软件的特性，所以分布式系统具有高度的内聚性和透明性。\n\n因此，网络和分布式系统之间的区别更多的在于高层软件（特别是操作系统），而不是硬件。\n\n分布式系统可以应用在不同的平台上如：Pc、工作站、局域网和广域网上等。\n\n可靠性（容错） ：\n\n分布式计算系统中的一个重要的优点是可靠性。一台服务器的系统崩溃并不影响到其余的服务器。\n\n可扩展性：\n\n在分布式计算系统可以根据需要增加更多的机器。\n\n资源共享：\n\n共享数据是必不可少的应用，如银行，预订系统。\n\n灵活性：\n\n由于该系统是非常灵活的，它很容易安装，实施和调试新的服务。\n\n更快的速度：\n\n分布式计算系统可以有多台计算机的计算能力，使得它比其他系统有更快的处理速度。\n\n开放系统：\n\n由于它是开放的系统，本地或者远程都可以访问到该服务。\n\n更高的性能：\n\n相较于集中式计算机网络集群可以提供更高的性能（及更好的性价比）。\n\n故障排除：\n\n故障排除和诊断问题。\n\n软件：\n\n更少的软件支持是分布式计算系统的主要缺点。\n\n网络：\n\n网络基础设施的问题，包括：传输问题，高负载，信息丢失等。\n\n安全性：\n\n开放系统的特性让分布式计算系统存在着数据的安全性和共享的风险等问题。\n\n\n\t\t\t\t特点\n\n\n\t\t\t\t列存储\n\nHbase\n\nCassandra\n\nHypertable\n\n顾名思义，是按列存储数据的。最大的特点是方便存储结构化和半结构化数据，方便做数据压缩，对针对某一列或者某几列的查询有非常大的IO优势。\n\n文档存储\n\nMongoDB\n\nCouchDB\n\n文档存储一般用类似json的格式存储，存储的内容是文档型的。这样也就有机会对某些字段建立索引，实现关系数据库的某些功能。\n\nkey-value存储\n\nTokyo Cabinet / Tyrant\n\nBerkeley DB\n\nMemcacheDB\n\nRedis\n\n可以通过key快速查询到其value。一般来说，存储不管value的格式，照单全收。（Redis包含了其他功能）\n\n图存储\n\nNeo4J\n\nFlockDB\n\n图形关系的最佳存储。使用传统关系数据库来解决的话性能低下，而且设计使用不方便。\n\n对象存储\n\ndb4o\n\nVersant\n\n通过类似面向对象语言的语法操作数据库，通过对象的方式存取数据。\n\nxml数据库\n\nBerkeley DB XML\n\nBaseX\n\n高效的存储XML数据，并支持XML的内部查询语法，比如XQuery,Xpath。\n\n\n现在已经有很多公司使用了 NoSQL：\n\n- Google\n- Facebook\n- Mozilla\n- Adobe\n- Foursquare\n- LinkedIn\n- Digg\n- McGraw-Hill Education\n- Vermont Public Radio\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/nosql.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-nosql','NoSQL 简介 - MongoDB 教程','NoSQLNoSQL = Not Only SQL ，意即"不仅仅是SQL"。 在现代的计算系统上每天网络上都会产生庞大的数据量。 这些数据有很大一部分是由关系数据库管理系统（RDBMS）来处理。 1970年 E.F.Codd\'s提出的关系...',0,'PUBLISHED',2774,94,55,10,'2025-07-02 00:00:00','2025-07-02 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631002,1,'MongoDB 简介','MongoDB 是一个文档型数据库，数据以类似 JSON 的文档形式存储。 MongoDB 的设计理念是为了应对大数据量、高性能和灵活性需求。 MongoDB使用集合（Collections）来组织文档（Documents），每个文档都是由键值对组成的。 MongoDB 将数据存储为一个文档，数据结构由键值key=>value对组成，文档类似于 JSON 对象，字段值可以包含其他文档，数组及文档数组：','## 什么是 MongoDB ?\n\nMongoDB 是一个文档型数据库，数据以类似 JSON 的文档形式存储。\n\nMongoDB 的设计理念是为了应对大数据量、高性能和灵活性需求。\n\nMongoDB使用集合（Collections）来组织文档（Documents），每个文档都是由键值对组成的。\n\n- 数据库（Database）：存储数据的容器，类似于关系型数据库中的数据库。\n- 集合（Collection）：数据库中的一个集合，类似于关系型数据库中的表。\n- 文档（Document）：集合中的一个数据记录，类似于关系型数据库中的行（row），以 BSON 格式存储。\n\nMongoDB 将数据存储为一个文档，数据结构由键值(key=>value)对组成，文档类似于 JSON 对象，字段值可以包含其他文档，数组及文档数组：\n\n![图片](/api/uploads/files/runoob/mongodb/crud-annotated-document-3e69779f3a.png)\n\n## 主要特点\n\n- 文档导向的存储：MongoDB 是一个面向文档的数据库，它以 JSON-like 的格式存储数据，使得数据结构更加灵活和丰富。\n- 索引优化查询：MongoDB 允许用户为文档中的任意属性创建索引，例如 `FirstName` 和 `Address`，从而提高查询效率和排序性能。\n- 数据镜像与扩展性：通过本地或网络创建数据的副本，MongoDB 实现了强大的数据冗余和扩展能力。\n- 水平扩展与分片：面对增加的负载，MongoDB 可以通过分片技术将数据分布到计算机网络中的其他节点上，实现水平扩展。\n- 强大的查询语言：MongoDB 使用 JSON 格式的查询语法，支持复杂的查询表达式，包括对内嵌对象和数组的查询。\n- 数据更新：利用 `update()` 命令，MongoDB 能够替换整个文档或更新指定的数据字段，提供了灵活的数据更新方式。\n- MapReduce 批量处理：MongoDB 的 MapReduce 功能专为大规模数据处理和聚合操作设计，通过 Map 函数的 `emit(key, value)` 调用和 Reduce 函数的逻辑处理，实现高效的数据汇总。\n- MapReduce 脚本编写：Map 和 Reduce 函数使用 JavaScript 编写，可以通过 `db.runCommand` 或 `mapreduce` 命令在 MongoDB 中执行。\n- GridFS 大文件存储：GridFS 是 MongoDB 内置的功能，用于存储和检索大于 BSON 文档大小限制的文件，如图片和视频。\n- 服务端脚本执行：MongoDB 允许在服务端执行 JavaScript 脚本，提供了直接在服务端执行或存储函数定义以供后续调用的能力。\n- 多语言支持：MongoDB 提供了对多种编程语言的支持，包括但不限于 RUBY、PYTHON、JAVA、C++、PHP 和 C#。\n- 安装简单：MongoDB 的安装过程简单直观，便于用户快速部署和使用。\n\n## 历史\n\n| 版本 | 发布日期 | 特性说明 |\n| --- | --- | --- |\n| 1.0 | 2009年8月 | 每个集合更多的索引 更快的索引创建 |\n| 1.2 | 2009年12月 | Map/Reduce 存储的 JavaScript 函数 可配置的 fsync 时间 几个小特性和修复 |\n| 1.4 | 2010年3月 | 生产就绪的分片(sharding) |\n| 1.6 | 2010年8月 | 副本集(replica sets) 支持 IPv6 |\n| 1.8 | 2011年3月 |  |\n| 2.0 | 2011年9月 |  |\n| 2.2 | 2012年8月 | 增强的地理空间支持 切换到 V8 JavaScript 引擎 |\n| 2.4 | 2013年3月 | 安全性增强 文本搜索(beta) 哈希索引 聚合增强 文本搜索集成 |\n| 2.6 | 2014年4月8日 | 查询引擎改进 新的写操作协议 安全性增强 WiredTiger 存储引擎支持 可插拔存储引擎 API |\n| 3.0 | 2015年3月3日 | SCRAM-SHA-1 认证 改进的 explain 功能 MongoDB Ops Manager 副本集选举增强 WiredTiger 存储引擎默认 |\n| 3.2 | 2015年12月8日 | 配置服务器作为副本集 读关注 从 V8 切换到 SpiderMonkey 线性化读关注 |\n| 3.4 | 2016年11月29日 | 视图 排序(collation) |\n| 3.6 | 2017年11月 |  |\n| 4.0 | 2018年6月 | 事务 |\n| 4.2 | 2019年8月 |  |\n| 4.4 | 2020年7月 |  |\n| 4.4.5 | 2021年4月 |  |\n| 4.4.6 | 2021年5月 | 面向未来的版本化 API |\n| 5.0 | 2021年7月13日 | 客户端字段级加密 实时重分片 时间序列支持 |\n| 6.0 | 2022年7月 |  |\n| 7.0 | 2023年8月15日 |  |\n\n## MongoDB 下载\n\n你可以在 MongoDB 官网下载该安装包，地址为：[https://www.mongodb.com/try/download/community](https://www.mongodb.com/try/download/community)。\n\nMongoDB 支持以下平台:\n\n- Linux：MongoDB 支持各种 Linux 发行版，包括但不限于 Ubuntu、Debian、CentOS、Red Hat Enterprise Linux（RHEL）、Fedora 等。\n- Windows：MongoDB 提供了适用于 Windows 操作系统的官方版本，可以在 Windows Server 和 Windows 桌面操作系统上运行。\n- macOS：MongoDB 可以在 macOS 上运行，并且提供了适用于 macOS 的官方安装程序。\n- Docker：MongoDB 也可以作为 Docker 容器运行，这使得在各种平台上部署和管理 MongoDB 变得更加便捷。\n\n![图片](/api/uploads/files/runoob/mongodb/c13b127c48795222a0374fc600e50b28-3d71a57f4f.png)\n\n## 语言支持\n\nMongoDB 有官方的驱动如下：\n\n- [C](https://github.com/mongodb/mongo-c-driver)\n- [C++](https://github.com/mongodb/mongo)\n- [C# / .NET](http://www.mongodb.org/display/DOCS/CSharp+Language+Center)\n- [Erlang](https://github.com/TonyGen/mongodb-erlang)\n- [Haskell](http://hackage.haskell.org/package/mongoDB)\n- [Java](https://github.com/mongodb/mongo-java-driver)\n- [JavaScript](http://www.mongodb.org/display/DOCS/Javascript+Language+Center)\n- [Lisp](https://github.com/fons/cl-mongo)\n- [node.JS](https://github.com/mongodb/node-mongodb-native)\n- [Perl](https://github.com/mongodb/mongo-perl-driver)\n- [PHP](https://github.com/mongodb/mongo-php-driver)\n- [Python](https://github.com/mongodb/mongo-python-driver)\n- [Ruby](https://github.com/mongodb/mongo-ruby-driver)\n- [Scala](https://github.com/mongodb/casbah)\n- [Go](https://github.com/mongodb/mongo-go-driver)\n\n## MongoDB 工具\n\n有几种可用于MongoDB的管理工具。\n\n### 监控\n\nMongoDB提供了网络和系统监控工具Munin，它作为一个插件应用于MongoDB中。\n\nGangila是MongoDB高性能的系统监视的工具，它作为一个插件应用于MongoDB中。\n\n基于图形界面的开源工具 Cacti, 用于查看CPU负载, 网络带宽利用率,它也提供了一个应用于监控 MongoDB 的插件。\n\n### GUI\n\n- Fang of Mongo – 网页式,由Django和jQuery所构成。\n- Futon4Mongo – 一个CouchDB Futon web的mongodb山寨版。\n- Mongo3 – Ruby写成。\n- MongoHub – 适用于OSX的应用程序。\n- Opricot – 一个基于浏览器的MongoDB控制台, 由PHP撰写而成。\n- Database Master — Windows的mongodb管理工具\n- RockMongo — 最好的PHP语言的MongoDB管理工具，轻量级, 支持多国语言.\n\n## MongoDB 应用案例\n\n下面列举一些公司MongoDB的实际应用：\n\n- Craiglist上使用MongoDB的存档数十亿条记录。\n- FourSquare，基于位置的社交网站，在Amazon EC2的服务器上使用MongoDB分享数据。\n- Shutterfly，以互联网为基础的社会和个人出版服务，使用MongoDB的各种持久性数据存储的要求。\n- bit.ly, 一个基于Web的网址缩短服务，使用MongoDB的存储自己的数据。\n- spike.com，一个MTV网络的联营公司， spike.com使用MongoDB的。\n- Intuit公司，一个为小企业和个人的软件和服务提供商，为小型企业使用MongoDB的跟踪用户的数据。\n- sourceforge.net，资源网站查找，创建和发布开源软件免费，使用MongoDB的后端存储。\n- etsy.com ，一个购买和出售手工制作物品网站，使用MongoDB。\n- 纽约时报，领先的在线新闻门户网站之一，使用MongoDB。\n- CERN，著名的粒子物理研究所，欧洲核子研究中心大型强子对撞机的数据使用MongoDB。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-intro.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-intro','MongoDB 简介 - MongoDB 教程','MongoDB 是一个文档型数据库，数据以类似 JSON 的文档形式存储。 MongoDB 的设计理念是为了应对大数据量、高性能和灵活性需求。 MongoDB使用集合（Collections）来组织文档（Documents），每个文档都是由...',0,'PUBLISHED',2911,101,60,11,'2025-07-03 00:00:00','2025-07-03 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631003,1,'Windows MongoDB','最新版本的 MongoDB 提供了可用于 64 位系统的预编译二进制包，你可以从 MongoDB 官网下载安装，MongoDB 预编译二进制包下载地址：https://www.mongodb.com/try/download/communityhttps://www.mongodb.com/try/download/community 下载 .msi 文件，下载后双击该文件，按操作提示安装即可。 点击 "Next" 按钮来启动安装过程： 接下来，将出现一个协议窗口，选中同意的选项，然后再点击 "Next" 按钮：','# Windows 平台安装 MongoDB\n\n## MongoDB 下载\n\n最新版本的 MongoDB 提供了可用于 64 位系统的预编译二进制包，你可以从 MongoDB 官网下载安装，MongoDB 预编译二进制包下载地址：[https://www.mongodb.com/try/download/community](https://www.mongodb.com/try/download/community)\n\n> 注意：在 MongoDB 2.2 版本后已经不再支持 Windows XP 系统。最新版本也已经没有了 32 位系统的安装文件。\n\n![图片](/api/uploads/files/runoob/mongodb/win-mongo-dw-660cc56a26.png)\n\n- MongoDB for Windows 64-bit 适合 64 位的 Windows Server 2008 R2, Windows 7 , 及最新版本的 Window 系统。\n- MongoDB for Windows 32-bit 适合 32 位的 Window 系统及最新的 Windows Vista。 32 位系统上 MongoDB 的数据库最大为 2GB。\n- MongoDB for Windows 64-bit Legacy 适合 64 位的 Windows Vista, Windows Server 2003, 及 Windows Server 2008 。\n\n下载 .msi 文件，下载后双击该文件，按操作提示安装即可。\n\n点击 "Next" 按钮来启动安装过程：\n\n![图片](/api/uploads/files/runoob/mongodb/image3-5-b3c08d15fa.png)\n\n接下来，将出现一个协议窗口，选中同意的选项，然后再点击 "Next" 按钮：\n\n![图片](/api/uploads/files/runoob/mongodb/image2-5-448dafdeb1.png)\n\n现在，出现了两个选择：您可以以网络服务用户身份运行 MongoDB，也可以以本地或域用户身份运行它。\n\n如果您需要简单性和基本功能，网络服务用户选项就可以了，如果您需要对权限进行更多控制，或者需要使用特定用户凭据访问和限制资源，则选择本地或域用户选项会更合适\n。\n\n我们简单测试就选第一个，然后单击"Next" 按钮：\n\n![图片](/api/uploads/files/runoob/mongodb/image5-5-b15eaac6cc.png)\n\n接下来我们可以选择完整安装，改安装方式默认配置安装所有 MongoDB 组件和工具，当然你也可以选择自定义安装。\n\n![图片](/api/uploads/files/runoob/mongodb/Steps-to-install-MongoDB_4-ceed10714e.png)\n\n![图片](/api/uploads/files/runoob/mongodb/image4-4-bbb0b03e92.png)\n\n选择安装方法后，您需要单击 "Install" 按钮来开始安装过程：\n\n![图片](/api/uploads/files/runoob/mongodb/image7-3-1420e450d8.png)\n\n安装完成后，点击 "Finish" 按钮关闭安装程序：\n\n![图片](/api/uploads/files/runoob/mongodb/image6-3-40e2be2809.png)\n\n设置环境变量:系统属性->环境变量->系统变量->路径->编辑环境变量：\n\n![图片](/api/uploads/files/runoob/mongodb/image8-3-d317bd3c99.png)\n\n创建数据目录\n\nMongoDB 将数据目录存储在 db 目录下，我们在安装完成后可以创建它。\n\n请注意，数据目录应该放在根目录下 (如： C:\\ 或者 D:\\ 等 )。\n\n在本教程中，我们已经在 C 盘安装了 mongodb，现在让我们创建一个 data 的目录然后在 data 目录里创建 db 目录。\n\n```text\n\ncd C:\\\nmd "\\data\\db"\n```\n\n你也可以通过 window 的资源管理器中创建这些目录，而不一定通过命令行。\n\n## 命令行下运行 MongoDB 服务器\n\n执行 mongod 命令：\n\n```text\n\nmongod --dbpath c:\\data\\db\n```\n\n如果执行成功，会输出如下信息：\n\n![图片](/api/uploads/files/runoob/mongodb/image10-3-8e374f37df.png)\n\n## 连接 MongoDB\n\n> MongoDB6.0 以后做出了重大改变，MongoDB 已经不再默认安装 shell 工具，你需要安装一个额外的 shell 工具：[MongoDB Shell](https://www.runoob.com/mongodb/mongodb-shell.html)\n\n我们可以在命令窗口中运行 mongo 命令即可连接上 MongoDB，执行如下命令：\n\n```text\n\nmongo\n```\n\n## 配置 MongoDB 服务\n\n> 注意：一些新版本的 MongoDB 安装时已经自行完成大部分配置，如果以下目录已经存在，你可以直接跳过这部分内容。\n\n管理员模式打开命令行窗口\n\n创建目录，执行下面的语句来创建数据库和日志文件的目录\n\n```text\nmkdir c:\\data\\db\nmkdir c:\\data\\log\n```\n\n创建配置文件\n\n创建一个配置文件。该文件必须设置 systemLog.path 参数，包括一些附加的配置选项更好。\n\n例如，创建一个配置文件位于 C:\\mongodb\\mongod.cfg，其中指定 systemLog.path 和 storage.dbPath。具体配置内容如下：\n\n```text\nsystemLog:\n    destination: file\n    path: c:\\data\\log\\mongod.log\nstorage:\n    dbPath: c:\\data\\db\n```\n\n### 安装 MongoDB服务\n\n通过执行 mongod，使用 --install 选项来安装服务，使用 --config 选项来指定之前创建的配置文件。\n\n```text\nmongod  --config "C:\\mongodb\\mongod.cfg" --install\n```\n\n要使用备用 dbpath，可以在配置文件（例如：C:\\mongodb\\mongod.cfg）或命令行中通过 --dbpath 选项指定。\n\n如果需要，您可以安装 mongod 或 mongos 的多个实例的服务。只需要通过使用 --serviceName 和 --serviceDisplayName 指定不同的实例名。只有当存在足够的系统资源和系统的设计需要这么做。\n\n启动 MongoDB 服务\n\n```text\nnet start MongoDB\n```\n\n关闭 MongoDB 服务\n\n```text\nnet stop MongoDB\n```\n\n移除 MongoDB 服务\n\n```text\nmongod --remove\n```\n\n> 命令行下运行 MongoDB 服务器 和 配置 MongoDB 服务 任选一个方式启动就可以。\n\n\n\n\n任选一个操作就好\n\n## MongoDB 后台管理 Shell\n\n如果你需要进入MongoDB后台管理，你需要先打开mongodb装目录的下的bin目录，然后执行mongo.exe文件，MongoDB Shell是MongoDB自带的交互式Javascript shell,用来对MongoDB进行操作和管理的交互式环境。\n\n当你进入mongoDB后台后，它默认会链接到 test 文档（数据库）：\n\n```text\n\n> mongo\nMongoDB shell version: 3.0.6\nconnecting to: test\n……\n```\n\n由于它是一个JavaScript shell，您可以运行一些简单的算术运算:\n\n```text\n\n> 2 + 2\n4\n>\n```\n\ndb 命令用于查看当前操作的文档（数据库）：\n\n```text\n\n> db\ntest\n>\n```\n\n插入一些简单的记录并查找它：\n\n```text\n\n> db.runoob.insert({x:10})\nWriteResult({ "nInserted" : 1 })\n> db.runoob.find()\n{ "_id" : ObjectId("5604ff74a274a611b0c990aa"), "x" : 10 }\n>\n```\n\n第一个命令将数字 10 插入到 runoob 集合的 x 字段中。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-window-install.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-window-install','Windows MongoDB - MongoDB 教程','最新版本的 MongoDB 提供了可用于 64 位系统的预编译二进制包，你可以从 MongoDB 官网下载安装，MongoDB 预编译二进制包下载地址：https://www.mongodb.com/try/download/communi...',0,'PUBLISHED',3048,108,65,12,'2025-07-04 00:00:00','2025-07-04 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631004,1,'Linux MongoDB','MongoDB 提供了 Linux 各个发行版本 64 位的安装包，你可以在官网下载安装包。 安装前我们需要根据自己的系统版本安装对应的依赖包，三选一执行： Red Hat/CentOS： Ubuntu 18.04 LTS "Bionic"/Debian 10 "Buster"：','# Linux平台安装MongoDB\n\nMongoDB 提供了 Linux 各个发行版本 64 位的安装包，你可以在官网下载安装包。\n\n安装前我们需要根据自己的系统版本安装对应的依赖包，三选一执行：\n\nRed Hat/CentOS：\n\n```text\nsudo yum install libcurl openssl\n```\n\nUbuntu 18.04 LTS ("Bionic")/Debian 10 "Buster"：\n\n```text\nsudo apt-get install libcurl4 openssl\n```\n\nUbuntu 16.04 LTS ("Xenial")/Debian 9 "Stretch"：\n\n```text\nsudo apt-get install libcurl3 openssl\n```\n\nMongoDB 源码下载地址：[https://www.mongodb.com/try/download/community](https://www.mongodb.com/try/download/community)\n\n![图片](/api/uploads/files/runoob/mongodb/0D72BC20-1D77-437E-972C-286EB5EFB183-9a4c1e6a14.jpg)\n\n![图片](/api/uploads/files/runoob/mongodb/558D36F2-01AF-49C3-BA07-F2728B216C87-90651aca4f.jpg)\n\n这里我们选择 tgz 下载，下载完安装包，并解压 tgz（以下演示的是 64 位 Linux上的安装） 。\n\n```text\n\nwget https://fastdl.mongodb.org/linux/mongodb-linux-x86_64-ubuntu1604-4.2.8.tgz    # 下载\ntar -zxvf mongodb-linux-x86_64-ubuntu1604-4.2.8.tgz                                # 解压\n\nmv mongodb-linux-x86_64-ubuntu1604-4.2.8  /usr/local/mongodb4                      # 将解压包拷贝到指定目录\n```\n\nMongoDB 的可执行文件位于 bin 目录下，所以可以将其添加到 PATH 路径中，这样就可以在任意目录执行 MongoDB 命令，而不需要每次切换到安装目录：\n\n```text\n\nexport PATH=<mongodb-install-directory>/bin:$PATH\n```\n\n<mongodb-install-directory> 为你 MongoDB 的安装路径。如本文的 /usr/local/mongodb4 。\n\n```text\nexport PATH=/usr/local/mongodb4/bin:$PATH\n```\n\n注意：以上 export 命令只在当前终端会话中有效，关闭终端后会失效。如需永久生效，请将该命令追加到 `~/.bashrc` 或 `~/.profile` 文件中，然后执行 `source ~/.bashrc` 使其立即生效。\n\n## 创建数据库目录\n\n默认情况下 MongoDB 启动后会初始化以下两个目录：\n\n- 数据存储目录：/var/lib/mongodb\n- 日志文件目录：/var/log/mongodb\n\n我们在启动前可以先创建这两个目录并设置当前用户有读写权限：\n\n```text\nsudo mkdir -p /var/lib/mongodb\nsudo mkdir -p /var/log/mongodb\nsudo chown `whoami` /var/lib/mongodb     # 设置权限，whoami 会自动替换为当前登录的用户名\nsudo chown `whoami` /var/log/mongodb     # 设置权限\n```\n\n接下来启动 Mongodb 服务：\n\n```text\n\nmongod --dbpath /var/lib/mongodb --logpath /var/log/mongodb/mongod.log --fork\n```\n\n参数说明：\n\n- `--dbpath`：指定数据库文件的存储目录\n- `--logpath`：指定日志文件的路径（注意是文件路径，不是目录）\n- `--fork`：让 MongoDB 在后台运行（即以守护进程方式启动），不加此参数则会占用当前终端\n\n打开 /var/log/mongodb/mongod.log 文件看到以下信息，说明启动成功。\n\n```text\ntail -10f /var/log/mongodb/mongod.log\n2020-07-09T12:20:17.391+0800 I  NETWORK  [listener] Listening on /tmp/mongodb-27017.sock\n2020-07-09T12:20:17.392+0800 I  NETWORK  [listener] Listening on 127.0.0.1\n2020-07-09T12:20:17.392+0800 I  NETWORK  [listener] waiting for connections on port 27017\n```\n\n## MongoDB 后台管理 Shell\n\n> MongoDB6.0 以后做出了重大改变，MongoDB 已经不再默认安装 shell 工具，你需要安装一个额外的 shell 工具：[MongoDB Shell](https://www.runoob.com/mongodb/mongodb-shell.html)\n\n如果你需要进入 mongodb 后台管理，你需要先打开 mongodb 安装目录的下的 bin 目录，然后执行 mongo 命令文件。\n\nMongoDB Shell 是 MongoDB 自带的交互式 Javascript shell，用来对 MongoDB 进行操作和管理的交互式环境。\n\n当你进入 mongoDB 后台后，它默认会连接到 test 文档（数据库）：\n\n```text\n\n$ cd /usr/local/mongodb4/bin\n$ ./mongo\nMongoDB shell version v4.2.8\nconnecting to: mongodb://127.0.0.1:27017/?compressors=disabled&gssapiServiceName=mongodb\nImplicit session: session { "id" : UUID("2cfdafc4-dd56-4cfc-933a-187b887119b3") }\nMongoDB server version: 4.2.8\nWelcome to the MongoDB shell.\n……\n```\n\n由于它是一个JavaScript shell，您可以运行一些简单的算术运算:\n\n```text\n\n> 2+2\n4\n> 3+6\n9\n```\n\n现在让我们插入一些简单的数据，并对插入的数据进行检索：\n\n```text\n\n> db.runoob.insert({x:10})\nWriteResult({ "nInserted" : 1 })\n> db.runoob.find()\n{ "_id" : ObjectId("5f069bdb4e02f8baf90f1184"), "x" : 10 }\n> \n```\n\n第一个命令将数字 10 插入到 runoob 集合的 x 字段中。\n\n如果要停止 mongodb 可以使用以下命令：\n\n\n```text\nmongod --dbpath /var/lib/mongodb --logpath /var/log/mongodb/mongod.log --shutdown\n```\n\n也可以在 mongo 的命令行中实现：\n\n```text\n> use admin\nswitched to db admin\n> db.shutdownServer()\n```\n\n更多安装方法可以参考官网：[https://docs.mongodb.com/manual/administration/install-on-linux/](https://docs.mongodb.com/manual/administration/install-on-linux/)\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-linux-install.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-linux-install','Linux MongoDB - MongoDB 教程','MongoDB 提供了 Linux 各个发行版本 64 位的安装包，你可以在官网下载安装包。 安装前我们需要根据自己的系统版本安装对应的依赖包，三选一执行： Red Hat/CentOS： Ubuntu 18.04 LTS "Bionic"...',0,'PUBLISHED',3185,115,70,13,'2025-07-05 00:00:00','2025-07-05 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631005,1,'OSX MongoDB','MongoDB 提供了 OSX 平台上 64 位的安装包，你可以在官网下载安装包。 下载地址：https://www.mongodb.com/try/download/communityhttps://www.mongodb.com/try/download/community 接下来我们使用 curl 命令来下载安装： 安装完成后，我们可以把 MongoDB 的二进制命令文件目录（安装目录/bin）添加到 PATH 路径中：','# Mac OSX 平台安装 MongoDB\n\nMongoDB 提供了 OSX 平台上 64 位的安装包，你可以在官网下载安装包。\n\n下载地址：[https://www.mongodb.com/try/download/community](https://www.mongodb.com/try/download/community)\n\n![图片](/api/uploads/files/runoob/mongodb/F1642F2B-A395-41BD-A66D-A1446BAD2324-9a9a9bce23.jpg)\n\n> 从 MongoDB 3.0 版本开始只支持 OS X 10.7 (Lion) 版本及更新版本的系统。\n\n接下来我们使用 curl 命令来下载安装：\n\n```text\n\n# 进入 /usr/local\ncd /usr/local\n\n# 下载\nsudo curl -O https://fastdl.mongodb.org/osx/mongodb-osx-ssl-x86_64-4.0.9.tgz\n\n# 解压\nsudo tar -zxvf mongodb-osx-ssl-x86_64-4.0.9.tgz\n\n# 重命名为 mongodb 目录\n\nsudo mv mongodb-osx-x86_64-4.0.9/ mongodb\n```\n\n安装完成后，我们可以把 MongoDB 的二进制命令文件目录（安装目录/bin）添加到 PATH 路径中：\n\n```text\n\nexport PATH=/usr/local/mongodb/bin:$PATH\n```\n\n创建日志及数据存放的目录：\n\n- 数据存放路径：\n  ```text\n  sudo mkdir -p /usr/local/var/mongodb\n  ```\n- 日志文件路径：\n  ```text\n  sudo mkdir -p /usr/local/var/log/mongodb\n  ```\n\n接下来要确保当前用户对以上两个目录有读写的权限：\n\n```text\nsudo chown runoob /usr/local/var/mongodb\nsudo chown runoob /usr/local/var/log/mongodb\n```\n\n创建日志文件：\n\n```text\n\nsudo touch /usr/local/var/log/mongodb/mongo.log\nsudo chown runoob /usr/local/var/log/mongodb/mongo.log\n```\n\n以上 runoob 是我电脑上的用户，你这边需要根据你当前对用户名来修改。\n\n接下来我们使用以下命令在后台启动 mongodb：\n\n```text\nmongod --dbpath /usr/local/var/mongodb --logpath /usr/local/var/log/mongodb/mongo.log --fork\n```\n\n- --dbpath 设置数据存放目录\n- --logpath 设置日志存放目录\n- --fork 在后台运行\n\n如果不想在后端运行，而是在控制台上查看运行过程可以直接设置配置文件启动：\n\n```text\nmongod --config /usr/local/etc/mongod.conf\n```\n\n查看 mongod 服务是否启动：\n\n```text\nps aux | grep -v grep | grep mongod\n```\n\n使用以上命令如果看到有 mongod 的记录表示运行成功。\n\n启动后我们可以使用 mongo 命令打开一个终端：\n\n```text\n\n$ cd /usr/local/mongodb/bin \n$ ./mongo\nMongoDB shell version v4.0.9\nconnecting to: mongodb://127.0.0.1:27017/?gssapiServiceName=mongodb\nImplicit session: session { "id" : UUID("3c12bf4f-695c-48b2-b160-8420110ccdcf") }\nMongoDB server version: 4.0.9\n……\n> 1 + 1\n2\n> \n```\n\n> MongoDB6.0 以后做出了重大改变，MongoDB 已经不再默认安装 shell 工具，你需要安装一个额外的 shell 工具：[MongoDB Shell](https://www.runoob.com/mongodb/mongodb-shell.html)\n\n## 使用 brew 安装\n\n此外你还可以使用 OSX 的 brew 来安装 mongodb：\n\n```text\n\nbrew tap mongodb/brew\nbrew install\n[email protected]\n\n```\n\n@ 符号后面的 4.4 是最新版本号。\n\n安装信息：\n\n- 配置文件：/usr/local/etc/mongod.conf\n- 日志文件路径：/usr/local/var/log/mongodb\n- 数据存放路径：/usr/local/var/mongodb\n\n### 运行 MongoDB\n\n我们可以使用 brew 命令或 mongod 命令来启动服务。\n\nbrew 启动：\n\n```text\n\nbrew services start\n[email protected]\n```\n\nbrew 停止：\n\n```text\n\nbrew services stop\n[email protected]\n```\n\nmongod 命令后台进程方式：\n\n```text\nmongod --config /usr/local/etc/mongod.conf --fork\n```\n\n这种方式启动要关闭可以进入 mongo shell 控制台来实现：\n\n```text\n> db.adminCommand({ "shutdown" : 1 })\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-osx-install.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-osx-install','OSX MongoDB - MongoDB 教程','MongoDB 提供了 OSX 平台上 64 位的安装包，你可以在官网下载安装包。 下载地址：https://www.mongodb.com/try/download/communityhttps://www.mongodb.com/try...',0,'PUBLISHED',3322,122,75,14,'2025-07-06 00:00:00','2025-07-06 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631006,1,'MongoDB Shell','MongoDB Shell 是 MongoDB 提供的官方交互式界面，允许用户与 MongoDB 数据库进行交互、执行命令和操作数据库。 MongoDB Shell 是基于 JavaScript 的，允许用户直接在命令行或者脚本中使用 JavaScript 语言来操作 MongoDB 数据库。 MongoDB Shell 是 MongoDB 数据库安装包的一部分，因此，安装 MongoDB 数据库也会自动安装 MongoDB Shell。 使用 Homebrew 安装：','# MongoDB Shell\n\nMongoDB Shell 是 MongoDB 提供的官方交互式界面，允许用户与 MongoDB 数据库进行交互、执行命令和操作数据库。\n\nMongoDB Shell 是基于 JavaScript 的，允许用户直接在命令行或者脚本中使用 JavaScript 语言来操作 MongoDB 数据库。\n\n## 安装 MongoDB Shell\n\nMongoDB Shell 是 MongoDB 数据库安装包的一部分，因此，安装 MongoDB 数据库也会自动安装 MongoDB Shell。\n\n### 在 macOS 上安装 MongoDB Shell\n\n使用 Homebrew 安装：\n\n如果你使用 Homebrew 管理 macOS 上的软件包，可以通过以下命令安装 MongoDB：\n\n```text\nbrew tap mongodb/brew\nbrew install mongodb-community-shell\n```\n\n这将安装 MongoDB 的最新版本及其相关工具，包括 MongoDB Shell。\n\n手动下载安装：\n\n另一种方法是从 MongoDB 官网下载适用于 macOS 的 MongoDB Shell，下载地址 [https://www.mongodb.com/try/download/shell](https://www.mongodb.com/try/download/shell) :\n\n![图片](/api/uploads/files/runoob/mongodb/1730c0439cc5568232067f2d2021fca3-9956f99622.png)\n\n下载后，解压安装包，将 bin 目录中 mongosh 二进制文件复制到 PATH 变量中列出的目录中，例如 /usr/local/bin：\n\n```text\nsudo cp mongosh /usr/local/bin/\nsudo cp mongosh_crypt_v1.so /usr/local/lib/\n```\n\n安装完成后，MongoDB Shell 将可以在命令行中通过 mongosh 命令启动。\n\n若 macOS 阻止运行 mongosh，打开"系统偏好设置"中的"安全与隐私"以允许其运行。\n\n### 在 Linux 上安装 MongoDB Shell\n\n在大多数 Linux 发行版中，可以通过包管理器来安装 MongoDB Shell。例如，在 Ubuntu 上可以使用 apt 包管理器：\n\n为 Ubuntu 22.04 (Jammy) 创建 /etc/apt/sources.list.d/mongodb-org-7.0.list 文件：\n\n```text\necho "deb [ arch=amd64,arm64 ] https://repo.mongodb.org/apt/ubuntu jammy/mongodb-org/7.0 multiverse" | sudo tee /etc/apt/sources.list.d/mongodb-org-7.0.list\n```\n\n```text\n\nsudo apt update\nsudo apt install mongodb-shell\n```\n\n安装完成后，MongoDB Shell 将可以在命令行中通过 mongosh 命令启动。\n\n另一种方法是从 MongoDB 官网下载适用于 Linux 的 MongoDB Shell，下载地址 [https://www.mongodb.com/try/download/shell](https://www.mongodb.com/try/download/shell)  :\n\n![图片](/api/uploads/files/runoob/mongodb/fb02c0cbf311ab95064bb0b6282c5f2d-2-93fe8e388c.png)\n\n下载后，解压安装包，将 bin 目录中 mongosh 二进制文件复制到 PATH 变量中列出的目录中，例如 /usr/local/bin：\n\n```text\nsudo cp mongosh /usr/local/bin/\nsudo cp mongosh_crypt_v1.so /usr/local/lib/\n```\n\n安装完成后，MongoDB Shell 将可以在命令行中通过 mongosh 命令启动。\n\n### 在 Windows 上安装 MongoDB Shell\n\n访问 MongoDB 官网下载页面（[https://www.mongodb.com/try/download/shell](https://www.mongodb.com/try/download/shell)），选择适合 Windows 的 MongoDB Shell 版本，并下载安装程序。\n\n![图片](/api/uploads/files/runoob/mongodb/23bc1e03cb63ef2e51b2fda7d633aa44-e587ee8ab1.png)\n\n运行下载的安装程序，并按照指示进行安装。在安装过程中，确保选择安装 MongoDB Shell（默认情况下会包含在安装中）。\n\n可以选择在安装过程中配置环境变量，这样可以在命令行中直接运行 mongosh 命令来启动 MongoDB Shell。\n\n## 使用 MongoDB Shell\n\n安装完成后，可以通过以下步骤来使用 MongoDB Shell 连接到 MongoDB 数据库并执行操作。\n\n启动 MongoDB Shell：\n\n在命令行中输入 mongosh 命令，启动 MongoDB Shell，如果 MongoDB 服务器运行在本地默认端口（27017），则可以直接连接。\n\n```text\n\nmongosh\n```\n\n查看版本：\n\n```text\nmongosh --version\n2.2.9\n```\n\n连接到 MongoDB 服务器：\n\n如果 MongoDB 服务器运行在非默认端口或者远程服务器上，可以使用以下命令连接：\n\n```text\n\nmongosh --host <hostname>:<port>\n```\n\n其中 `<hostname>` 是 MongoDB 服务器的主机名或 IP 地址，`<port>` 是 MongoDB 服务器的端口号。\n\n执行基本操作：\n\n连接成功后，可以执行各种 MongoDB 数据库操作。例如：\n\n- 查看当前数据库：`db`\n- 显示数据库列表：`show dbs`\n- 切换到指定数据库：`use <database_name>`\n- 执行查询操作：`db.<collection_name>.find()`\n- 插入文档：`db.<collection_name>.insertOne({ ... })`\n- 更新文档：`db.<collection_name>.updateOne({ ... })`\n- 删除文档：`db.<collection_name>.deleteOne({ ... })`\n- 退出 MongoDB Shell：`quit()` 或者 `exit`\n\n### 实例\n\n以下是使用 MongoDB Shell 连接到本地 MongoDB 服务器，并执行一些基本操作的示例：\n\n## 实例\n\n# 启动 MongoDB Shell\n\n![图片](/api/uploads/files/runoob/mongodb/d867822e85a8b2baf7456a230132beb5-123ba1c282.png)\n\n通过上述步骤和示例，你可以开始使用 MongoDB Shell 来管理和操作 MongoDB 数据库。\n\n官方安装说明：[https://www.mongodb.com/zh-cn/docs/mongodb-shell/install/](https://www.mongodb.com/zh-cn/docs/mongodb-shell/install/)\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-shell.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-shell','MongoDB Shell - MongoDB 教程','MongoDB Shell 是 MongoDB 提供的官方交互式界面，允许用户与 MongoDB 数据库进行交互、执行命令和操作数据库。 MongoDB Shell 是基于 JavaScript 的，允许用户直接在命令行或者脚本中使用 Ja...',0,'PUBLISHED',3459,129,80,15,'2025-07-07 00:00:00','2025-07-07 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631007,1,'MongoDB 概念解析','不管我们学习什么数据库都应该学习其中的基础概念，在 MongoDB 中基本的概念是文档、集合、数据库，下面我们挨个介绍。 下表将帮助您更容易理解 MongoDB 中的一些概念： 通过下图实例，我们也可以更直观的了解Mongo中的一些概念： 一个 MongoDB 中可以建立多个数据库。','# MongoDB 概念解析\n\n不管我们学习什么数据库都应该学习其中的基础概念，在 MongoDB 中基本的概念是文档、集合、数据库，下面我们挨个介绍。\n\n下表将帮助您更容易理解 MongoDB 中的一些概念：\n\n| SQL 术语/概念 | MongoDB 术语/概念 | 解释/说明 |\n| --- | --- | --- |\n| database | database | 数据库 |\n| table | collection | 数据库表/集合 |\n| row | document | 数据记录行/文档 |\n| column | field | 数据字段/域 |\n| index | index | 索引 |\n| table joins |  | 表连接,MongoDB不支持 |\n| primary key | primary key | 主键,MongoDB自动将_id字段设置为主键 |\n\n通过下图实例，我们也可以更直观的了解Mongo中的一些概念：\n\n![图片](/api/uploads/files/runoob/mongodb/Figure-1-Mapping-Table-to-Collection-1-d5c82b19f2.png)\n\n完整术语列表：\n\n- 文档（Document）：MongoDB 的基本数据单元，通常是一个 JSON-like 的结构，可以包含多种数据类型。\n- 集合（Collection）：类似于关系型数据库中的表，集合是一组文档的容器。在 MongoDB 中，一个集合中的文档不需要有一个固定的模式。\n- 数据库（Database）：包含一个或多个集合的 MongoDB 实例。\n- BSON：Binary JSON 的缩写，是 MongoDB 用来存储和传输文档的二进制形式的 JSON。\n- 索引（Index）：用于优化查询性能的数据结构，可以基于集合中的一个或多个字段创建索引。\n- 分片（Sharding）：一种分布数据到多个服务器（称为分片）的方法，用于处理大数据集和高吞吐量应用。\n- 副本集（Replica Set）：一组维护相同数据集的 MongoDB 服务器，提供数据的冗余备份和高可用性。\n- 主节点（Primary）：副本集中负责处理所有写入操作的服务器。\n- 从节点（Secondary）：副本集中的服务器，用于读取数据和在主节点故障时接管为主节点。\n- MongoDB Shell：MongoDB 提供的命令行界面，用于与 MongoDB 实例交互。\n- 聚合框架（Aggregation Framework）：用于执行复杂的数据处理和聚合操作的一系列操作。\n- Map-Reduce：一种编程模型，用于处理大量数据集的并行计算。\n- GridFS：用于存储和检索大于 BSON 文档大小限制的文件的规范。\n- ObjectId：MongoDB 为每个文档自动生成的唯一标识符。\n- CRUD 操作：创建（Create）、读取（Read）、更新（Update）、删除（Delete）操作。\n- 事务（Transactions）：从 MongoDB 4.0 开始支持，允许一组操作作为一个原子单元执行。\n- 操作符（Operators）：用于查询和更新文档的特殊字段。\n- 连接（Join）：MongoDB 允许在查询中使用 `$lookup` 操作符来实现类似 SQL 的连接操作。\n- TTL（Time-To-Live）：可以为集合中的某些字段设置 TTL，以自动删除旧数据。\n- 存储引擎（Storage Engine）：MongoDB 用于数据存储和管理的底层技术，如 WiredTiger 和 MongoDB 的旧存储引擎 MMAPv1。\n- MongoDB Compass：MongoDB 的图形界面工具，用于可视化和管理 MongoDB 数据。\n- MongoDB Atlas：MongoDB 提供的云服务，允许在云中托管 MongoDB 数据库。\n\n## 数据库\n\n一个 MongoDB 中可以建立多个数据库。\n\n如果在操作时没有指定数据库，MongoDB 会使用一个名为 test 的默认数据库，该数据库存储在 data 目录中。\n\nMongoDB 的单个实例可以容纳多个独立的数据库，每一个都有自己的集合和权限，不同的数据库也放置在不同的文件中。\n\n从 MongoDB 4.0 开始，支持在单个数据库上执行多文档事务。\n\n"show dbs" 命令可以显示所有数据的列表。\n\n```text\n\n$ ./mongo\nMongoDB shell version: 3.0.6\nconnecting to: test\n> show dbs\nlocal  0.078GB\ntest   0.078GB\n> \n```\n\n执行 "db" 命令可以显示当前数据库对象或集合。\n\n```text\n\n$ ./mongo\nMongoDB shell version: 3.0.6\nconnecting to: test\n> db\ntest\n> \n```\n\n运行"use"命令，可以连接到一个指定的数据库。\n\n```text\n\n> use local\nswitched to db local\n> db\nlocal\n> \n```\n\n以上实例命令中，"local" 是你要链接的数据库。\n\n在下一个章节我们将详细讲解MongoDB中命令的使用。\n\n数据库也通过名字来标识。数据库名可以是满足以下条件的任意UTF-8字符串。\n\n- 不能是空字符串（"")。\n- 不得含有\' \'（空格)、.、$、/、\\和\\0 (空字符)。\n- 应全部小写。\n- 最多64字节。\n\n有一些数据库名是保留的，可以直接访问这些有特殊作用的数据库。\n\n- admin：\n  从权限的角度来看，这是"root"数据库。要是将一个用户添加到这个数据库，这个用户自动继承所有数据库的权限。一些特定的服务器端命令也只能从这个数据库运行，比如列出所有的数据库或者关闭服务器。\n- local:\n  这个数据永远不会被复制，可以用来存储限于本地单台服务器的任意集合\n- config:\n  当Mongo用于分片设置时，config数据库在内部使用，用于保存分片的相关信息。\n\n## 文档(Document)\n\n文档是一组键值(key-value)对(即 BSON)。MongoDB 的文档不需要设置相同的字段，并且相同的字段不需要相同的数据类型，这与关系型数据库有很大的区别，也是 MongoDB 非常突出的特点。\n\n一个简单的文档例子如下：\n\n```text\n{"site":"www.runoob.com", "name":"菜鸟教程"}\n```\n\n下表列出了 RDBMS 与 MongoDB 对应的术语：\n\n| RDBMS | MongoDB |\n| --- | --- |\n| 数据库 | 数据库 |\n| 表格 | 集合 |\n| 行 | 文档 |\n| 列 | 字段 |\n| 表联合 | 嵌入文档 |\n| 主键 | 主键 (MongoDB 提供了 key 为 _id ) |\n| 数据库服务和客户端 |  |\n| Mysqld/Oracle | mongodb |\n| mysql/sqlplus | mongo |\n\n需要注意的是：\n\n1. 文档中的键/值对是有序的。\n2. 文档中的值不仅可以是在双引号里面的字符串，还可以是其他几种数据类型（甚至可以是整个嵌入的文档)。\n3. MongoDB区分类型和大小写。\n4. MongoDB的文档不能有重复的键。\n5. 文档的键是字符串。除了少数例外情况，键可以使用任意UTF-8字符。\n\n文档键命名规范：\n\n- 键不能含有\\0 (空字符)。这个字符用来表示键的结尾。\n- .和$有特别的意义，只有在特定环境下才能使用。\n- 以下划线"_"开头的键是保留的(不是严格要求的)。\n\n## 集合\n\n集合就是 MongoDB 文档组，类似于 RDBMS （关系数据库管理系统：Relational Database Management System)中的表格。\n\n集合存在于数据库中，集合没有固定的结构，这意味着你在对集合可以插入不同格式和类型的数据，但通常情况下我们插入集合的数据都会有一定的关联性。\n\n比如，我们可以将以下不同数据结构的文档插入到集合中：\n\n```text\n\n{"site":"www.baidu.com"}\n{"site":"www.google.com","name":"Google"}\n{"site":"www.runoob.com","name":"菜鸟教程","num":5}\n```\n\n当第一个文档插入时，集合就会被创建。\n\n### 合法的集合名\n\n- 集合名不能是空字符串""。\n- 集合名不能含有\\0字符（空字符)，这个字符表示集合名的结尾。\n- 集合名不能以"system."开头，这是为系统集合保留的前缀。\n- 用户创建的集合名字不能含有保留字符。有些驱动程序的确支持在集合名里面包含，这是因为某些系统生成的集合中包含该字符。除非你要访问这种系统创建的集合，否则千万不要在名字里出现$。\n\n如下实例：\n\n```text\n\ndb.col.findOne()\n```\n\n### capped collections\n\nCapped collections 就是固定大小的collection。\n\n它有很高的性能以及队列过期的特性(过期按照插入的顺序). 有点和 "RRD" 概念类似。\n\nCapped collections 是高性能自动的维护对象的插入顺序。它非常适合类似记录日志的功能和标准的 collection 不同，你必须要显式的创建一个capped collection，指定一个 collection 的大小，单位是字节。collection 的数据存储空间值提前分配的。\n\nCapped collections 可以按照文档的插入顺序保存到集合中，而且这些文档在磁盘上存放位置也是按照插入顺序来保存的，所以当我们更新Capped collections 中文档的时候，更新后的文档不可以超过之前文档的大小，这样话就可以确保所有文档在磁盘上的位置一直保持不变。\n\n由于 Capped collection 是按照文档的插入顺序而不是使用索引确定插入位置，这样的话可以提高增添数据的效率。MongoDB 的操作日志文件 oplog.rs 就是利用 Capped Collection 来实现的。\n\n要注意的是指定的存储大小包含了数据库的头信息。\n\n```text\ndb.createCollection("mycoll", {capped:true, size:100000})\n```\n\n- 在 capped collection 中，你能添加新的对象。\n- 能进行更新，然而，对象不会增加存储空间。如果增加，更新就会失败 。\n- 使用 Capped Collection 不能删除一个文档，可以使用 drop() 方法删除 collection 所有的行。\n- 删除之后，你必须显式的重新创建这个 collection。\n- 在32bit机器中，capped collection 最大存储为 1e9( 1X109)个字节。\n\n## 元数据\n\n数据库的信息是存储在集合中。它们使用了系统的命名空间：\n\n```text\n\ndbname.system.*\n```\n\n在MongoDB数据库中名字空间 <dbname>.system.* 是包含多种系统信息的特殊集合(Collection)，如下:\n\n| 集合命名空间 | 描述 |\n| --- | --- |\n| dbname.system.namespaces | 列出所有名字空间。 |\n| dbname.system.indexes | 列出所有索引。 |\n| dbname.system.profile | 包含数据库概要(profile)信息。 |\n| dbname.system.users | 列出所有可访问数据库的用户。 |\n| dbname.local.sources | 包含复制对端（slave）的服务器信息和状态。 |\n\n对于修改系统集合中的对象有如下限制。\n\n在{{system.indexes}}插入数据，可以创建索引。但除此之外该表信息是不可变的(特殊的drop index命令将自动更新相关信息)。\n\n{{system.users}}是可修改的。 {{system.profile}}是可删除的。\n\n## MongoDB 数据类型\n\n下表为MongoDB中常用的几种数据类型。\n\n| 数据类型 | 描述 |\n| --- | --- |\n| String | 字符串。存储数据常用的数据类型。在 MongoDB 中，UTF-8 编码的字符串才是合法的。 |\n| Integer | 整型数值。用于存储数值。根据你所采用的服务器，可分为 32 位或 64 位。 |\n| Boolean | 布尔值。用于存储布尔值（真/假）。 |\n| Double | 双精度浮点值。用于存储浮点值。 |\n| Min/Max keys | 将一个值与 BSON（二进制的 JSON）元素的最低值和最高值相对比。 |\n| Array | 用于将数组或列表或多个值存储为一个键。 |\n| Timestamp | 时间戳。记录文档修改或添加的具体时间。 |\n| Object | 用于内嵌文档。 |\n| Null | 用于创建空值。 |\n| Symbol | 符号。该数据类型基本上等同于字符串类型，但不同的是，它一般用于采用特殊符号类型的语言。 |\n| Date | 日期时间。用 UNIX 时间格式来存储当前日期或时间。你可以指定自己的日期时间：创建 Date 对象，传入年月日信息。 |\n| Object ID | 对象 ID。用于创建文档的 ID。 |\n| Binary Data | 二进制数据。用于存储二进制数据。 |\n| Code | 代码类型。用于在文档中存储 JavaScript 代码。 |\n| Regular expression | 正则表达式类型。用于存储正则表达式。 |\n\n下面说明下几种重要的数据类型。\n\n### ObjectId\n\nObjectId 类似唯一主键，可以很快的去生成和排序，包含 12 bytes，含义是：\n\n- 前 4 个字节表示创建 unix 时间戳,格林尼治时间 UTC 时间，比北京时间晚了 8 个小时\n- 接下来的 3 个字节是机器标识码\n- 紧接的两个字节由进程 id 组成 PID\n- 最后三个字节是随机数\n\n![图片](/api/uploads/files/runoob/mongodb/2875754375-5a19268f0fd9b_articlex-f91b75c030.jpeg)\n\nMongoDB 中存储的文档必须有一个 _id 键。这个键的值可以是任何类型的，默认是个 ObjectId 对象\n\n由于 ObjectId 中保存了创建的时间戳，所以你不需要为你的文档保存时间戳字段，你可以通过 getTimestamp 函数来获取文档的创建时间:\n\n```text\n> var newObject = ObjectId()\n> newObject.getTimestamp()\nISODate("2017-11-25T07:21:10Z")\n```\n\nObjectId 转为字符串\n\n```text\n> newObject.str\n5a1919e63df83ce79df8b38f\n```\n\n### 字符串\n\nBSON 字符串都是 UTF-8 编码。\n\n### 时间戳\n\nBSON 有一个特殊的时间戳类型用于 MongoDB 内部使用，与普通的 日期 类型不相关。 时间戳值是一个 64 位的值。其中：\n\n- 前32位是一个 time_t 值（与Unix新纪元相差的秒数）\n- 后32位是在某秒中操作的一个递增的`序数`\n\n在单个 mongod 实例中，时间戳值通常是唯一的。\n\n在复制集中， oplog 有一个 ts 字段。这个字段中的值使用BSON时间戳表示了操作时间。\n\n> BSON 时间戳类型主要用于 MongoDB 内部使用。在大多数情况下的应用开发中，你可以使用 BSON 日期类型。\n\n### 日期\n\n表示当前距离 Unix新纪元（1970年1月1日）的毫秒数。日期类型是有符号的, 负数表示 1970 年之前的日期。\n\n```text\n\n> var mydate1 = new Date()     //格林尼治时间\n> mydate1\nISODate("2018-03-04T14:58:51.233Z")\n> typeof mydate1\nobject\n```\n\n```text\n> var mydate2 = ISODate() //格林尼治时间\n> mydate2\nISODate("2018-03-04T15:00:45.479Z")\n> typeof mydate2\nobject\n```\n\n这样创建的时间是日期类型，可以使用 JS 中的 Date 类型的方法。\n\n返回一个时间类型的字符串：\n\n```text\n> var mydate1str = mydate1.toString()\n> mydate1str\nSun Mar 04 2018 14:58:51 GMT+0000 (UTC) \n> typeof mydate1str\nstring\n```\n\n或者\n\n```text\n> Date()\nSun Mar 04 2018 15:02:59 GMT+0000 (UTC)\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-databases-documents-collections.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-databases-documents-collections','MongoDB 概念解析 - MongoDB 教程','不管我们学习什么数据库都应该学习其中的基础概念，在 MongoDB 中基本的概念是文档、集合、数据库，下面我们挨个介绍。 下表将帮助您更容易理解 MongoDB 中的一些概念： 通过下图实例，我们也可以更直观的了解Mongo中的一些概念： ...',0,'PUBLISHED',3596,136,85,16,'2025-07-08 00:00:00','2025-07-08 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631008,1,'MongoDB 用户管理','在 MongoDB 中进行用户管理涉及用户的创建、分配角色、认证和登录等操作。 下面是一个详细的说明，包含如何使用 MongoDB Shell mongo 或 MongoDB Compass 来管理用户。 以下是使用 MongoDB Shell mongosh 进行用户管理的详细说明，包括创建用户、分配角色、认证和登录的具体步骤。 1. 连接到 MongoDB','# MongoDB 用户管理\n\n在 MongoDB 中进行用户管理涉及用户的创建、分配角色、认证和登录等操作。\n\n下面是一个详细的说明，包含如何使用 MongoDB Shell (mongo) 或 MongoDB Compass 来管理用户。\n\n### 使用 MongoDB Shell (mongo) 管理用户\n\n以下是使用 MongoDB Shell (mongosh) 进行用户管理的详细说明，包括创建用户、分配角色、认证和登录的具体步骤。\n\n1. 连接到 MongoDB\n\n首先，打开你的终端并使用 mongosh 命令连接到 MongoDB 服务器：\n\n```text\n\nmongosh --host <hostname> --port <port>\n```\n\n说明：\n\n- `mongosh`：启动 MongoDB Shell 命令行工具。\n- `--host <hostname>`：指定 MongoDB 服务器的主机名或 IP 地址。\n  - `<hostname>`：MongoDB 服务器的主机名（如 `localhost`）或 IP 地址（如 `127.0.0.1`）。\n- `--port <port>`：指定 MongoDB 服务器的端口号。\n  - `<port>`：MongoDB 服务器监听的端口号，默认端口是 `27017`。\n\n2. 切换到目标数据库\n\n在 MongoDB 中，用户是针对特定数据库创建的，使用 use 命令切换到你要创建用户的数据库：\n\n```text\n\nuse <database_name>\n```\n\n- database_name -  为要切换的数据库。\n\n3. 创建用户\n\n使用 db.createUser 命令创建用户并分配角色。\n\n例如，创建一个名为 testuser 的用户，密码为 password123，并赋予 readWrite 和 dbAdmin 角色：\n\n```text\ndb.createUser({\n  user: "testuser",\n  pwd: "password123",\n  roles: [\n    { role: "readWrite", db: "<database_name>" },\n    { role: "dbAdmin", db: "<database_name>" }\n  ]\n})\n```\n\n4. 验证用户\n\n创建用户后，你可以使用 db.auth 命令验证用户身份：\n\n```text\n\ndb.auth("testuser", "password123")\n```\n\n5. 启用身份验证\n\n为了确保只有经过身份验证的用户才能访问 MongoDB，需要启用身份验证。\n\n编辑 MongoDB 配置文件 mongod.conf，并在其中添加以下内容：\n\n```text\n\nsecurity:\n  authorization: "enabled"\n```\n\n然后重启 MongoDB 服务以应用更改。\n\n6. 使用用户身份登录\n\n启用身份验证后，你需要使用创建的用户身份连接到 MongoDB：\n\n```text\n\nmongosh --host <hostname> --port <port> -u "testuser" -p "password123" --authenticationDatabase "<database_name>"\n```\n\n7. 删除用户\n\n使用 db.dropUser 命令删除指定用户。\n\n例如，删除名为 testuser 的用户：\n\n```text\ndb.dropUser("testuser")\n```\n\n### 实例操作\n\n以下是一个完整的示例操作流程：\n\n启动 MongoDB Shell 并连接到服务器：\n\n```text\n\nmongosh --host localhost --port 27017\n```\n\n切换到 testdb 数据库：\n\n```text\n\nuse testdb\n```\n\n创建 testuser 用户：\n\n```text\ndb.createUser({\n  user: "testuser",\n  pwd: "password123",\n  roles: [{ role: "readWrite", db: "testdb" }]\n})\n```\n\n启用身份验证并重启 MongoDB 实例\n\n编辑 mongod.conf 文件，添加以下内容：\n\n```text\n\nsecurity:\n  authorization: "enabled"\n```\n\n重启 MongoDB 服务：\n\n```text\n\nsudo systemctl restart mongod\n```\n\n使用 testuser 用户进行身份验证连接：\n\n```text\n\nmongosh --host localhost --port 27017 -u "testuser" -p "password123" --authenticationDatabase "testdb"\n```\n\n删除 testuser 用户：\n\n```text\n\ndb.dropUser("testuser")\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-user.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-user','MongoDB 用户管理 - MongoDB 教程','在 MongoDB 中进行用户管理涉及用户的创建、分配角色、认证和登录等操作。 下面是一个详细的说明，包含如何使用 MongoDB Shell mongo 或 MongoDB Compass 来管理用户。 以下是使用 MongoDB She...',0,'PUBLISHED',3733,143,90,17,'2025-07-09 00:00:00','2025-07-09 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631009,1,'MongoDB 连接','在本教程我们将讨论 MongoDB 的不同连接方式。 在前面的教程中，我们已经讨论了如何启动 MongoDB 服务https://www.runoob.com/mongodb/mongodb-window-install.html，你只需要在 MongoDB 安装目录的 bin 目录下执行 mongodb 即可。 执行启动操作后，mongodb 在输出一些必要信息后不会输出任何信息，之后就等待连接的建立，当连接被建立后，就会开始打印日志信息。 你可以使用 MongoDB shellhttps://www.runoob.com/mongodb/mongodb-shell.html 来连接 Mon...','# MongoDB - 连接\n\n在本教程我们将讨论 MongoDB 的不同连接方式。\n\n### 启动 MongoDB 服务\n\n在前面的教程中，我们已经讨论了[如何启动 MongoDB 服务](https://www.runoob.com/mongodb/mongodb-window-install.html)，你只需要在 MongoDB 安装目录的 bin 目录下执行 mongodb 即可。\n\n执行启动操作后，mongodb 在输出一些必要信息后不会输出任何信息，之后就等待连接的建立，当连接被建立后，就会开始打印日志信息。\n\n你可以使用 [MongoDB shell](https://www.runoob.com/mongodb/mongodb-shell.html) 来连接 MongoDB 服务器。你也可以使用 PHP 来连接 MongoDB。本教程我们会使用 MongoDB shell 来连接 Mongodb 服务，之后的章节我们将会介绍如何通过 PHP、Python 以及 Node.js 来连接 MongoDB 服务。\n\n标准 URI 连接语法：\n\n```text\n\nmongodb://[username:password@]host1[:port1][,...hostN[:portN]][/[defaultauthdb][?options]]\n```\n\n- `mongodb://`：协议头，表示使用 MongoDB。\n- `[username:password@]`：（可选）认证信息，包括用户名和密码。\n- `host1[:port1][,...hostN[:portN]]`：服务器地址和端口，可以是一个或多个 MongoDB 服务器的地址和端口。\n- `/[defaultauthdb]`：（可选）默认认证数据库。\n- `[?options]`：（可选）连接选项。\n\n标准的连接格式包含了多个选项(options)，如下所示：\n\n- `authSource`：指定认证数据库。\n- `replicaSet`：指定副本集的名称。\n- `ssl`：启用 SSL 连接（true 或 false）。\n- `readPreference`：指定读偏好，如 `primary`, `primaryPreferred`, `secondary`, `secondaryPreferred`, `nearest`。\n- `connectTimeoutMS`：指定连接超时时间（毫秒）。\n- `socketTimeoutMS`：指定套接字超时时间（毫秒）。\n\n连接到本地 MongoDB 实例（默认端口 27017）：\n\n```text\n\nmongodb://localhost\n```\n\n连接到本地 MongoDB 实例，指定数据库：\n\n```text\n\nmongodb://localhost/mydatabase\n```\n\n使用用户名和密码连接到本地 MongoDB 实例：\n\n```text\n\nmongodb://username:password@localhost/mydatabase\n```\n\n连接到远程 MongoDB 实例：\n\n```text\n\nmongodb://remotehost:27017\n```\n\n连接到副本集（Replica Set）：\n\n```text\n\nmongodb://host1:27017,host2:27017,host3:27017/mydatabase?replicaSet=myReplicaSet\n```\n\n使用 SSL 连接到 MongoDB：\n\n```text\n\nmongodb://username:password@localhost:27017/mydatabase?ssl=true\n```\n\n使用多个选项连接：\n\n```text\n\nmongodb://username:password@localhost:27017/mydatabase?authSource=admin&ssl=true\n```\n\n### Python (PyMongo)\n\n## 实例\n\nfrom pymongo import MongoClient\n\n### Node.js (Mongoose)\n\n## 实例\n\nconst mongoose = require(\'mongoose\');\n\nmongoose.connect(\'mongodb://user:password@localhost:27017/mydatabase?authSource=admin\', {\n\n  useNewUrlParser: true,\n\n  useUnifiedTopology: true\n\n});\n\nconst db = mongoose.connection;\n\ndb.on(\'error\', console.error.bind(console, \'connection error:\'));\n\ndb.once(\'open\', function() {\n\n  console.log(\'Connected to MongoDB\');\n\n});\n\n### PHP (Mongoose)\n\n## 实例\n\n<?php\n\nrequire \'vendor/autoload.php\'; // 引入 Composer 自动加载文件\n\n$client = new MongoDB\\Client("mongodb://localhost:27017"); // 连接到本地 MongoDB 实例\n\n$database = $client->selectDatabase(\'mydatabase\'); // 选择数据库\n\n$collection = $database->selectCollection(\'mycollection\'); // 选择集合\n\n// 插入文档\n\n$result = $collection->insertOne([\'name\' => \'Alice\', \'age\' => 30]);\n\necho "Inserted with Object ID \'{$result->getInsertedId()}\'";\n\n// 查询文档\n\n$document = $collection->findOne([\'name\' => \'Alice\']);\n\necho "Found document: " . json_encode($document);\n\n?>\n\n### Java\n\n## 实例\n\nimport com.mongodb.client.MongoClient;\n\nimport com.mongodb.client.MongoClients;\n\nimport com.mongodb.client.MongoDatabase;\n\npublic class MongoDBConnection {\n\n    public static void main(String[] args) {\n\n        String uri = "mongodb://user:password@localhost:27017/mydatabase?authSource=admin";\n\n        try (MongoClient mongoClient = MongoClients.create(uri)) {\n\n            MongoDatabase database = mongoClient.getDatabase("mydatabase");\n\n            System.out.println("Connected to MongoDB");\n\n        }\n\n    }\n\n}\n\n### 实例\n\n使用默认端口来连接 MongoDB 的服务。\n\n```text\nmongodb://localhost\n```\n\n通过 shell 连接 MongoDB 服务：\n\n```text\n\n./mongosh\nCurrent Mongosh Log ID:    66792d6b87657ebec9ed70f1\nConnecting to:        mongodb://127.0.0.1:27017/?directConnection=true&serverSelectionTimeoutMS=2000&appName=mongosh+2.2.9\nUsing MongoDB:        7.0.11\nUsing Mongosh:        2.2.9\n```\n\n这时候你返回查看运行 ./mongod 命令的窗口，可以看到是从哪里连接到MongoDB的服务器，您可以看到如下信息：\n\n```text\n\n……省略信息……\n2015-09-25T17:22:27.336+0800 I CONTROL  [initandlisten] allocator: tcmalloc\n2015-09-25T17:22:27.336+0800 I CONTROL  [initandlisten] options: { storage: { dbPath: "/data/db" } }\n2015-09-25T17:22:27.350+0800 I NETWORK  [initandlisten] waiting for connections on port 27017\n2015-09-25T17:22:36.012+0800 I NETWORK  [initandlisten] connection accepted from 127.0.0.1:37310 #1 (1 connection now open)  # 该行表明一个来自本机的连接\n\n……省略信息……\n```\n\n## MongoDB 连接命令格式\n\n使用用户名和密码连接到 MongoDB 服务器，你必须使用 \'username:password@hostname/dbname\' 格式，\'username\'为用户名，\'password\' 为密码。\n\n使用用户名和密码连接登录到默认数据库：\n\n```text\n\n$ ./mongosh\nMongoDB shell version: 4.0.9\nconnecting to: test\n```\n\n使用用户 admin 使用密码 123456 连接到本地的 MongoDB 服务上。输出结果如下所示：\n\n```text\n\n> mongodb://admin:123456@localhost/\n... \n```\n\n使用用户名和密码连接登录到指定数据库，格式如下：\n\n```text\nmongodb://admin:123456@localhost/test\n```\n\n### 更多连接实例\n\n连接本地数据库服务器，端口是默认的。\n\n```text\nmongodb://localhost\n```\n\n使用用户名fred，密码foobar登录localhost的admin数据库。\n\n```text\nmongodb://fred:foobar@localhost\n```\n\n使用用户名fred，密码foobar登录localhost的baz数据库。\n\n```text\nmongodb://fred:foobar@localhost/baz\n```\n\n连接 replica pair, 服务器1为example1.com服务器2为example2。\n\n```text\nmongodb://example1.com:27017,example2.com:27017\n```\n\n连接 replica set 三台服务器 (端口 27017, 27018, 和27019):\n\n```text\nmongodb://localhost,localhost:27018,localhost:27019\n```\n\n连接 replica set 三台服务器, 写入操作应用在主服务器 并且分布查询到从服务器。\n\n```text\nmongodb://host1,host2,host3/?slaveOk=true\n```\n\n直接连接第一个服务器，无论是replica set一部分或者主服务器或者从服务器。\n\n```text\nmongodb://host1,host2,host3/?connect=direct;slaveOk=true\n```\n\n当你的连接服务器有优先级，还需要列出所有服务器，你可以使用上述连接方式。\n\n安全模式连接到localhost:\n\n```text\nmongodb://localhost/?safe=true\n```\n\n以安全模式连接到replica set，并且等待至少两个复制服务器成功写入，超时时间设置为2秒。\n\n```text\nmongodb://host1,host2,host3/?safe=true;w=2;wtimeoutMS=2000\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-connections.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-connections','MongoDB 连接 - MongoDB 教程','在本教程我们将讨论 MongoDB 的不同连接方式。 在前面的教程中，我们已经讨论了如何启动 MongoDB 服务https://www.runoob.com/mongodb/mongodb-window-install.html，你只需要...',0,'PUBLISHED',3870,150,95,18,'2025-07-10 00:00:00','2025-07-10 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631010,1,'MongoDB 创建集合','本章节我们为大家介绍如何使用 MongoDB 来创建集合。 MongoDB 中使用 createCollection 方法来创建集合。 options 可以是如下参数： 在插入文档时，MongoDB 首先检查固定集合的 size 字段，然后检查 max 字段。','# MongoDB 创建集合\n\n本章节我们为大家介绍如何使用 MongoDB 来创建集合。\n\nMongoDB 中使用 createCollection() 方法来创建集合。\n\n语法格式：\n\n```text\ndb.createCollection(name, options)\n```\n\n参数说明：\n\n- name: 要创建的集合名称。\n- options: 可选参数, 指定有关内存大小及索引的选项。\n\noptions 可以是如下参数：\n\n| 参数名 | 类型 | 描述 | 示例值 |\n| --- | --- | --- | --- |\n| capped | 布尔值 | 是否创建一个固定大小的集合。 | true |\n| size | 数值 | 集合的最大大小（以字节为单位）。仅在 capped 为 true 时有效。 | 10485760 (10MB) |\n| max | 数值 | 集合中允许的最大文档数。仅在 capped 为 true 时有效。 | 5000 |\n| validator | 对象 | 用于文档验证的表达式。 | { $jsonSchema: { ... }} |\n| validationLevel | 字符串 | 指定文档验证的严格程度。 "off" ：不进行验证。 "strict" ：插入和更新操作都必须通过验证（默认）。 "moderate" ：仅现有文档更新时必须通过验证，插入新文档时不需要。 | "strict" |\n| validationAction | 字符串 | 指定文档验证失败时的操作。 "error" ：阻止插入或更新（默认）。 "warn" ：允许插入或更新，但会发出警告。 | "error" |\n| storageEngine | 对象 | 为集合指定存储引擎配置。 | { wiredTiger: { ... }} |\n| collation | 对象 | 指定集合的默认排序规则。 | { locale: "en", strength: 2 } |\n\n在插入文档时，MongoDB 首先检查固定集合的 size 字段，然后检查 max 字段。\n\n使用这些选项创建一个集合的实例：\n\n## 实例\n\ndb.createCollection("myComplexCollection", {\n\n这个例子创建了一个集合，具有以下特性：\n\n- 固定大小，最大 10MB，最多存储 5000 个文档。\n- 文档必须包含 `name` 和 `email` 字段，其中 `name` 必须是字符串，`email` 必须是有效的电子邮件格式。\n- 验证级别为严格，验证失败将阻止插入或更新。\n- 使用 WiredTiger 存储引擎，指定块压缩器为 zstd。\n- 默认使用英语排序规则。\n\n### 实例\n\n在 test 数据库中创建 runoob 集合：\n\n```text\n> use test\nswitched to db test\n> db.createCollection("runoob")\n{ "ok" : 1 }\n>\n```\n\n如果要查看已有集合，可以使用 show collections 或 show tables 命令：\n\n```text\n> show collections\nrunoob\nsystem.indexes\n```\n\n下面是带有几个关键参数的 createCollection() 的用法：\n\n创建了一个固定大小的集合，最大大小为 5MB（5242880 字节），最多存储 5000 个文档。\n\n```text\ndb.createCollection("myCappedCollection", { capped: true, size: 5242880, max: 5000 });\n```\n\n在 MongoDB 中，你不需要创建集合，当你插入一些文档时，MongoDB 会自动创建集合。\n\n```text\n> db.mycol2.insert({"name" : "菜鸟教程"})\n> show collections\nmycol2\n...\n```\n\n创建了一个最大大小为 1MB（1048576 字节）的固定大小集合：\n\n```text\ndb.createCollection("myCappedCollection", { capped: true, size: 1048576 });\n```\n\n以下例子为 myCollection 集合创建了一个验证器，要求文档中必须有 name 和 age 字段，且 name 必须是字符串，age 必须是非负整数。\n\n## 实例\n\ndb.createCollection("myCollection", {\n\n  validator: { $jsonSchema: {\n\n    bsonType: "object",\n\n    required: ["name", "age"],\n\n    properties: {\n\n      name: {\n\n        bsonType: "string",\n\n        description: "必须为字符串且为必填项"\n\n      },\n\n      age: {\n\n        bsonType: "int",\n\n        minimum: 0,\n\n        description: "必须为整数且为必填项"\n\n      }\n\n    }\n\n  }}\n\n});\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-create-collection.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-create-collection','MongoDB 创建集合 - MongoDB 教程','本章节我们为大家介绍如何使用 MongoDB 来创建集合。 MongoDB 中使用 createCollection 方法来创建集合。 options 可以是如下参数： 在插入文档时，MongoDB 首先检查固定集合的 size 字段，然后...',0,'PUBLISHED',4007,157,100,19,'2025-07-11 00:00:00','2025-07-11 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631011,1,'MongoDB 更新集合名','在 MongoDB 中，不能直接通过命令来重命名集合。 MongoDB 可以使用 renameCollection 方法来来重命名集合。 renameCollection 方法在 MongoDB 的 admin 数据库中运行，可以将一个集合重命名为另一个名称。 renameCollection 命令的语法：','# MongoDB 更新集合名\n\n在 MongoDB 中，不能直接通过命令来重命名集合。\n\nMongoDB 可以使用 renameCollection 方法来来重命名集合。\n\nrenameCollection 方法在 MongoDB 的 admin 数据库中运行，可以将一个集合重命名为另一个名称。\n\nrenameCollection 命令的语法：\n\n```text\ndb.adminCommand({\n  renameCollection: "sourceDb.sourceCollection",\n  to: "targetDb.targetCollection",\n  dropTarget: <boolean>\n})\n```\n\n参数说明：\n\n- renameCollection：要重命名的集合的完全限定名称（包括数据库名）。\n- to：目标集合的完全限定名称（包括数据库名）。\n- dropTarget（可选）：布尔值。如果目标集合已经存在，是否删除目标集合。默认值为 `false`。\n\n### 实例\n\n假设你要将 test 数据库中的 oldCollection 重命名为 newCollection，可以按以下步骤进行：\n\n1. 确保已连接到 test 数据库\n\n```text\n\nuse test\n```\n\n2. 运行 renameCollection 命令\n\n```text\n\ndb.adminCommand({ \n  renameCollection: "test.oldCollection", \n  to: "test.newCollection" \n});\n```\n\n如果你要将集合重命名到另一个数据库，例如将 test 数据库中的 oldCollection 重命名为 production 数据库中的 newCollection，可以这样做：\n\n```text\ndb.adminCommand({ \n  renameCollection: "test.oldCollection", \n  to: "production.newCollection" \n});\n```\n\n### 注意事项\n\n- 权限要求：执行 `renameCollection` 命令需要具有对源数据库和目标数据库的适当权限。通常需要 `dbAdmin` 或 `dbOwner` 角色。\n- 目标集合不存在：目标集合不能已经存在。如果目标集合存在，则会返回错误。\n- 索引和数据：重命名集合会保留所有文档和索引。\n\n### 检查重命名结果\n\n重命名后，可以通过以下命令检查新的集合是否存在：\n\n```text\n\nuse test\nshow collections\n```\n\n如果集合已重命名为 newCollection，你应该会在结果中看到 newCollection。\n\n### 处理重命名失败的情况\n\n如果重命名过程中发生错误，你可以根据错误消息采取相应的措施。例如，如果目标集合已经存在，可以先删除目标集合（如果确认不需要），然后重新执行重命名操作：\n\n## 实例\n\nuse production\n\n通过 renameCollection 方法，你可以有效地管理 MongoDB 集合的名称，确保数据库结构符合应用需求。\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-renamecollection.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-renamecollection','MongoDB 更新集合名 - MongoDB 教程','在 MongoDB 中，不能直接通过命令来重命名集合。 MongoDB 可以使用 renameCollection 方法来来重命名集合。 renameCollection 方法在 MongoDB 的 admin 数据库中运行，可以将一个集合...',0,'PUBLISHED',4144,164,105,20,'2025-07-12 00:00:00','2025-07-12 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631012,1,'MongoDB 删除集合','本章节我们为大家介绍如何使用 MongoDB 来删除集合。 MongoDB 中使用 drop 方法来删除集合。 drop 方法可以永久地从数据库中删除指定的集合及其所有文档，这是一个不可逆的操作，因此需要谨慎使用。 如果成功删除选定集合，则 drop 方法返回 true，否则返回 false。','# MongoDB 删除集合\n\n本章节我们为大家介绍如何使用 MongoDB 来删除集合。\n\nMongoDB 中使用 drop() 方法来删除集合。\n\ndrop() 方法可以永久地从数据库中删除指定的集合及其所有文档，这是一个不可逆的操作，因此需要谨慎使用。\n\n语法格式：\n\n```text\ndb.collection.drop()\n```\n\n参数说明：\n\n- 无\n\n返回值\n\n如果成功删除选定集合，则 drop() 方法返回 true，否则返回 false。\n\n### 实例\n\n在数据库 mydb 中，我们可以先通过 show collections 命令查看已存在的集合：\n\n```text\n>use mydb\nswitched to db mydb\n>show collections\nmycol\nmycol2\nsystem.indexes\nrunoob\n>\n```\n\n接着删除集合 mycol2 :\n\n```text\n>db.mycol2.drop()\ntrue\n>\n```\n\n通过 show collections 再次查看数据库 mydb 中的集合：\n\n```text\n>show collections\nmycol\nsystem.indexes\nrunoob\n>\n```\n\n从结果中可以看出 mycol2 集合已被删除。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-delete-collection.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-delete-collection','MongoDB 删除集合 - MongoDB 教程','本章节我们为大家介绍如何使用 MongoDB 来删除集合。 MongoDB 中使用 drop 方法来删除集合。 drop 方法可以永久地从数据库中删除指定的集合及其所有文档，这是一个不可逆的操作，因此需要谨慎使用。 如果成功删除选定集合，则...',0,'PUBLISHED',4281,171,110,21,'2025-07-13 00:00:00','2025-07-13 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631013,1,'MongoDB 插入文档','本章节中我们将向大家介绍如何将数据插入到 MongoDB 的集合中。 文档的数据结构和 JSON 基本一样。 所有存储在集合中的数据都是 BSON 格式。 BSON 是一种类似 JSON 的二进制形式的存储格式，是 Binary JSON 的简称。','# MongoDB 插入文档\n\n本章节中我们将向大家介绍如何将数据插入到 MongoDB 的集合中。\n\n文档的数据结构和 JSON 基本一样。\n\n所有存储在集合中的数据都是 BSON 格式。\n\nBSON 是一种类似 JSON 的二进制形式的存储格式，是 Binary JSON 的简称。\n\n常用的插入文档方法包括：\n\n| 方法 | 用途 | 是否弃用 |\n| --- | --- | --- |\n| insertOne() | 插入单个文档 | 否 |\n| insertMany() | 插入多个文档 | 否 |\n| insert() | 插入单个或多个文档 | 是 |\n| save() | 插入或更新文档 | 是 |\n\n### 1、insertOne()\n\ninsertOne() 方法用于在集合中插入单个文档。\n\n```text\ndb.collection.insertOne(document, options)\n```\n\n- document：要插入的单个文档。\n- options（可选）：一个可选参数对象，可以包含 writeConcern 和 bypassDocumentValidation 等。\n\n## 实例\n\ndb.myCollection.insertOne({\n\n返回结果：\n\n```text\n\n{\n    "acknowledged": true,\n    "insertedId": ObjectId("60c72b2f9b1d8b5a5f8e2b2d")\n}\n```\n\n### 2、insertMany()\n\ninsertMany() 方法用于在集合中插入多个文档。\n\n```text\n\ndb.collection.insertMany(documents, options)\n```\n\n- documents：要插入的文档数组。\n- options（可选）：一个可选参数对象，可以包含 ordered、writeConcern 和 bypassDocumentValidation 等。\n\n```text\n\ndb.myCollection.insertMany([\n    { name: "Bob", age: 30, city: "Los Angeles" },\n    { name: "Charlie", age: 35, city: "Chicago" }\n]);\n```\n\n返回结果：\n\n```text\n{\n    "acknowledged": true,\n    "insertedIds": [\n        ObjectId("60c72b2f9b1d8b5a5f8e2b2e"),\n        ObjectId("60c72b2f9b1d8b5a5f8e2b2f")\n    ]\n}\n```\n\n### 3、db.collection.save()\n\nsave() 方法在插入文档时表现得类似于 insertOne()。\n\n如果文档包含 _id 字段且已存在，则该文档会被更新；如果文档不包含 _id 字段或 _id 不存在，则会插入一个新文档。\n\n从 MongoDB 4.2 开始，db.collection.save() 已被标记为弃用（deprecated），官方推荐使用 db.collection.insertOne() 或 db.collection.replaceOne() 替代。\n\n```text\n\ndb.collection.save(document, options)\n```\n\n- document：要保存的文档。\n- options（可选）：一个可选参数对象，可以包含 writeConcern 等。\n\n```text\n\ndb.myCollection.save({\n    _id: ObjectId("60c72b2f9b1d8b5a5f8e2b2d"),\n    name: "David",\n    age: 40,\n    city: "San Francisco"\n});\n```\n\n### 插入单个或多个文档（旧方法）\n\n使用 db.collection.insert() 方法插入单个或多个文档。\n\ninsert() 方法在 MongoDB 4.2 及更高版本中已被标记为弃用（deprecated），推荐使用 insertOne() 和 insertMany()。\n\n语法：\n\n```text\n\ndb.collection.insert(document_or_array)\n```\n\n参数：\n\n- 可以是一个文档，也可以是一个文档数组。\n\n1、插入单个文档：\n\n```text\n\ndb.users.insert({ name: "David", age: 40, email: "\n[email protected]\n" });\n```\n\n2、插入多个文档：\n\n```text\n\ndb.users.insert([\n  { name: "Eve", age: 45, email: "\n[email protected]\n" },\n  { name: "Frank", age: 50, email: "\n[email protected]\n" }\n]);\n```\n\n### 批量插入的性能优化\n\n如果需要插入大量文档，可以使用 insertMany() 并启用 ordered: false 选项，以提高插入性能。\n\n语法：\n\n```text\n\ndb.collection.insertMany([document1, document2, ...], { ordered: false })\n```\n\n参数：\n\n- `ordered: false`：表示无序插入，即使某个文档插入失败，也不会影响其他文档的插入。\n\n## 实例\n\ndb.users.insertMany([\n\n  { name: "Henry", age: 60 },\n\n  { name: "Ivy", age: 65 }\n\n], { ordered: false });\n\n### 插入时的验证\n\nMongoDB 会根据集合的 schema 验证规则（如果定义了）对插入的文档进行验证。如果文档不符合规则，插入操作会失败。\n\n假设集合 users 有一个验证规则，要求 age 字段必须大于 0：\n\n```text\n\ndb.createCollection("users", {\n  validator: {\n    age: { $gt: 0 }\n  }\n});\n```\n\n如果插入以下文档会失败：\n\n```text\n\ndb.users.insertOne({ name: "John", age: -5 }); // 验证失败\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-insert.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-insert','MongoDB 插入文档 - MongoDB 教程','本章节中我们将向大家介绍如何将数据插入到 MongoDB 的集合中。 文档的数据结构和 JSON 基本一样。 所有存储在集合中的数据都是 BSON 格式。 BSON 是一种类似 JSON 的二进制形式的存储格式，是 Binary JSON ...',0,'PUBLISHED',4418,178,115,22,'2025-07-14 00:00:00','2025-07-14 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631014,1,'MongoDB 更新文档','在 MongoDB 中，更新文档的操作可以使用多种方法实现，常用的方法包括 updateOne、updateMany、replaceOne 和 findOneAndUpdate。 updateOne 方法用于更新匹配过滤器的单个文档。 db.myCollection.updateOne updateMany 方法用于更新所有匹配过滤器的文档。','# MongoDB 更新文档\n\n在 MongoDB 中，更新文档的操作可以使用多种方法实现，常用的方法包括 updateOne()、updateMany()、replaceOne() 和 findOneAndUpdate()。\n\n### 1、updateOne()\n\nupdateOne() 方法用于更新匹配过滤器的单个文档。\n\n语法：\n\n```text\ndb.collection.updateOne(filter, update, options)\n```\n\n- filter：用于查找文档的查询条件。\n- update：指定更新操作的文档或更新操作符。\n- options：可选参数对象，如 `upsert`、`arrayFilters` 等。\n\n## 实例\n\ndb.myCollection.updateOne(\n\n### 2、updateMany()\n\nupdateMany() 方法用于更新所有匹配过滤器的文档。\n\n语法：\n\n```text\ndb.collection.updateMany(filter, update, options)\n```\n\n- filter：用于查找文档的查询条件。\n- update：指定更新操作的文档或更新操作符。\n- options：可选参数对象，如 `upsert`、`arrayFilters` 等。\n\n## 实例\n\ndb.myCollection.updateMany(\n\n    { age: { $lt: 30 } },             // 过滤条件\n\n    { $set: { status: "active" } },   // 更新操作\n\n    { upsert: false }                  // 可选参数\n\n);\n\n### 3、replaceOne()\n\nreplaceOne() 方法用于替换匹配过滤器的单个文档，新的文档将完全替换旧的文档。\n\n语法：\n\n```text\ndb.collection.replaceOne(filter, replacement, options)\n```\n\n- filter：用于查找文档的查询条件。\n- replacement：新的文档，将替换旧的文档。\n- options：可选参数对象，如 `upsert` 等。\n\n## 实例\n \ndb.myCollection.replaceOne(\n\n    { name: "Bob" },                  // 过滤条件\n\n    { name: "Bob", age: 31 }          // 新文档\n\n);\n\n### 4、findOneAndUpdate()\n\nfindOneAndUpdate() 方法用于查找并更新单个文档，可以选择返回更新前或更新后的文档。\n\n语法：\n\n```text\n\ndb.collection.findOneAndUpdate(filter, update, options)\n```\n\n- filter：用于查找文档的查询条件。\n- update：指定更新操作的文档或更新操作符。\n- options：可选参数对象，如 `projection`、`sort`、`upsert`、`returnDocument` 等。\n\n## 实例\n\ndb.myCollection.findOneAndUpdate(\n\n    { name: "Charlie" },              // 过滤条件\n\n    { $set: { age: 36 } },            // 更新操作\n\n    { returnDocument: "after" }       // 可选参数，返回更新后的文档\n\n);\n\n### 选项参数\n\n这些更新方法的 options 参数通常可以包含以下选项：\n\n- upsert：如果没有匹配的文档，是否插入一个新文档。\n- arrayFilters：当更新嵌套数组时，指定应更新的数组元素的条件。\n- collation：指定比较字符串时使用的排序规则。\n- returnDocument：在 findOneAndUpdate 中使用，指定返回更新前 ("before") 或更新后 ("after") 的文档。\n\n### 简单实例\n\n更新单个文档：\n\n```text\n\ndb.myCollection.updateOne(\n    { name: "Alice" },\n    { $set: { age: 26 } }\n);\n```\n\n更新多个文档：\n\n```text\n\ndb.myCollection.updateMany(\n    { age: { $lt: 30 } },\n    { $set: { status: "active" } }\n);\n```\n\n替换单个文档：\n\n```text\n\ndb.myCollection.replaceOne(\n    { name: "Bob" },\n    { name: "Bob", age: 31 }\n);\n```\n\n查找并更新单个文档：\n\n```text\n\ndb.myCollection.findOneAndUpdate(\n    { name: "Charlie" },\n    { $set: { age: 36 } },\n    { returnDocument: "after" }\n);\n```\n\n以下实例中我们替换了 _id  为 56064f89ade2f21f36b03136 的文档数据：\n\n```text\n\n>db.col.save({\n    "_id" : ObjectId("56064f89ade2f21f36b03136"),\n    "title" : "MongoDB",\n    "description" : "MongoDB 是一个 Nosql 数据库",\n    "by" : "Runoob",\n    "url" : "http://www.runoob.com",\n    "tags" : [\n            "mongodb",\n            "NoSQL"\n    ],\n    "likes" : 110\n})\n```\n\n替换成功后，我们可以通过 find() 命令来查看替换后的数据\n\n```text\n\n>db.col.find().pretty()\n{\n        "_id" : ObjectId("56064f89ade2f21f36b03136"),\n        "title" : "MongoDB",\n        "description" : "MongoDB 是一个 Nosql 数据库",\n        "by" : "Runoob",\n        "url" : "http://www.runoob.com",\n        "tags" : [\n                "mongodb",\n                "NoSQL"\n        ],\n        "likes" : 110\n}\n> \n```\n\n## 更多实例\n\n只更新第一条记录：\n\n```text\n\ndb.col.update( { "count" : { $gt : 1 } } , { $set : { "test2" : "OK"} } );\n```\n\n全部更新：\n\n```text\n\ndb.col.update( { "count" : { $gt : 3 } } , { $set : { "test2" : "OK"} },false,true );\n```\n\n只添加第一条：\n\n```text\n\ndb.col.update( { "count" : { $gt : 4 } } , { $set : { "test5" : "OK"} },true,false );\n```\n\n全部添加进去:\n\n```text\ndb.col.update( { "count" : { $gt : 5 } } , { $set : { "test5" : "OK"} },true,true );\n```\n\n全部更新：\n\n```text\n\ndb.col.update( { "count" : { $gt : 15 } } , { $inc : { "count" : 1} },false,true );\n```\n\n只更新第一条记录：\n\n```text\n\ndb.col.update( { "count" : { $gt : 10 } } , { $inc : { "count" : 1} },false,false );\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-update.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-update','MongoDB 更新文档 - MongoDB 教程','在 MongoDB 中，更新文档的操作可以使用多种方法实现，常用的方法包括 updateOne、updateMany、replaceOne 和 findOneAndUpdate。 updateOne 方法用于更新匹配过滤器的单个文档。 db...',0,'PUBLISHED',4555,185,120,23,'2025-07-15 00:00:00','2025-07-15 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631015,1,'MongoDB 删除文档','在前面的几个章节中我们已经学习了 MongoDB 中如何为集合添加数据和更新数据，在本章节中我们将继续学习 MongoDB 集合的删除。 常用的删除文档方法包括 deleteOne、deleteMany 以及 findOneAndDelete。 deleteOne 方法用于删除匹配过滤器的单个文档。 db.myCollection.deleteOne{ name: "Alice" };','# MongoDB 删除文档\n\n在前面的几个章节中我们已经学习了 MongoDB 中如何为集合添加数据和更新数据，在本章节中我们将继续学习 MongoDB 集合的删除。\n\n常用的删除文档方法包括 deleteOne()、deleteMany() 以及 findOneAndDelete()。\n\n使用场景：\n\n- 数据清理：删除不再需要的旧数据或无效数据。\n- 数据修正：在数据修正过程中删除错误的或重复的文档。\n- 自动化任务：在自动化脚本或任务中，根据特定条件删除文档。\n\n### 1、deleteOne()\n\ndeleteOne() 方法用于删除匹配过滤器的单个文档。\n\n语法：\n\n```text\ndb.collection.deleteOne(filter, options)\n```\n\n- filter：用于查找要删除的文档的查询条件。\n- options（可选）：一个可选参数对象。\n\n## 实例\n\ndb.myCollection.deleteOne({ name: "Alice" });\n\n返回结果：\n\n```text\n{\n    "acknowledged": true,\n    "deletedCount": 1\n}\n```\n\n### 2、deleteMany()\n\ndeleteMany() 方法用于删除所有匹配过滤器的文档。\n\n语法：\n\n```text\n\ndb.collection.deleteMany(filter, options)\n```\n\n- filter：用于查找要删除的文档的查询条件。\n- options（可选）：一个可选参数对象。\n\n## 实例\n\ndb.myCollection.deleteMany({ status: "inactive" });\n\n返回结果：\n\n```text\n{\n    "acknowledged": true,\n    "deletedCount": 1\n}\n```\n\n### 3、findOneAndDelete()\n\nfindOneAndDelete() 方法用于查找并删除单个文档，并可以选择返回删除的文档。\n\n语法：\n\n```text\ndb.collection.findOneAndDelete(filter, options)\n```\n\n- filter：用于查找要删除的文档的查询条件。\n- options：可选参数对象，如 `projection`、`sort` 等。\n\n## 实例\n\ndb.myCollection.findOneAndDelete(\n\n    { name: "Charlie" },\n\n    { projection: { name: 1, age: 1 } }\n\n);\n\nfindOneAndDelete 返回被删除的文档，如果找不到匹配的文档，则返回 null。\n\n### 删除操作的选项\n\n这些删除方法的 options 参数通常可以包含以下选项：\n\n- writeConcern：指定写操作的确认级别。\n- collation：指定比较字符串时使用的排序规则。\n- projection（仅适用于 `findOneAndDelete`）：指定返回的字段。\n- sort（仅适用于 `findOneAndDelete`）：指定排序顺序以确定要删除的文档。\n\n### 实例\n\n删除单个文档：\n\n```text\n\ndb.myCollection.deleteOne({ name: "Alice" });\n```\n\n删除多个文档：\n\n```text\n\ndb.myCollection.deleteMany({ status: "inactive" });\n```\n\n查找并删除单个文档：\n\n```text\n\ndb.myCollection.findOneAndDelete(\n    { name: "Charlie" },\n    { projection: { name: 1, age: 1 } }\n);\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-remove.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-remove','MongoDB 删除文档 - MongoDB 教程','在前面的几个章节中我们已经学习了 MongoDB 中如何为集合添加数据和更新数据，在本章节中我们将继续学习 MongoDB 集合的删除。 常用的删除文档方法包括 deleteOne、deleteMany 以及 findOneAndDelet...',0,'PUBLISHED',4692,192,125,24,'2025-07-16 00:00:00','2025-07-16 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631016,1,'MongoDB 查询文档','MongoDB 查询文档使用 find、findOne 方法。 find 方法以非结构化的方式来显示所有文档。 MongoDB 查询数据的语法格式如下： db.myCollection.find;','# MongoDB 查询文档\n\nMongoDB 查询文档使用 find()、findOne() 方法。\n\nfind() 方法以非结构化的方式来显示所有文档。\n\n### 语法\n\nMongoDB 查询数据的语法格式如下：\n\n```text\ndb.collection.find(query, projection)\n```\n\n- query：用于查找文档的查询条件。默认为 `{}`，即匹配所有文档。\n- projection（可选）：指定返回结果中包含或排除的字段。\n\n查找所有文档：\n\n## 实例\n\ndb.myCollection.find();\n\n按条件查找文档：\n\n## 实例\n\ndb.myCollection.find({ age: { $gt: 25 } });\n\n按条件查找文档，并只返回指定字段：\n\n## 实例\n\ndb.myCollection.find(\n\n    { age: { $gt: 25 } },\n\n    { name: 1, age: 1, _id: 0 }\n\n);\n\n如果你需要以易读的方式来读取数据，可以使用 pretty() 方法，语法格式如下：\n\n```text\n\n>db.col.find().pretty()\n```\n\npretty() 方法以格式化的方式来显示所有文档。\n\n## 实例\n\ndb.col.find().pretty()\n\n{\n\n        "_id" : ObjectId("56063f17ade2f21f36b03133"),\n\n        "title" : "MongoDB 教程",\n\n        "description" : "MongoDB 是一个 Nosql 数据库",\n\n        "by" : "菜鸟教程",\n\n        "url" : "http://www.runoob.com",\n\n        "tags" : [\n\n                "mongodb",\n\n                "database",\n\n                "NoSQL"\n\n        ],\n\n        "likes" : 100\n\n}\n\n### 2、findOne()\n\nfindOne() 方法用于查找集合中的单个文档。如果找到多个匹配的文档，它只返回第一个。\n\n语法：\n\n```text\n\ndb.collection.findOne(query, projection)\n```\n\n- query：用于查找文档的查询条件。默认为 `{}`，即匹配所有文档。\n- projection（可选）：指定返回结果中包含或排除的字段。\n\n查找单个文档：\n\n```text\n\ndb.myCollection.findOne({ name: "Alice" });\n```\n\n查找单个文档，并只返回指定字段：\n```text\n\ndb.myCollection.findOne(\n    { name: "Alice" },\n    { name: 1, age: 1, _id: 0 }\n);\n```\n\n## 高级查询方法\n\n### 1、使用比较操作符\n\nMongoDB 支持多种比较操作符，如 $gt、$lt、$gte、$lte、$eq、$ne 等。\n\n查找年龄大于 25 的文档:\n\n```text\n\ndb.myCollection.find({ age: { $gt: 25 } });\n```\n\n### 2、使用逻辑操作符\n\nMongoDB 支持多种逻辑操作符，如 $and、$or、$not、$nor 等。\n\n查找年龄大于 25 且城市为 "New York" 的文档:\n\n## 实例\n\ndb.myCollection.find({\n\n    $and: [\n\n        { age: { $gt: 25 } },\n\n        { city: "New York" }\n\n    ]\n\n});\n\n### 3、使用正则表达式\n\n可以使用正则表达式进行模式匹配查询。\n\n查找名字以 "A" 开头的文档：\n\n```text\n\ndb.myCollection.find({ name: /^A/ });\n```\n\n### 4、投影\n\n投影用于控制查询结果中返回的字段。可以使用包含字段和排除字段两种方式。\n\n只返回名字和年龄字段：\n\n## 实例\n\ndb.myCollection.find(\n\n    { age: { $gt: 25 } },\n\n    { name: 1, age: 1, _id: 0 }\n\n);\n\n### 5、排序\n\n可以对查询结果进行排序。\n\n按年龄降序排序：\n\n```text\n\ndb.myCollection.find().sort({ age: -1 });\n```\n\n### 6、限制与跳过\n\n可以对查询结果进行限制和跳过指定数量的文档。\n\n返回前 10 个文档：\n\n```text\n\ndb.myCollection.find().limit(10);\n```\n\n跳过前 5 个文档，返回接下来的 10 个文档：\n\n```text\n\ndb.myCollection.find().skip(5).limit(10);\n```\n\n### 实例\n\n查找年龄大于 25 且城市为 "New York" 的文档，只返回名字和年龄字段，按年龄降序排序，并返回前 10 个文档。\n\n## 实例\n\ndb.myCollection.find(\n\n    {\n\n        $and: [\n\n            { age: { $gt: 25 } },\n\n            { city: "New York" }\n\n        ]\n\n    },\n\n    { name: 1, age: 1, _id: 0 }\n\n).sort({ age: -1 }).limit(10);\n\n## MongoDB 与 RDBMS Where 语句比较\n\n如果你熟悉常规的 SQL 数据，通过下表可以更好的理解 MongoDB 的条件语句查询：\n\n| 操作 | 格式 | 范例 | RDBMS中的类似语句 |\n| --- | --- | --- | --- |\n| 等于 | {<key>:<value> } | db.col.find({"by":"菜鸟教程"}).pretty() | where by = \'菜鸟教程\' |\n| 小于 | {<key>:{$lt:<value>}} | db.col.find({"likes":{$lt:50}}).pretty() | where likes < 50 |\n| 小于或等于 | {<key>:{$lte:<value>}} | db.col.find({"likes":{$lte:50}}).pretty() | where likes <= 50 |\n| 大于 | {<key>:{$gt:<value>}} | db.col.find({"likes":{$gt:50}}).pretty() | where likes > 50 |\n| 大于或等于 | {<key>:{$gte:<value>}} | db.col.find({"likes":{$gte:50}}).pretty() | where likes >= 50 |\n| 不等于 | {<key>:{$ne:<value>}} | db.col.find({"likes":{$ne:50}}).pretty() | where likes != 50 |\n\n## MongoDB AND 条件\n\nMongoDB 的 find() 方法可以传入多个键(key)，每个键(key)以逗号隔开，即常规 SQL  的 AND 条件。\n\n语法格式如下：\n\n```text\n\n>db.col.find({key1:value1, key2:value2}).pretty()\n```\n\n### 实例\n\n以下实例通过 by 和 title 键来查询 菜鸟教程 中 MongoDB 教程 的数据\n\n```text\n\n> db.col.find({"by":"菜鸟教程", "title":"MongoDB 教程"}).pretty()\n{\n        "_id" : ObjectId("56063f17ade2f21f36b03133"),\n        "title" : "MongoDB 教程",\n        "description" : "MongoDB 是一个 Nosql 数据库",\n        "by" : "菜鸟教程",\n        "url" : "http://www.runoob.com",\n        "tags" : [\n                "mongodb",\n                "database",\n                "NoSQL"\n        ],\n        "likes" : 100\n}\n```\n\n以上实例中类似于 WHERE 语句：WHERE by=\'菜鸟教程\' AND title=\'MongoDB 教程\'\n\n## MongoDB OR 条件\n\nMongoDB OR 条件语句使用了关键字 $or,语法格式如下：\n\n```text\n\n>db.col.find(\n   {\n      $or: [\n         {key1: value1}, {key2:value2}\n      ]\n   }\n).pretty()\n```\n\n### 实例\n\n以下实例中，我们演示了查询键 by 值为 菜鸟教程 或键 title 值为 MongoDB 教程 的文档。\n\n```text\n\n>db.col.find({$or:[{"by":"菜鸟教程"},{"title": "MongoDB 教程"}]}).pretty()\n{\n        "_id" : ObjectId("56063f17ade2f21f36b03133"),\n        "title" : "MongoDB 教程",\n        "description" : "MongoDB 是一个 Nosql 数据库",\n        "by" : "菜鸟教程",\n        "url" : "http://www.runoob.com",\n        "tags" : [\n                "mongodb",\n                "database",\n                "NoSQL"\n        ],\n        "likes" : 100\n}\n>\n```\n\n## AND 和 OR 联合使用\n\n以下实例演示了 AND 和 OR 联合使用，类似常规 SQL 语句为：\n\'where likes>50 AND (by = \'菜鸟教程\' OR title = \'MongoDB 教程\')\'\n\n```text\n\n>db.col.find({"likes": {$gt:50}, $or: [{"by": "菜鸟教程"},{"title": "MongoDB 教程"}]}).pretty()\n{\n        "_id" : ObjectId("56063f17ade2f21f36b03133"),\n        "title" : "MongoDB 教程",\n        "description" : "MongoDB 是一个 Nosql 数据库",\n        "by" : "菜鸟教程",\n        "url" : "http://www.runoob.com",\n        "tags" : [\n                "mongodb",\n                "database",\n                "NoSQL"\n        ],\n        "likes" : 100\n}\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-query.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-query','MongoDB 查询文档 - MongoDB 教程','MongoDB 查询文档使用 find、findOne 方法。 find 方法以非结构化的方式来显示所有文档。 MongoDB 查询数据的语法格式如下： db.myCollection.find;',0,'PUBLISHED',4829,199,130,25,'2025-07-17 00:00:00','2025-07-17 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631017,1,'MongoDB 条件操作符','在本章节中，我们将讨论如何在 MongoDB 中使用条件操作符。 在 MongoDB 中，条件操作符用于在查询文档时进行过滤、比较和逻辑操作。 这些操作符可以分为以下几类：比较操作符、逻辑操作符、元素操作符、数组操作符、以及其他常用操作符。 查找年龄等于 25 的人：','# MongoDB 条件操作符\n\n在本章节中，我们将讨论如何在 MongoDB 中使用条件操作符。\n\n在 MongoDB 中，条件操作符用于在查询文档时进行过滤、比较和逻辑操作。\n\n这些操作符可以分为以下几类：比较操作符、逻辑操作符、元素操作符、数组操作符、以及其他常用操作符。\n\n## 比较操作符\n\n比较操作符有：\n\n| 操作符 | 描述 | 示例 |\n| --- | --- | --- |\n| $eq | 等于 | { age: { $eq: 25 } } |\n| $ne | 不等于 | { age: { $ne: 25 } } |\n| $gt | 大于 | { age: { $gt: 25 } } |\n| $gte | 大于等于 | { age: { $gte: 25 } } |\n| $lt | 小于 | { age: { $lt: 25 } } |\n| $lte | 小于等于 | { age: { $lte: 25 } } |\n| $in | 在指定的数组中 | { age: { $in: [25, 30, 35] } } |\n| $nin | 不在指定的数组中 | { age: { $nin: [25, 30, 35] } } |\n\n### $eq (等于)\n\n语法格式：\n\n```text\n{ field: { $eq: value } }\n```\n\n查找年龄等于 25 的人：\n\n```text\n\ndb.collection.find({ age: { $eq: 25 } })\n```\n\n### $ne (不等于)\n\n语法格式：\n\n```text\n{ field: { $ne: value } }\n```\n\n查找年龄不等于 25 的人：\n\n```text\n\ndb.collection.find({ age: { $ne: 25 } })\n```\n\n### $gt (大于)\n\n语法格式：\n\n```text\n{ field: { $gt: value } }\n```\n\n查找年龄大于 25 的人：\n\n```text\n\ndb.collection.find({ age: { $gt: 25 } })\n```\n\n### $gte (大于等于)\n\n语法格式：\n\n```text\n{ field: { $gte: value } }\n```\n\n查找年龄大于或等于 25 的人：\n\n```text\n\ndb.collection.find({ age: { $gte: 25 } })\n```\n\n### $lt (小于)\n\n语法格式：{ field: { $lt: value } }\n\n查找年龄小于 25 的人：\n\n```text\n\ndb.collection.find({ age: { $lt: 25 } })\n```\n\n### $lte (小于等于)\n\n语法格式：\n\n```text\n{ field: { $lte: value } }\n```\n\n查找年龄小于或等于25的人：\n\n```text\n\ndb.collection.find({ age: { $lte: 25 } })\n```\n\n### $in (值在数组中)\n\n语法格式：\n\n```text\n{ field: { $in: [value1, value2, ...] } }\n```\n\n查找年龄在 20、25 和 30 岁之间的人：\n\n```text\n\ndb.collection.find({ age: { $in: [20, 25, 30] } })\n```\n\n### $nin (值不在数组中)\n\n语法格式：\n\n```text\n{ field: { $nin: [value1, value2, ...] } }\n```\n\n查找年龄不在 20、25 和 30 岁之间的人：\n\n```text\n\ndb.collection.find({ age: { $nin: [20, 25, 30] } })\n```\n\n## 逻辑操作符\n\n逻辑操作符有：\n\n| 操作符 | 描述 | 示例 |\n| --- | --- | --- |\n| $and | 逻辑与，符合所有条件 | { $and: [ { age: { $gt: 25 } }, { city: "New York" } ] } |\n| $or | 逻辑或，符合任意条件 | { $or: [ { age: { $lt: 25 } }, { city: "New York" } ] } |\n| $not | 取反，不符合条件 | { age: { $not: { $gt: 25 } } } |\n| $nor | 逻辑或非，均不符合条件 | { $nor: [ { age: { $gt: 25 } }, { city: "New York" } ] } |\n\n### $and (多个条件都成立)\n\n语法格式：\n\n```text\n{ $and: [ { condition1 }, { condition2 } ] }\n```\n\n查找年龄大于 25 且小于 35 的人:\n\n```text\n\ndb.collection.find({ $and: [{ age: { $gt: 25 } }, { age: { $lt: 35 } }] })\n```\n\n### $or (至少一个条件成立)\n\n语法格式：\n\n```text\n{ $or: [ { condition1 }, { condition2 } ] }\n```\n\n查找年龄大于 25 或小于 18 的人:\n\n```text\n\ndb.collection.find({ $or: [{ age: { $gt: 25 } }, { age: { $lt: 18 } }] })\n```\n\n### $not (取反条件)\n\n语法格式：\n\n```text\n{ field: { $not: { condition } } }\n```\n\n查找年龄不大于 25 的人:\n\n```text\n\ndb.collection.find({ age: { $not: { $gt: 25 } } })\n```\n\n### $nor (没有任何条件成立)\n\n语法格式：\n\n```text\n{ $nor: [ { condition1 }, { condition2 } ] }\n```\n\n查找年龄不大于 25 且不小于 18 的人:\n\n```text\n\ndb.collection.find({ $nor: [{ age: { $gt: 25 } }, { age: { $lt: 18 } }] })\n```\n\n## 元素操作符\n\n元素操作符有：\n\n| 操作符 | 描述 | 示例 |\n| --- | --- | --- |\n| $exists | 字段是否存在 | { age: { $exists: true } } |\n| $type | 字段的 BSON 类型 | { age: { $type: "int" } } |\n\n### $exists (字段是否存在)\n\n语法格式：\n\n```text\n{ field: { $exists: boolean } }\n```\n\n查找包含 age 字段的文档:\n\n```text\n\ndb.collection.find({ age: { $exists: true } })\n```\n\n### $type (字段类型)\n\n语法格式：\n\n```text\n{ field: { $type: "type" } }\n```\n\n查找 age 字段为整数类型的文档:\n\n```text\n\ndb.collection.find({ age: { $type: "int" } })\n```\n\n## 数组操作符\n\n数组操作符有：\n\n| 操作符 | 描述 | 示例 |\n| --- | --- | --- |\n| $all | 数组包含所有指定的元素 | { tags: { $all: ["red", "blue"] } } |\n| $elemMatch | 数组中的元素匹配指定条件 | { results: { $elemMatch: { score: { $gt: 80, $lt: 85 } } } } |\n| $size | 数组的长度等于指定值 | { tags: { $size: 3 } } |\n\n查找数组 tags 中包含 "red" 和 "blue" 的文档：\n\n```text\n\ndb.myCollection.find({ tags: { $all: ["red", "blue"] } });\n```\n\n### $all (数组包含指定的所有元素)\n\n语法格式：\n\n```text\n{ field: { $all: [value1, value2, ...] } }\n```\n\n查找 tags 数组中包含 "mongodb" 和 "database" 的文档:\n\n```text\n\ndb.collection.find({ tags: { $all: ["mongodb", "database"] } })\n```\n\n### $elemMatch (数组中至少有一个元素符合条件)\n\n语法格式：\n```text\n{ field: { $elemMatch: { condition } } }\n```\n\n查找 items 数组中 quantity 大于 10 的元素:\n\n```text\n\ndb.collection.find({ items: { $elemMatch: { quantity: { $gt: 10 } } } })\n```\n\n### $size (数组的大小)\n\n语法格式：\n\n```text\n{ field: { $size: value } }\n```\n\n查找 tags 数组大小为 3 的文档:\n\n```text\n\ndb.collection.find({ tags: { $size: 3 } })\n```\n\n## 其他操作符\n\n还有一些其他操作符如下：\n\n| 操作符 | 描述 | 示例 |\n| --- | --- | --- |\n| $regex | 匹配正则表达式 | { name: { $regex: /^A/ } } |\n| $text | 进行文本搜索 | { $text: { $search: "coffee" } } |\n| $where | 使用 JavaScript 表达式进行条件过滤 | { $where: "this.age > 25" } |\n| $near | 查找接近指定点的文档 | db.collection.find({ location: { $near: [10, 20], $maxDistance: 1000 } }) |\n| $geoWithin | 查找在指定地理区域内的文档 | db.collection.find({ location: { $geoWithin: { $centerSphere: [[10, 20], 1] } } }) |\n\n### $regex (正则表达式匹配)\n\n语法格式：\n\n```text\n{ field: { $regex: "pattern" } }\n```\n\n查找 name 以 "John" 开头的文档:\n\n```text\n\ndb.collection.find({ name: { $regex: /^John/ } })\n```\n\n### $near (接近指定点的文档)\n\n语法格式：\n\n```text\n{ field: { $near: [longitude, latitude], $maxDistance: distance } }\n```\n\n查找距离某个位置近的文档:\n\n```text\n\ndb.collection.find({ location: { $near: [10, 20], $maxDistance: 1000 } })\n```\n\n### $geoWithin (查找指定区域内的文档)\n\n语法格式：\n\n```text\n{ field: { $geoWithin: { $centerSphere: [[longitude, latitude], radius] } } }\n```\n\n查找在指定地理区域内的文档:\n\n```text\n\ndb.collection.find({ location: { $geoWithin: { $centerSphere: [[10, 20], 1] } } })\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-operators.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-operators','MongoDB 条件操作符 - MongoDB 教程','在本章节中，我们将讨论如何在 MongoDB 中使用条件操作符。 在 MongoDB 中，条件操作符用于在查询文档时进行过滤、比较和逻辑操作。 这些操作符可以分为以下几类：比较操作符、逻辑操作符、元素操作符、数组操作符、以及其他常用操作符。...',0,'PUBLISHED',4966,206,135,26,'2025-07-18 00:00:00','2025-07-18 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631018,1,'MongoDB $type 操作符','在 MongoDB 中，$type 操作符用于查询具有指定类型的字段的文档。 MongoDB 的 $type 操作符用于查询字段的 BSON 数据类型。 它允许您指定一个或多个类型，并返回匹配这些类型的文档。 以下是 $type 操作符的详细介绍和示例。','# MongoDB $type 操作符\n\n在 MongoDB 中，$type 操作符用于查询具有指定类型的字段的文档。\n\nMongoDB 的 $type 操作符用于查询字段的 BSON 数据类型。\n\n它允许您指定一个或多个类型，并返回匹配这些类型的文档。\n以下是 $type 操作符的详细介绍和示例。\n\n语法：\n\n```text\ndb.collection.find({ field: { $type: <type> } })\n```\n\n- field：要检查类型的字段。\n- type：指定的 BSON 类型，可以是类型的数字代码或类型名称的字符串。\n\n### BSON 类型\n\n以下是常见的 BSON 类型及其对应的数字代码和字符串名称：\n\n| 类型代码 | 类型名称 |\n| --- | --- |\n| 1 | double |\n| 2 | string |\n| 3 | object |\n| 4 | array |\n| 5 | binData |\n| 6 | undefined |\n| 7 | objectId |\n| 8 | bool |\n| 9 | date |\n| 10 | null |\n| 11 | regex |\n| 12 | dbPointer |\n| 13 | javascript |\n| 14 | symbol |\n| 15 | javascriptWithScope |\n| 16 | int |\n| 17 | timestamp |\n| 18 | long |\n| 19 | decimal |\n| 255 | minKey |\n| 127 | maxKey |\n\n### 实例\n\n查找字段类型为字符串的文档:\n\n```text\ndb.myCollection.find({ fieldName: { $type: "string" } })\n```\n\n或使用类型代码：\n\n```text\ndb.myCollection.find({ fieldName: { $type: 2 } })\n```\n\n查找字段类型为数字的文档，例如，查找 age 字段类型为整数的文档：\n\n```text\n\ndb.myCollection.find({ age: { $type: "int" } })\n```\n\n或使用类型代码：\n\n```text\n\ndb.myCollection.find({ age: { $type: 16 } })\n```\n\n查找字段类型为布尔值的文档：\n\n```text\n\ndb.myCollection.find({ isActive: { $type: "bool" } })\n```\n\n或使用类型代码：\n\n```text\n\ndb.myCollection.find({ isActive: { $type: 8 } })\n```\n\n查找字段类型为日期的文档：\n\n```text\ndb.myCollection.find({ createdAt: { $type: "date" } })\n```\n\n或使用类型代码：\n\n```text\n\ndb.myCollection.find({ createdAt: { $type: 9 } })\n```\n\n查找字段类型为多种类型的文档，例如，查找 value 字段类型为字符串或整数的文档：\n\n```text\n\ndb.myCollection.find({ value: { $type: ["string", "int"] } })\n```\n\n或使用类型代码：\n\n```text\n\ndb.myCollection.find({ value: { $type: [2, 16] } })\n```\n\n查找 details 字段类型为对象，并且 score 字段类型为双精度浮点数的文档：\n\n## 实例\n\ndb.myCollection.find({\n\n或使用类型代码：\n\n## 实例\n\ndb.myCollection.find({\n\n    $and: [\n\n        { details: { $type: 3 } },\n\n        { score: { $type: 1 } }\n\n    ]\n\n})\n\n通过使用 $type 操作符，您可以精确地查询文档中特定字段的数据类型，从而进行更细粒度的数据过滤和管理。\n\n## 更多实例\n\n我们使用的数据库名称为"runoob" 我们的集合名称为"col"，以下为我们插入的数据。\n\n简单的集合"col"：\n\n```text\n\n>db.col.insert({\n    title: \'PHP 教程\', \n    description: \'PHP 是一种创建动态交互性站点的强有力的服务器端脚本语言。\',\n    by: \'菜鸟教程\',\n    url: \'http://www.runoob.com\',\n    tags: [\'php\'],\n    likes: 200\n})\n```\n\n```text\n\n>db.col.insert({title: \'Java 教程\', \n    description: \'Java 是由Sun Microsystems公司于1995年5月推出的高级程序设计语言。\',\n    by: \'菜鸟教程\',\n    url: \'http://www.runoob.com\',\n    tags: [\'java\'],\n    likes: 150\n})\n```\n\n```text\n\n>db.col.insert({title: \'MongoDB 教程\', \n    description: \'MongoDB 是一个 Nosql 数据库\',\n    by: \'菜鸟教程\',\n    url: \'http://www.runoob.com\',\n    tags: [\'mongodb\'],\n    likes: 100\n})\n```\n\n使用find()命令查看数据：\n\n```text\n\n> db.col.find()\n{ "_id" : ObjectId("56066542ade2f21f36b0313a"), "title" : "PHP 教程", "description" : "PHP 是一种创建动态交互性站点的强有力的服务器端脚本语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "php" ], "likes" : 200 }\n{ "_id" : ObjectId("56066549ade2f21f36b0313b"), "title" : "Java 教程", "description" : "Java 是由Sun Microsystems公司于1995年5月推出的高级程序设计语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "java" ], "likes" : 150 }\n{ "_id" : ObjectId("5606654fade2f21f36b0313c"), "title" : "MongoDB 教程", "description" : "MongoDB 是一个 Nosql 数据库", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "mongodb" ], "likes" : 100 }\n```\n\n如果想获取 "col" 集合中 title 为 String 的数据，你可以使用以下命令：\n\n```text\n\ndb.col.find({"title" : {$type : 2}})\n或\ndb.col.find({"title" : {$type : \'string\'}})\n```\n\n输出结果为：\n\n```text\n\n{ "_id" : ObjectId("56066542ade2f21f36b0313a"), "title" : "PHP 教程", "description" : "PHP 是一种创建动态交互性站点的强有力的服务器端脚本语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "php" ], "likes" : 200 }\n{ "_id" : ObjectId("56066549ade2f21f36b0313b"), "title" : "Java 教程", "description" : "Java 是由Sun Microsystems公司于1995年5月推出的高级程序设计语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "java" ], "likes" : 150 }\n{ "_id" : ObjectId("5606654fade2f21f36b0313c"), "title" : "MongoDB 教程", "description" : "MongoDB 是一个 Nosql 数据库", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "mongodb" ], "likes" : 100 }\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-operators-type.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-operators-type','MongoDB $type 操作符 - MongoDB 教程','在 MongoDB 中，$type 操作符用于查询具有指定类型的字段的文档。 MongoDB 的 $type 操作符用于查询字段的 BSON 数据类型。 它允许您指定一个或多个类型，并返回匹配这些类型的文档。 以下是 $type 操作符的详...',0,'PUBLISHED',5103,213,140,27,'2025-07-19 00:00:00','2025-07-19 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631019,1,'MongoDB Limit 与 Skip 方法','如果你需要在 MongoDB 中读取指定数量的数据记录，可以使用 MongoDB 的 limit 方法，如果想跳过指定数量的文档读取数据可以使用 skip 方法。 limit 方法用于限制查询结果返回的文档数量，而 skip 方法用于跳过指定数量的文档。这两个方法通常一起使用，可以用来实现分页查询或在大型数据集上进行分批处理。 limit 方法用于限制查询结果返回的文档数量。 limit 方法基本语法如下所示：','# MongoDB Limit 与 Skip 方法\n\n## MongoDB Limit() 方法\n\n如果你需要在 MongoDB 中读取指定数量的数据记录，可以使用 MongoDB 的 limit() 方法，如果想跳过指定数量的文档读取数据可以使用 skip() 方法。\n\nlimit() 方法用于限制查询结果返回的文档数量，而 skip() 方法用于跳过指定数量的文档。这两个方法通常一起使用，可以用来实现分页查询或在大型数据集上进行分批处理。\n\n## limit() 方法\n\nlimit() 方法用于限制查询结果返回的文档数量。\n\n### 语法\n\nlimit() 方法基本语法如下所示：\n\n```text\n\ndb.collection.find().limit(<limit>)\n```\n\n- `<limit>`：返回的文档数量。\n\n## 实例\n\n// 返回前 10 个文档\n\n### 实例\n\n集合 col 中的数据如下：\n\n```text\n\n{ "_id" : ObjectId("56066542ade2f21f36b0313a"), "title" : "PHP 教程", "description" : "PHP 是一种创建动态交互性站点的强有力的服务器端脚本语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "php" ], "likes" : 200 }\n{ "_id" : ObjectId("56066549ade2f21f36b0313b"), "title" : "Java 教程", "description" : "Java 是由Sun Microsystems公司于1995年5月推出的高级程序设计语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "java" ], "likes" : 150 }\n{ "_id" : ObjectId("5606654fade2f21f36b0313c"), "title" : "MongoDB 教程", "description" : "MongoDB 是一个 Nosql 数据库", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "mongodb" ], "likes" : 100 }\n```\n\n以下实例为显示查询文档中的两条记录：\n\n```text\n\n> db.col.find({},{"title":1,_id:0}).limit(2)\n{ "title" : "PHP 教程" }\n{ "title" : "Java 教程" }\n>\n```\n\n注：如果你们没有指定 limit() 方法中的参数则显示集合中的所有数据。\n\n## skip() 方法\n\n我们除了可以使用 limit() 方法来读取指定数量的数据外，还可以使用 skip() 方法来跳过指定数量的数据，skip() 方法同样接受一个数字参数作为跳过的记录条数。\n\nskip() 方法用于跳过指定数量的文档，从而实现分页或分批查询。\n\n### 语法\n\nskip() 方法语法格式如下：\n\n```text\n\ndb.collection.find().skip(<skip>)\n```\n\n- `<skip>`：要跳过的文档数量。\n\n## 实例\n\n// 跳过前 10 个文档，返回接下来的 10 个文档\n\ndb.myCollection.find().skip(10).limit(10);\n\n### 实例\n\n以下实例只会显示第二条文档数据\n\n```text\n\n>db.col.find({},{"title":1,_id:0}).limit(1).skip(1)\n{ "title" : "Java 教程" }\n>\n```\n\n分页查询：\n\n## 实例\n\n// 第一页，每页 10 个文档\n\ndb.myCollection.find().skip(0).limit(10);\n\n// 第二页，每页 10 个文档\n\ndb.myCollection.find().skip(10).limit(10);\n\n// 第三页，每页 10 个文档\n\ndb.myCollection.find().skip(20).limit(10);\n\n注:skip()方法默认参数为 0 。\n\n### 注意事项\n\n- `skip()` 和 `limit()` 方法通常用于配合使用，以实现分页查询。但是在大型数据集上使用 `skip()` 可能会导致性能问题，因为 MongoDB 在执行查询时需要扫描并跳过指定数量的文档，因此建议仅在需要时才使用 `skip()` 方法，尽量避免在大型数据集上连续使用。\n- 当结合 `skip()` 和 `limit()` 时，`skip()` 应该在 `limit()` 之前使用，以避免意外行为。\n\n通过使用 `limit()` 和 `skip()` 方法，您可以实现在 MongoDB 中对查询结果进行分页处理，提高查询的灵活性和性能。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-limit-skip.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-limit-skip','MongoDB Limit 与 Skip 方法 - MongoDB 教程','如果你需要在 MongoDB 中读取指定数量的数据记录，可以使用 MongoDB 的 limit 方法，如果想跳过指定数量的文档读取数据可以使用 skip 方法。 limit 方法用于限制查询结果返回的文档数量，而 skip 方法用于跳过指...',0,'PUBLISHED',5240,220,145,28,'2025-07-20 00:00:00','2025-07-20 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631020,1,'MongoDB 排序','在 MongoDB 中使用 sort 方法对数据进行排序，sort 方法可以通过参数指定排序的字段，并使用 1 和 -1 来指定排序的方式，其中 1 为升序排列，而 -1 是用于降序排列。 sort方法基本语法如下所示： // 按 age 字段升序排序 // 按 createdAt 字段降序排序','# MongoDB 排序\n\n在 MongoDB 中使用 sort() 方法对数据进行排序，sort() 方法可以通过参数指定排序的字段，并使用 1 和 -1 来指定排序的方式，其中 1 为升序排列，而 -1 是用于降序排列。\n\n### 语法\n\nsort()方法基本语法如下所示：\n\n```text\n\ndb.collection.find().sort({ field1: 1, field2: -1 })\n```\n\n- `{ field1: 1, field2: -1 }`：指定要排序的字段及排序顺序。1 表示升序，-1 表示降序。\n\n### 实例\n\n按字段升序排序：\n\n## 实例\n\n// 按 age 字段升序排序\n\n按字段降序排序：\n\n## 实例\n\n// 按 createdAt 字段降序排序\n\ndb.myCollection.find().sort({ createdAt: -1 });\n\n可以指定多个字段进行排序，MongoDB 将按照指定的字段顺序依次排序。\n\n## 实例\n\n// 先按 age 字段升序排序，再按 createdAt 字段降序排序\n\ndb.myCollection.find().sort({ age: 1, createdAt: -1 });\n\ncol 集合中的数据如下：\n\n```text\n\n{ "_id" : ObjectId("56066542ade2f21f36b0313a"), "title" : "PHP 教程", "description" : "PHP 是一种创建动态交互性站点的强有力的服务器端脚本语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "php" ], "likes" : 200 }\n{ "_id" : ObjectId("56066549ade2f21f36b0313b"), "title" : "Java 教程", "description" : "Java 是由Sun Microsystems公司于1995年5月推出的高级程序设计语言。", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "java" ], "likes" : 150 }\n{ "_id" : ObjectId("5606654fade2f21f36b0313c"), "title" : "MongoDB 教程", "description" : "MongoDB 是一个 Nosql 数据库", "by" : "菜鸟教程", "url" : "http://www.runoob.com", "tags" : [ "mongodb" ], "likes" : 100 }\n```\n\n以下实例演示了 col 集合中的数据按字段 likes 的降序排列：\n\n```text\n\n>db.col.find({},{"title":1,_id:0}).sort({"likes":-1})\n{ "title" : "PHP 教程" }\n{ "title" : "Java 教程" }\n{ "title" : "MongoDB 教程" }\n>\n```\n\n### 注意事项\n\n- MongoDB 在执行排序时会对查询结果进行排序，因此可能会影响性能，特别是在大型数据集上排序操作可能会较慢。\n- 如果排序字段上有索引，排序操作可能会更高效。在执行频繁的排序操作时，可以考虑创建适当的索引以提高性能。\n\n通过使用 sort() 方法，您可以方便地对 MongoDB 查询结果进行排序，以满足不同排序需求，并根据需要按升序或降序排列文档。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-sort.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-sort','MongoDB 排序 - MongoDB 教程','在 MongoDB 中使用 sort 方法对数据进行排序，sort 方法可以通过参数指定排序的字段，并使用 1 和 -1 来指定排序的方式，其中 1 为升序排列，而 -1 是用于降序排列。 sort方法基本语法如下所示： // 按 age ...',0,'PUBLISHED',5377,227,150,29,'2025-07-21 00:00:00','2025-07-21 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631021,1,'MongoDB 索引','索引通常能够极大的提高查询的效率，如果没有索引，MongoDB在读取数据时必须扫描集合中的每个文件并选取那些符合查询条件的记录。 这种扫描全集合的查询效率是非常低的，特别在处理大量的数据时，查询可能要花费几十秒甚至几分钟，这对网站的性能是非常致命的。 索引是特殊的数据结构，索引存储在一个易于遍历读取的数据集合中，索引是对数据库表中一列或多列的值进行排序的一种结构 在 MongoDB 中，常见的索引类型包括：','# MongoDB 索引\n\n索引通常能够极大的提高查询的效率，如果没有索引，MongoDB在读取数据时必须扫描集合中的每个文件并选取那些符合查询条件的记录。\n\n这种扫描全集合的查询效率是非常低的，特别在处理大量的数据时，查询可能要花费几十秒甚至几分钟，这对网站的性能是非常致命的。\n\n索引是特殊的数据结构，索引存储在一个易于遍历读取的数据集合中，索引是对数据库表中一列或多列的值进行排序的一种结构\n\n在 MongoDB 中，常见的索引类型包括：\n\n- 单字段索引：基于单个字段的索引。\n- 复合索引：基于多个字段组合的索引。\n- 文本索引：用于支持全文搜索。\n- 地理空间索引：用于地理空间数据的查询。\n- 哈希索引：用于对字段值进行哈希处理的索引。\n\n## 创建索引\n\nMongoDB 使用 createIndex() 方法来创建索引。\n\n> 注意在 3.0.0 版本前创建索引方法为 db.collection.ensureIndex()，之后的版本使用了 db.collection.createIndex() 方法，ensureIndex() 还能用，但只是 createIndex() 的别名。\n\n### 语法\n\ncreateIndex() 方法基本语法格式如下所示：\n\n```text\n\ndb.collection.createIndex( keys, options )\n```\n\n- `db`：数据库的引用。\n- `collection`：集合的名称。\n- `keys`：一个对象，指定了字段名和索引的排序方向（1 表示升序，-1 表示降序）。\n- `options`：一个可选参数，可以包含索引的额外选项。\n\noptions 参数是一个对象，可以包含多种配置选项，以下是一些常用的选项：\n\n- `unique`：如果设置为 `true`，则创建唯一索引，确保索引字段的值在集合中是唯一的。\n- `background`：如果设置为 `true`，则索引创建过程在后台运行，不影响其他数据库操作。\n- `name`：指定索引的名称，如果不指定，MongoDB 会根据索引的字段自动生成一个名称。\n- `sparse`：如果设置为 `true`，创建稀疏索引，只索引那些包含索引字段的文档。\n- `expireAfterSeconds`：设置索引字段的过期时间，MongoDB 将自动删除过期的文档。\n- `v`：索引版本，通常不需要手动设置。\n- `weights`：为文本索引指定权重。\n\n## 实例\n\n// 创建 age 字段的升序索引\n\n### 实例\n\n索引创建：\n\n## 实例\n\n// 创建唯一索引\n\ndb.collection.createIndex( { field: 1 }, { unique: true } )\n\n// 创建后台运行的索引\n\ndb.collection.createIndex( { field: 1 }, { background: true } )\n\n// 创建稀疏索引\n\ndb.collection.createIndex( { field: 1 }, { sparse: true } )\n\n// 创建文本索引并指定权重\n\ndb.collection.createIndex( { field: "text" }, { weights: { field: 10 } } )\n\n创建地理空间索引\n\n对于存储地理位置数据的字段，可以使用 2dsphere 或 2d 索引类型来创建地理空间索引。\n\n// 2dsphere 索引，适用于球形地理数据\n\ndb.collection.createIndex( { location: "2dsphere" } )\n\n// 2d 索引，适用于平面地理数据\n\ndb.collection.createIndex( { location: "2d" } )\n\n### 创建哈希索引\n\n从 MongoDB 3.2 版本开始，可以使用哈希索引对字段进行哈希，以支持大范围的数值查找。\n\n```text\n\ndb.collection.createIndex( { field: "hashed" } )\n```\n\n### 查看索引\n\n使用 getIndexes() 方法可以查看集合中的所有索引：\n\n```text\n\ndb.collection.getIndexes()\n```\n\n### 删除索引\n\n使用 dropIndex() 或 dropIndexes() 方法可以删除索引：\n\n## 实例\n\n// 删除指定的索引\n\ndb.collection.dropIndex( "indexName" )\n\n// 删除所有索引\n\ndb.collection.dropIndexes()\n\n### 索引策略\n\n在创建索引时，需要考虑以下因素：\n\n- 查询频率：优先考虑那些经常用于查询的字段。\n- 字段基数：字段值的基数越高（即唯一值越多），索引的效果越好。\n- 索引大小：索引的大小会影响数据库的内存占用和查询性能。\n\n### 索引优化\n\n在对索引进行优化时，可以考虑以下方法：\n\n- 选择合适的索引类型：根据查询需求选择合适的索引类型。\n- 创建复合索引：对于经常一起使用的字段，考虑创建复合索引以提高查询效率。\n- 监控索引性能：定期监控索引的使用情况，根据实际需求调整索引。\n\n### 注意事项\n\n- 索引虽然可以提高查询性能，但也会增加写操作的开销。因此，在创建索引时需要权衡查询性能和写入性能。\n- 索引会占用额外的存储空间，特别是对于大型数据集，需要考虑索引的存储成本。\n\n通过合理地设计和使用索引，可以大大提高 MongoDB 数据库的查询性能和响应速度，从而更好地支持应用程序的需求。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-indexing.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-indexing','MongoDB 索引 - MongoDB 教程','索引通常能够极大的提高查询的效率，如果没有索引，MongoDB在读取数据时必须扫描集合中的每个文件并选取那些符合查询条件的记录。 这种扫描全集合的查询效率是非常低的，特别在处理大量的数据时，查询可能要花费几十秒甚至几分钟，这对网站的性能是非...',0,'PUBLISHED',5514,234,155,30,'2025-07-22 00:00:00','2025-07-22 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631022,1,'MongoDB 聚合','MongoDB 中聚合aggregate主要用于处理数据诸如统计平均值，求和等，并返回计算后的数据结果。 有点类似 SQL 语句中的 count。 MongoDB中聚合的方法使用aggregate。 aggregate 方法的基本语法格式如下所示：','# MongoDB 聚合\n\nMongoDB 中聚合(aggregate)主要用于处理数据(诸如统计平均值，求和等)，并返回计算后的数据结果。\n\n有点类似 SQL 语句中的 count(*)。\n\n## aggregate() 方法\n\nMongoDB中聚合的方法使用aggregate()。\n\n### 语法\n\naggregate() 方法的基本语法格式如下所示：\n\n```text\n\n>db.COLLECTION_NAME.aggregate(AGGREGATE_OPERATION)\n```\n\n### 实例\n\n集合中的数据如下：\n\n```text\n\n{\n   _id: ObjectId(7df78ad8902c)\n   title: \'MongoDB Overview\', \n   description: \'MongoDB is no sql database\',\n   by_user: \'runoob.com\',\n   url: \'http://www.runoob.com\',\n   tags: [\'mongodb\', \'database\', \'NoSQL\'],\n   likes: 100\n},\n{\n   _id: ObjectId(7df78ad8902d)\n   title: \'NoSQL Overview\', \n   description: \'No sql database is very fast\',\n   by_user: \'runoob.com\',\n   url: \'http://www.runoob.com\',\n   tags: [\'mongodb\', \'database\', \'NoSQL\'],\n   likes: 10\n},\n{\n   _id: ObjectId(7df78ad8902e)\n   title: \'Neo4j Overview\', \n   description: \'Neo4j is no sql database\',\n   by_user: \'Neo4j\',\n   url: \'http://www.neo4j.com\',\n   tags: [\'neo4j\', \'database\', \'NoSQL\'],\n   likes: 750\n},\n```\n\n现在我们通过以上集合计算每个作者所写的文章数，使用aggregate()计算结果如下：\n\n```text\n\n> db.mycol.aggregate([{$group : {_id : "$by_user", num_tutorial : {$sum : 1}}}])\n{\n   "result" : [\n      {\n         "_id" : "runoob.com",\n         "num_tutorial" : 2\n      },\n      {\n         "_id" : "Neo4j",\n         "num_tutorial" : 1\n      }\n   ],\n   "ok" : 1\n}\n>\n```\n\n以上实例类似sql语句：\n\n```text\n select by_user, count(*) from mycol group by by_user\n```\n\n在上面的例子中，我们通过字段 by_user 字段对数据进行分组，并计算 by_user 字段相同值的总和。\n\n下表展示了一些聚合的表达式:\n\n| 表达式 | 描述 | 实例 |\n| --- | --- | --- |\n| $sum | 计算总和。 | db.mycol.aggregate([{$group : {_id : "$by_user", num_tutorial : {$sum : "$likes"}}}]) |\n| $avg | 计算平均值 | db.mycol.aggregate([{$group : {_id : "$by_user", num_tutorial : {$avg : "$likes"}}}]) |\n| $min | 获取集合中所有文档对应值得最小值。 | db.mycol.aggregate([{$group : {_id : "$by_user", num_tutorial : {$min : "$likes"}}}]) |\n| $max | 获取集合中所有文档对应值得最大值。 | db.mycol.aggregate([{$group : {_id : "$by_user", num_tutorial : {$max : "$likes"}}}]) |\n| $push | 将值加入一个数组中，不会判断是否有重复的值。 | db.mycol.aggregate([{$group : {_id : "$by_user", url : {$push: "$url"}}}]) |\n| $addToSet | 将值加入一个数组中，会判断是否有重复的值，若相同的值在数组中已经存在了，则不加入。 | db.mycol.aggregate([{$group : {_id : "$by_user", url : {$addToSet : "$url"}}}]) |\n| $first | 根据资源文档的排序获取第一个文档数据。 | db.mycol.aggregate([{$group : {_id : "$by_user", first_url : {$first : "$url"}}}]) |\n| $last | 根据资源文档的排序获取最后一个文档数据 | db.mycol.aggregate([{$group : {_id : "$by_user", last_url : {$last : "$url"}}}]) |\n\n## 管道的概念\n\n管道在Unix和Linux中一般用于将当前命令的输出结果作为下一个命令的参数。\n\nMongoDB的聚合管道将MongoDB文档在一个管道处理完毕后将结果传递给下一个管道处理。管道操作是可以重复的。\n\n表达式：处理输入文档并输出。表达式是无状态的，只能用于计算当前聚合管道的文档，不能处理其它的文档。\n\n这里我们介绍一下聚合框架中常用的几个操作：\n\n- $project：修改输入文档的结构。可以用来重命名、增加或删除域，也可以用于创建计算结果以及嵌套文档。\n- $match：用于过滤数据，只输出符合条件的文档。$match使用MongoDB的标准查询操作。\n- $limit：用来限制MongoDB聚合管道返回的文档数。\n- $skip：在聚合管道中跳过指定数量的文档，并返回余下的文档。\n- $unwind：将文档中的某一个数组类型字段拆分成多条，每条包含数组中的一个值。\n- $group：将集合中的文档分组，可用于统计结果。\n- $sort：将输入文档排序后输出。\n- $geoNear：输出接近某一地理位置的有序文档。\n\n### 管道操作符实例\n\n1、$project实例\n```text\n\ndb.article.aggregate(\n    { $project : {\n        title : 1 ,\n        author : 1 ,\n    }}\n );\n```\n\n这样的话结果中就只还有_id,tilte和author三个字段了，默认情况下_id字段是被包含的，如果要想不包含_id话可以这样:\n\n```text\n\ndb.article.aggregate(\n    { $project : {\n        _id : 0 ,\n        title : 1 ,\n        author : 1\n    }});\n```\n\n2.$match实例\n\n```text\n\ndb.articles.aggregate( [\n                        { $match : { score : { $gt : 70, $lte : 90 } } },\n                        { $group: { _id: null, count: { $sum: 1 } } }\n                       ] );\n```\n\n$match用于获取分数大于70小于或等于90记录，然后将符合条件的记录送到下一阶段$group管道操作符进行处理。\n\n3.$skip实例\n\n```text\n\ndb.article.aggregate(\n    { $skip : 5 });\n\n```\n\n经过$skip管道操作符处理后，前五个文档被"过滤"掉。\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-aggregate.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-aggregate','MongoDB 聚合 - MongoDB 教程','MongoDB 中聚合aggregate主要用于处理数据诸如统计平均值，求和等，并返回计算后的数据结果。 有点类似 SQL 语句中的 count。 MongoDB中聚合的方法使用aggregate。 aggregate 方法的基本语法格式如...',0,'PUBLISHED',5651,241,160,31,'2025-07-23 00:00:00','2025-07-23 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631023,1,'MongoDB 复制(副本集)','MongoDB复制是将数据同步在多个服务器的过程。 复制提供了数据的冗余备份，并在多个服务器上存储数据副本，提高了数据的可用性， 并可以保证数据的安全性。 复制还允许您从硬件故障和服务中断中恢复数据。','# MongoDB 复制（副本集）\n\nMongoDB复制是将数据同步在多个服务器的过程。\n\n复制提供了数据的冗余备份，并在多个服务器上存储数据副本，提高了数据的可用性，\n并可以保证数据的安全性。\n\n复制还允许您从硬件故障和服务中断中恢复数据。\n\n## 什么是复制?\n\n- 保障数据的安全性\n- 数据高可用性 (24*7)\n- 灾难恢复\n- 无需停机维护（如备份，重建索引，压缩）\n- 分布式读取数据\n\n## MongoDB复制原理\n\nmongodb的复制至少需要两个节点。其中一个是主节点，负责处理客户端请求，其余的都是从节点，负责复制主节点上的数据。\n\nmongodb各个节点常见的搭配方式为：一主一从、一主多从。\n\n主节点记录在其上的所有操作oplog，从节点定期轮询主节点获取这些操作，然后对自己的数据副本执行这些操作，从而保证从节点的数据与主节点一致。\n\nMongoDB复制结构图如下所示：\n\n![MongoDB复制结构图](/api/uploads/files/runoob/mongodb/replication-92dc3da56f.png)\n\n以上结构图中，客户端从主节点读取数据，在客户端写入数据到主节点时，\n主节点与从节点进行数据交互保障数据的一致性。\n\n### 副本集特征：\n\n- N 个节点的集群\n- 任何节点可作为主节点\n- 所有写入操作都在主节点上\n- 自动故障转移\n- 自动恢复\n\n## MongoDB副本集设置\n\n在本教程中我们使用同一个MongoDB来做MongoDB主从的实验，\n操作步骤如下：\n\n1、关闭正在运行的MongoDB服务器。\n\n现在我们通过指定 --replSet 选项来启动mongoDB。--replSet 基本语法格式如下：\n\n```text\n\nmongod --port "PORT" --dbpath "YOUR_DB_DATA_PATH" --replSet "REPLICA_SET_INSTANCE_NAME"\n```\n\n### 实例\n\n```text\n\nmongod --port 27017 --dbpath "D:\\set up\\mongodb\\data" --replSet rs0\n```\n\n以上实例会启动一个名为rs0的MongoDB实例，其端口号为27017。\n\n启动后打开命令提示框并连接上mongoDB服务。\n\n在Mongo客户端使用命令rs.initiate()来启动一个新的副本集。\n\n我们可以使用rs.conf()来查看副本集的配置\n\n查看副本集状态使用 rs.status() 命令\n\n## 副本集添加成员\n\n添加副本集的成员，我们需要使用多台服务器来启动mongo服务。进入Mongo客户端，并使用rs.add()方法来添加副本集的成员。\n\n### 语法\n\n rs.add() 命令基本语法格式如下：\n\n```text\n\n>rs.add(HOST_NAME:PORT)\n```\n\n### 实例\n\n假设你已经启动了一个名为mongod1.net，端口号为27017的Mongo服务。\n在客户端命令窗口使用rs.add() 命令将其添加到副本集中，命令如下所示：\n\n```text\n\n>rs.add("mongod1.net:27017")\n>\n```\n\nMongoDB中你只能通过主节点将Mongo服务添加到副本集中，\n判断当前运行的Mongo服务是否为主节点可以使用命令db.isMaster() 。\n\nMongoDB的副本集与我们常见的主从有所不同，主从在主机宕机后所有服务将停止，而副本集在主机宕机后，副本会接管主节点成为主节点，不会出现宕机的情况。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-replication.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-replication','MongoDB 复制(副本集) - MongoDB 教程','MongoDB复制是将数据同步在多个服务器的过程。 复制提供了数据的冗余备份，并在多个服务器上存储数据副本，提高了数据的可用性， 并可以保证数据的安全性。 复制还允许您从硬件故障和服务中断中恢复数据。',0,'PUBLISHED',5788,248,165,32,'2025-07-24 00:00:00','2025-07-24 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631024,1,'MongoDB 分片','在Mongodb里面存在另一种集群，就是分片技术,可以满足MongoDB数据量大量增长的需求。 当MongoDB存储海量的数据时，一台机器可能不足以存储数据，也可能不足以提供可接受的读写吞吐量。这时，我们就可以通过在多台机器上分割数据，使得数据库系统能存储和处理更多的数据。 下图展示了在MongoDB中使用分片集群结构分布： 上图中主要有如下所述三个主要组件：','# MongoDB 分片\n\n## 分片\n\n在Mongodb里面存在另一种集群，就是分片技术,可以满足MongoDB数据量大量增长的需求。\n\n当MongoDB存储海量的数据时，一台机器可能不足以存储数据，也可能不足以提供可接受的读写吞吐量。这时，我们就可以通过在多台机器上分割数据，使得数据库系统能存储和处理更多的数据。\n\n## 为什么使用分片\n\n- 复制所有的写入操作到主节点\n- 延迟的敏感数据会在主节点查询\n- 单个副本集限制在12个节点\n- 当请求量巨大时会出现内存不足。\n- 本地磁盘不足\n- 垂直扩展价格昂贵\n\n## MongoDB分片\n\n下图展示了在MongoDB中使用分片集群结构分布：\n\n![图片](/api/uploads/files/runoob/mongodb/sharding-842188f755.png)\n\n上图中主要有如下所述三个主要组件：\n\n- Shard:\n  用于存储实际的数据块，实际生产环境中一个shard server角色可由几台机器组个一个replica set承担，防止主机单点故障\n- Config Server:\n  mongod实例，存储了整个 ClusterMetadata，其中包括 chunk信息。\n- Query Routers:\n  前端路由，客户端由此接入，且让整个集群看上去像单一数据库，前端应用可以透明使用。\n\n## 分片实例\n\n分片结构端口分布如下：\n\n```text\n\nShard Server 1：27020\nShard Server 2：27021\nShard Server 3：27022\nShard Server 4：27023\nConfig Server ：27100\nRoute Process：40000\n```\n\n步骤一：启动Shard Server\n\n```text\n\n[root@100 /]# mkdir -p /www/mongoDB/shard/s0\n[root@100 /]# mkdir -p /www/mongoDB/shard/s1\n[root@100 /]# mkdir -p /www/mongoDB/shard/s2\n[root@100 /]# mkdir -p /www/mongoDB/shard/s3\n[root@100 /]# mkdir -p /www/mongoDB/shard/log\n[root@100 /]# /usr/local/mongoDB/bin/mongod --port 27020 --dbpath=/www/mongoDB/shard/s0 --logpath=/www/mongoDB/shard/log/s0.log --logappend --fork\n....\n[root@100 /]# /usr/local/mongoDB/bin/mongod --port 27023 --dbpath=/www/mongoDB/shard/s3 --logpath=/www/mongoDB/shard/log/s3.log --logappend --fork\n```\n\n步骤二：\n启动Config Server\n\n```text\n\n[root@100 /]# mkdir -p /www/mongoDB/shard/config\n[root@100 /]# /usr/local/mongoDB/bin/mongod --port 27100 --dbpath=/www/mongoDB/shard/config --logpath=/www/mongoDB/shard/log/config.log --logappend --fork\n```\n\n注意：这里我们完全可以像启动普通mongodb服务一样启动，不需要添加—shardsvr和configsvr参数。因为这两个参数的作用就是改变启动端口的，所以我们自行指定了端口就可以。\n\n步骤三：\n启动Route Process\n\n```text\n\n/usr/local/mongoDB/bin/mongos --port 40000 --configdb localhost:27100 --fork --logpath=/www/mongoDB/shard/log/route.log --chunkSize 500\n```\n\nmongos启动参数中，chunkSize这一项是用来指定chunk的大小的，单位是MB，默认大小为200MB.\n\n步骤四：\n配置Sharding\n\n接下来，我们使用MongoDB Shell登录到mongos，添加Shard节点\n\n```text\n\n[root@100 shard]# /usr/local/mongoDB/bin/mongo admin --port 40000\nMongoDB shell version: 2.0.7\nconnecting to: 127.0.0.1:40000/admin\nmongos> db.runCommand({ addshard:"localhost:27020" })\n{ "shardAdded" : "shard0000", "ok" : 1 }\n......\nmongos> db.runCommand({ addshard:"localhost:27029" })\n{ "shardAdded" : "shard0009", "ok" : 1 }\nmongos> db.runCommand({ enablesharding:"test" }) #设置分片存储的数据库\n{ "ok" : 1 }\nmongos> db.runCommand({ shardcollection: "test.log", key: { id:1,time:1}})\n{ "collectionsharded" : "test.log", "ok" : 1 }\n```\n\n步骤五：\n程序代码内无需太大更改，直接按照连接普通的mongo数据库那样，将数据库连接接入接口40000\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-sharding.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-sharding','MongoDB 分片 - MongoDB 教程','在Mongodb里面存在另一种集群，就是分片技术,可以满足MongoDB数据量大量增长的需求。 当MongoDB存储海量的数据时，一台机器可能不足以存储数据，也可能不足以提供可接受的读写吞吐量。这时，我们就可以通过在多台机器上分割数据，使得...',0,'PUBLISHED',5925,255,170,33,'2025-07-25 00:00:00','2025-07-25 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631025,1,'MongoDB 备份与恢复','在Mongodb中我们使用mongodump命令来备份MongoDB数据。该命令可以导出所有数据到指定目录中。 mongodump命令可以通过参数指定导出的数据量级转存的服务器。 mongodump命令脚本语法如下： MongoDB 所在服务器地址，例如：127.0.0.1，当然也可以指定端口号：127.0.0.1:27017','# MongoDB 备份(mongodump)与恢复(mongorestore)\n\n## MongoDB数据备份\n\n在Mongodb中我们使用mongodump命令来备份MongoDB数据。该命令可以导出所有数据到指定目录中。\n\nmongodump命令可以通过参数指定导出的数据量级转存的服务器。\n\n### 语法\n\nmongodump命令脚本语法如下：\n\n```text\n\n>mongodump -h dbhost -d dbname -o dbdirectory\n```\n\n- -h：\n  MongoDB 所在服务器地址，例如：127.0.0.1，当然也可以指定端口号：127.0.0.1:27017\n- -d：\n  需要备份的数据库实例，例如：test\n- -o：\n  备份的数据存放位置，例如：c:\\data\\dump，当然该目录需要提前建立，在备份完成后，系统自动在dump目录下建立一个test目录，这个目录里面存放该数据库实例的备份数据。\n\n### 实例\n\n在本地使用 27017 启动你的mongod服务。打开命令提示符窗口，进入MongoDB安装目录的bin目录输入命令mongodump:\n\n```text\n\n>mongodump\n```\n\n执行以上命令后，客户端会连接到ip为 127.0.0.1 端口号为 27017 的MongoDB服务上，并备份所有数据到 bin/dump/ 目录中。命令输出结果如下：\n\n![MongoDB数据备份](/api/uploads/files/runoob/mongodb/mongodump-0710761106.png)\n\nmongodump 命令可选参数列表如下所示：\n\n| 语法 | 描述 | 实例 |\n| --- | --- | --- |\n| mongodump --host HOST_NAME --port PORT_NUMBER | 该命令将备份所有MongoDB数据 | mongodump --host runoob.com --port 27017 |\n| mongodump --dbpath DB_PATH --out BACKUP_DIRECTORY |  | mongodump --dbpath /data/db/ --out /data/backup/ |\n| mongodump --collection COLLECTION --db DB_NAME | 该命令将备份指定数据库的集合。 | mongodump --collection mycol --db test |\n\n## MongoDB数据恢复\n\nmongodb使用 mongorestore 命令来恢复备份的数据。\n\n### 语法\n\nmongorestore命令脚本语法如下：\n\n```text\n\n>mongorestore -h <hostname><:port> -d dbname <path>\n```\n\n- --host <:port>, -h <:port>：\n  MongoDB所在服务器地址，默认为： localhost:27017\n- --db , -d ：\n  需要恢复的数据库实例，例如：test，当然这个名称也可以和备份时候的不一样，比如test2\n- --drop：\n  恢复的时候，先删除当前数据，然后恢复备份的数据。就是说，恢复后，备份后添加修改的数据都会被删除，慎用哦！\n- <path>：\n  mongorestore 最后的一个参数，设置备份数据所在位置，例如：c:\\data\\dump\\test。\n  你不能同时指定 <path> 和 --dir 选项，--dir也可以设置备份目录。\n- --dir：\n  指定备份的目录\n  你不能同时指定 <path> 和 --dir 选项。\n\n接下来我们执行以下命令:\n\n```text\n\n>mongorestore\n```\n\n执行以上命令输出结果如下：\n\n![MongoDB数据恢复](/api/uploads/files/runoob/mongodb/mongorestore-21b5e3da78.png)\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-mongodump-mongorestore.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-mongodump-mongorestore','MongoDB 备份与恢复 - MongoDB 教程','在Mongodb中我们使用mongodump命令来备份MongoDB数据。该命令可以导出所有数据到指定目录中。 mongodump命令可以通过参数指定导出的数据量级转存的服务器。 mongodump命令脚本语法如下： MongoDB 所在服...',0,'PUBLISHED',6062,262,175,34,'2025-07-26 00:00:00','2025-07-26 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631026,1,'MongoDB 监控','在你已经安装部署并允许MongoDB服务后，你必须要了解MongoDB的运行情况，并查看MongoDB的性能。这样在大流量得情况下可以很好的应对并保证MongoDB正常运作。 MongoDB中提供了mongostat 和 mongotop 两个命令来监控MongoDB的运行情况。 mongostat是mongodb自带的状态检测工具，在命令行下使用。它会间隔固定时间获取mongodb的当前运行状态，并输出。如果你发现数据库突然变慢或者有其他问题的话，你第一手的操作就考虑采用mongostat来查看mongo的状态。 启动你的Mongod服务，进入到你安装的MongoDB目录下的bin目录，','# MongoDB 监控\n\n在你已经安装部署并允许MongoDB服务后，你必须要了解MongoDB的运行情况，并查看MongoDB的性能。这样在大流量得情况下可以很好的应对并保证MongoDB正常运作。\n\nMongoDB中提供了mongostat 和 mongotop 两个命令来监控MongoDB的运行情况。\n\n## mongostat 命令\n\nmongostat是mongodb自带的状态检测工具，在命令行下使用。它会间隔固定时间获取mongodb的当前运行状态，并输出。如果你发现数据库突然变慢或者有其他问题的话，你第一手的操作就考虑采用mongostat来查看mongo的状态。\n\n启动你的Mongod服务，进入到你安装的MongoDB目录下的bin目录，\n然后输入mongostat命令，如下所示：\n\n```text\n\nD:\\set up\\mongodb\\bin>mongostat\n```\n\n以上命令输出结果如下：\n\n![图片](/api/uploads/files/runoob/mongodb/mongostat-2aafc57814.png)\n\n## mongotop 命令\n\nmongotop也是mongodb下的一个内置工具，mongotop提供了一个方法，用来跟踪一个MongoDB的实例，查看哪些大量的时间花费在读取和写入数据。 mongotop提供每个集合的水平的统计数据。默认情况下，mongotop返回值的每一秒。\n\n启动你的Mongod服务，进入到你安装的MongoDB目录下的bin目录，\n然后输入mongotop命令，如下所示：\n\n```text\n\nD:\\set up\\mongodb\\bin>mongotop\n```\n\n以上命令执行输出结果如下：\n\n![图片](/api/uploads/files/runoob/mongodb/mongotop-7b3052ad16.png)\n\n带参数实例\n\n```text\n\n E:\\mongodb-win32-x86_64-2.2.1\\bin>mongotop 10\n```\n\n![图片](/api/uploads/files/runoob/mongodb/29122412-e32a9f09e46e496a8833433fdb421311-d661d74374.gif)\n\n后面的10是<sleeptime>参数 ，可以不使用，等待的时间长度，以秒为单位，mongotop等待调用之间。通过的默认mongotop返回数据的每一秒。\n\n```text\n\n E:\\mongodb-win32-x86_64-2.2.1\\bin>mongotop --locks\n```\n\n报告每个数据库的锁的使用中，使用mongotop - 锁，这将产生以下输出：\n\n![图片](/api/uploads/files/runoob/mongodb/29122706-bfdd58e62c404b948f8039c489f8be81-7469fec2c2.gif)\n\n输出结果字段说明：\n\n- ns：\n  包含数据库命名空间，后者结合了数据库名称和集合。\n- db：\n  包含数据库的名称。名为 . 的数据库针对全局锁定，而非特定数据库。\n- total：\n  mongod花费的时间工作在这个命名空间提供总额。\n- read：\n  提供了大量的时间，这mongod花费在执行读操作，在此命名空间。\n- write：\n  提供这个命名空间进行写操作，这mongod花了大量的时间。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-mongostat-mongotop.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-mongostat-mongotop','MongoDB 监控 - MongoDB 教程','在你已经安装部署并允许MongoDB服务后，你必须要了解MongoDB的运行情况，并查看MongoDB的性能。这样在大流量得情况下可以很好的应对并保证MongoDB正常运作。 MongoDB中提供了mongostat 和 mongotop ...',0,'PUBLISHED',6199,269,180,35,'2025-07-27 00:00:00','2025-07-27 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631027,1,'MongoDB Java','在 Java 程序中如果要使用 MongoDB，你需要确保已经安装了 Java 环境及 MongoDB JDBC 驱动。 本章节实例适合 Mongo 3.x 以上版本。 你可以参考本站的Java教程https://www.runoob.com/java/java-tutorial.html来安装Java程序。现在让我们来检测你是否安装了 MongoDB  JDBC  驱动。 连接数据库，你需要指定数据库名称，如果指定的数据库不存在，mongo会自动创建数据库。','# MongoDB Java\n\n## 环境配置\n\n在 Java 程序中如果要使用 MongoDB，你需要确保已经安装了 Java 环境及 MongoDB JDBC 驱动。\n\n本章节实例适合 Mongo 3.x 以上版本。\n\n你可以参考本站的[Java教程](https://www.runoob.com/java/java-tutorial.html)来安装Java程序。现在让我们来检测你是否安装了 MongoDB  JDBC  驱动。\n\n- 首先你必须下载mongo jar包，下载地址：[https://mongodb.github.io/mongo-java-driver/](https://mongodb.github.io/mongo-java-driver/),\n  请确保下载最新版本。\n  ![图片](/api/uploads/files/runoob/mongodb/downlaod-mongo-java-f8988092ae.jpg)\n- 你需要将 mongo-java-driver-3.2.2.jar （找到合适的版本）包含在你的 classpath 中。。\n- 国内 mongodb-driver jar 下载地址：[http://central.maven.org/maven2/org/mongodb/mongo-java-driver/](http://central.maven.org/maven2/org/mongodb/mongo-java-driver/)\n\n## 连接数据库\n\n连接数据库，你需要指定数据库名称，如果指定的数据库不存在，mongo会自动创建数据库。\n\n连接数据库的Java代码如下：\n\n```text\n\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.MongoDatabase;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n       // 连接到 mongodb 服务\n         MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n       \n         // 连接到数据库\n         MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n       System.out.println("Connect to database successfully");\n        \n      }catch(Exception e){\n        System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n     }\n   }\n}\n```\n\n现在，让我们来编译运行程序并连接到数据库 mycol。\n\n你可以根据你的实际环境改变 MongoDB JDBC 驱动的路径。\n\n本实例将 MongoDB JDBC 启动包 mongo-java-driver-3.2.2.jar 放在本地目录下:\n\n```text\n\n$ javac -cp .:mongo-java-driver-3.2.2.jar MongoDBJDBC.java\n$ java -cp .:mongo-java-driver-3.2.2.jar MongoDBJDBC\nConnect to database successfully\nAuthentication: true\n```\n\n本实例中 Mongo 数据库无需用户名密码验证。如果你的 Mongo 需要验证用户名及密码，可以使用以下代码：\n\n```text\n\nimport java.util.ArrayList;  \nimport java.util.List;  \nimport com.mongodb.MongoClient;  \nimport com.mongodb.MongoCredential;  \nimport com.mongodb.ServerAddress;  \nimport com.mongodb.client.MongoDatabase;  \n  \npublic class MongoDBJDBC {  \n    public static void main(String[] args){  \n        try {  \n            //连接到MongoDB服务 如果是远程连接可以替换“localhost”为服务器所在IP地址  \n            //ServerAddress()两个参数分别为 服务器地址 和 端口  \n            ServerAddress serverAddress = new ServerAddress("localhost",27017);  \n            List<ServerAddress> addrs = new ArrayList<ServerAddress>();  \n            addrs.add(serverAddress);  \n              \n            //MongoCredential.createScramSha1Credential()三个参数分别为 用户名 数据库名称 密码  \n            MongoCredential credential = MongoCredential.createScramSha1Credential("username", "databaseName", "password".toCharArray());  \n            List<MongoCredential> credentials = new ArrayList<MongoCredential>();  \n            credentials.add(credential);  \n              \n            //通过连接认证获取MongoDB连接  \n            MongoClient mongoClient = new MongoClient(addrs,credentials);  \n              \n            //连接到数据库  \n            MongoDatabase mongoDatabase = mongoClient.getDatabase("databaseName");  \n            System.out.println("Connect to database successfully");  \n        } catch (Exception e) {  \n            System.err.println( e.getClass().getName() + ": " + e.getMessage() );  \n        }  \n    }  \n} \n```\n\n## 创建集合\n\n我们可以使用 com.mongodb.client.MongoDatabase 类中的createCollection()来创建集合\n\n代码片段如下：\n\n```text\n\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.MongoDatabase;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n      // 连接到 mongodb 服务\n      MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n         \n       \n      // 连接到数据库\n      MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n      System.out.println("Connect to database successfully");\n      mongoDatabase.createCollection("test");\n      System.out.println("集合创建成功");\n        \n      }catch(Exception e){\n        System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n     }\n   }\n}\n```\n\n编译运行以上程序，输出结果如下:\n\n```text\n\nConnect to database successfully\n集合创建成功\n```\n\n## 获取集合\n\n我们可以使用com.mongodb.client.MongoDatabase类的 getCollection() 方法来获取一个集合\n\n代码片段如下：\n\n```text\n\nimport org.bson.Document;\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.MongoCollection;\nimport com.mongodb.client.MongoDatabase;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n       // 连接到 mongodb 服务\n         MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n       \n         // 连接到数据库\n         MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n       System.out.println("Connect to database successfully");\n      \n       MongoCollection<Document> collection = mongoDatabase.getCollection("test");\n       System.out.println("集合 test 选择成功");\n      }catch(Exception e){\n        System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n     }\n   }\n}\n```\n\n编译运行以上程序，输出结果如下:\n\n```text\n\nConnect to database successfully\n集合 test 选择成功\n```\n\n## 插入文档\n\n我们可以使用com.mongodb.client.MongoCollection类的 insertMany() 方法来插入一个文档\n\n代码片段如下：\n\n```text\n\nimport java.util.ArrayList;\nimport java.util.List;\nimport org.bson.Document;\n\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.MongoCollection;\nimport com.mongodb.client.MongoDatabase;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n         // 连接到 mongodb 服务\n         MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n         \n         // 连接到数据库\n         MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n         System.out.println("Connect to database successfully");\n         \n         MongoCollection<Document> collection = mongoDatabase.getCollection("test");\n         System.out.println("集合 test 选择成功");\n         //插入文档  \n         /** \n         * 1. 创建文档 org.bson.Document 参数为key-value的格式 \n         * 2. 创建文档集合List<Document> \n         * 3. 将文档集合插入数据库集合中 mongoCollection.insertMany(List<Document>) 插入单个文档可以用 mongoCollection.insertOne(Document) \n         * */\n         Document document = new Document("title", "MongoDB").  \n         append("description", "database").  \n         append("likes", 100).  \n         append("by", "Fly");  \n         List<Document> documents = new ArrayList<Document>();  \n         documents.add(document);  \n         collection.insertMany(documents);  \n         System.out.println("文档插入成功");  \n      }catch(Exception e){\n         System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n      }\n   }\n}\n\n```\n\n编译运行以上程序，输出结果如下:\n\n```text\n\nConnect to database successfully\n集合 test 选择成功\n文档插入成功\n```\n\n## 检索所有文档\n\n我们可以使用 com.mongodb.client.MongoCollection 类中的 find() 方法来获取集合中的所有文档。\n\n此方法返回一个游标，所以你需要遍历这个游标。\n\n代码片段如下：\n\n```text\n\nimport org.bson.Document;\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.FindIterable;\nimport com.mongodb.client.MongoCollection;\nimport com.mongodb.client.MongoCursor;\nimport com.mongodb.client.MongoDatabase;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n         // 连接到 mongodb 服务\n         MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n         \n         // 连接到数据库\n         MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n         System.out.println("Connect to database successfully");\n         \n         MongoCollection<Document> collection = mongoDatabase.getCollection("test");\n         System.out.println("集合 test 选择成功");\n         \n         //检索所有文档  \n         /** \n         * 1. 获取迭代器FindIterable<Document> \n         * 2. 获取游标MongoCursor<Document> \n         * 3. 通过游标遍历检索出的文档集合 \n         * */  \n         FindIterable<Document> findIterable = collection.find();  \n         MongoCursor<Document> mongoCursor = findIterable.iterator();  \n         while(mongoCursor.hasNext()){  \n            System.out.println(mongoCursor.next());  \n         }  \n      \n      }catch(Exception e){\n         System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n      }\n   }\n}\n```\n\n编译运行以上程序，输出结果如下:\n\n```text\n\nConnect to database successfully\n集合 test 选择成功\nDocument{{_id=56e65fb1fd57a86304fe2692, title=MongoDB, description=database, likes=100, by=Fly}}\n```\n\n## 更新文档\n\n你可以使用 com.mongodb.client.MongoCollection 类中的 updateMany() 方法来更新集合中的文档。\n\n代码片段如下：\n\n```text\n\nimport org.bson.Document;\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.FindIterable;\nimport com.mongodb.client.MongoCollection;\nimport com.mongodb.client.MongoCursor;\nimport com.mongodb.client.MongoDatabase;\nimport com.mongodb.client.model.Filters;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n         // 连接到 mongodb 服务\n         MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n         \n         // 连接到数据库\n         MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n         System.out.println("Connect to database successfully");\n         \n         MongoCollection<Document> collection = mongoDatabase.getCollection("test");\n         System.out.println("集合 test 选择成功");\n         \n         //更新文档   将文档中likes=100的文档修改为likes=200   \n         collection.updateMany(Filters.eq("likes", 100), new Document("$set",new Document("likes",200)));  \n         //检索查看结果  \n         FindIterable<Document> findIterable = collection.find();  \n         MongoCursor<Document> mongoCursor = findIterable.iterator();  \n         while(mongoCursor.hasNext()){  \n            System.out.println(mongoCursor.next());  \n         }  \n      \n      }catch(Exception e){\n         System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n      }\n   }\n}\n```\n\n编译运行以上程序，输出结果如下:\n\n```text\n\nConnect to database successfully\n集合 test 选择成功\nDocument{{_id=56e65fb1fd57a86304fe2692, title=MongoDB, description=database, likes=200, by=Fly}}\n```\n\n## 删除第一个文档\n\n要删除集合中的第一个文档，首先你需要使用com.mongodb.DBCollection类中的\n findOne()方法来获取第一个文档，然后使用remove 方法删除。\n\n代码片段如下：\n\n```text\n\nimport org.bson.Document;\nimport com.mongodb.MongoClient;\nimport com.mongodb.client.FindIterable;\nimport com.mongodb.client.MongoCollection;\nimport com.mongodb.client.MongoCursor;\nimport com.mongodb.client.MongoDatabase;\nimport com.mongodb.client.model.Filters;\n\npublic class MongoDBJDBC{\n   public static void main( String args[] ){\n      try{   \n         // 连接到 mongodb 服务\n         MongoClient mongoClient = new MongoClient( "localhost" , 27017 );\n\n         // 连接到数据库\n         MongoDatabase mongoDatabase = mongoClient.getDatabase("mycol");  \n         System.out.println("Connect to database successfully");\n\n         MongoCollection<Document> collection = mongoDatabase.getCollection("test");\n         System.out.println("集合 test 选择成功");\n\n         //删除符合条件的第一个文档  \n         collection.deleteOne(Filters.eq("likes", 200));  \n         //删除所有符合条件的文档  \n         collection.deleteMany (Filters.eq("likes", 200));  \n         //检索查看结果  \n         FindIterable<Document> findIterable = collection.find();  \n         MongoCursor<Document> mongoCursor = findIterable.iterator();  \n         while(mongoCursor.hasNext()){  \n           System.out.println(mongoCursor.next());  \n         }  \n           \n      }catch(Exception e){\n        System.err.println( e.getClass().getName() + ": " + e.getMessage() );\n     }\n   }\n}\n```\n\n编译运行以上程序，输出结果如下:\n\n```text\n\nConnect to database successfully\n集合 test 选择成功\n```\n\n更多操作可以参考：[http://mongodb.github.io/mongo-java-driver/3.0/driver/getting-started/quick-tour/](http://mongodb.github.io/mongo-java-driver/3.0/driver/getting-started/quick-tour/)\n\n参考文档：http://blog.csdn.net/ererfei/article/details/50857103\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-java.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-java','MongoDB Java - MongoDB 教程','在 Java 程序中如果要使用 MongoDB，你需要确保已经安装了 Java 环境及 MongoDB JDBC 驱动。 本章节实例适合 Mongo 3.x 以上版本。 你可以参考本站的Java教程https://www.runoob.co...',0,'PUBLISHED',6336,276,185,36,'2025-07-28 00:00:00','2025-07-28 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631028,1,'MongoDB PHP','在php中使用mongodb你必须使用 mongodb 的 php驱动。 MongoDB PHP在各平台上的安装及驱动包下载请查看:/mongodb/mongodb-install-php-driver.htmlhttps://www.runoob.com/mongodb/mongodb-install-php-driver.htmlPHP安装MongoDB扩展驱动 如果你使用的是 PHP7，请参阅：PHP7 MongoDB 安装与使用https://www.runoob.com/mongodb/php7-mongdb-tutorial.html。 为了确保正确连接，你需要指定数据库名，如果数...','# MongoDB PHP\n\n在php中使用mongodb你必须使用 mongodb 的 php驱动。\n\nMongoDB PHP在各平台上的安装及驱动包下载请查看:[/mongodb/mongodb-install-php-driver.html](https://www.runoob.com/mongodb/mongodb-install-php-driver.html)PHP安装MongoDB扩展驱动\n\n如果你使用的是 PHP7，请参阅：[PHP7 MongoDB 安装与使用](https://www.runoob.com/mongodb/php7-mongdb-tutorial.html)。\n\n## 确保连接及选择一个数据库\n\n为了确保正确连接，你需要指定数据库名，如果数据库在mongoDB中不存在，mongoDB会自动创建\n\n代码片段如下：\n\n```text\n\n<?php\n$m = new MongoClient(); // 连接默认主机和端口为：mongodb://localhost:27017\n$db = $m->test; // 获取名称为 "test" 的数据库\n?>\n```\n\n## 创建集合\n\n创建集合的代码片段如下：\n\n```text\n\n<?php\n$m = new MongoClient(); // 连接\n$db = $m->test; // 获取名称为 "test" 的数据库\n$collection = $db->createCollection("runoob");\necho "集合创建成功";\n?>\n```\n\n执行以上程序，输出结果如下：\n\n```text\n\n集合创建成功\n```\n\n## 插入文档\n\n在mongoDB中使用 insert() 方法插入文档：\n\n插入文档代码片段如下：\n\n```text\n\n<?php\n$m = new MongoClient();    // 连接到mongodb\n$db = $m->test;            // 选择一个数据库\n$collection = $db->runoob; // 选择集合\n$document = array( \n    "title" => "MongoDB", \n    "description" => "database", \n    "likes" => 100,\n    "url" => "http://www.runoob.com/mongodb/",\n    "by", "菜鸟教程"\n);\n$collection->insert($document);\necho "数据插入成功";\n?>\n```\n\n执行以上程序，输出结果如下：\n\n```text\n\n数据插入成功\n```\n\n然后我们在 mongo 客户端使用 db.runoob.find().pretty(); 命令查看数据：\n\n![图片](/api/uploads/files/runoob/mongodb/D1BA0B68-F33C-4597-AAEC-DF3F09BD0C0E-d964597870.jpg)\n\n## 查找文档\n\n使用find() 方法来读取集合中的文档。\n\n读取使用文档的代码片段如下：\n\n```text\n\n<?php\n$m = new MongoClient();    // 连接到mongodb\n$db = $m->test;            // 选择一个数据库\n$collection = $db->runoob; // 选择集合\n\n$cursor = $collection->find();\n// 迭代显示文档标题\nforeach ($cursor as $document) {\n    echo $document["title"] . "\\n";\n}\n?>\n```\n\n执行以上程序，输出结果如下：\n\n```text\n\nMongoDB\n```\n\n## 更新文档\n\n使用 update() 方法来更新文档。\n\n以下实例将更新文档中的标题为\' MongoDB 教程\'， 代码片段如下：\n\n```text\n\n<pre>\n<?php\n$m = new MongoClient();    // 连接到mongodb\n$db = $m->test;            // 选择一个数据库\n$collection = $db->runoob; // 选择集合\n// 更新文档\n$collection->update(array("title"=>"MongoDB"), array(\'$set\'=>array("title"=>"MongoDB 教程")));\n// 显示更新后的文档\n$cursor = $collection->find();\n// 循环显示文档标题\nforeach ($cursor as $document) {\n    echo $document["title"] . "\\n";\n}\n?>\n```\n\n执行以上程序，输出结果如下：\n\n```text\n\nMongoDB 教程\n```\n\n然后我们在 mongo 客户端使用 db.runoob.find().pretty(); 命令查看数据：\n\n![图片](/api/uploads/files/runoob/mongodb/D1BA0B68-F33C-4597-AAEC-DF3F09BD0C0E-d964597870.jpg)\n\n## 删除文档\n\n使用  remove() 方法来删除文档。\n\n以下实例中我们将移除 \'title\' 为 \'MongoDB 教程\' 的一条数据记录。， 代码片段如下：\n\n```text\n\n<?php\n$m = new MongoClient();    // 连接到mongodb\n$db = $m->test;            // 选择一个数据库\n$collection = $db->runoob; // 选择集合\n   \n// 移除文档\n$collection->remove(array("title"=>"MongoDB 教程"), array("justOne" => true));\n\n// 显示可用文档数据\n$cursor = $collection->find();\nforeach ($cursor as $document) {\n    echo $document["title"] . "\\n";\n}\n?>\n```\n\n除了以上实例外，在php中你还可以使用findOne(), save(), limit(), skip(), sort()等方法来操作Mongodb数据库。\n\n更多的操作方法可以参考 Mongodb 核心类：[http://php.net/manual/zh/mongo.core.php](http://php.net/manual/zh/mongo.core.php)。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-php.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-php','MongoDB PHP - MongoDB 教程','在php中使用mongodb你必须使用 mongodb 的 php驱动。 MongoDB PHP在各平台上的安装及驱动包下载请查看:/mongodb/mongodb-install-php-driver.htmlhttps://www.ru...',0,'PUBLISHED',6473,283,190,37,'2025-07-29 00:00:00','2025-07-29 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631029,1,'MongoDB 关系','MongoDB 的关系表示多个文档之间在逻辑上的相互联系。 文档间可以通过嵌入和引用来建立联系。 MongoDB 中的关系可以是： 接下来我们来考虑下用户与用户地址的关系。','# MongoDB 关系\n\nMongoDB 的关系表示多个文档之间在逻辑上的相互联系。\n\n文档间可以通过嵌入和引用来建立联系。\n\nMongoDB 中的关系可以是：\n\n- 1:1 (1对1)\n- 1: N (1对多)\n- N: 1 (多对1)\n- N: N (多对多)\n\n接下来我们来考虑下用户与用户地址的关系。\n\n一个用户可以有多个地址，所以是一对多的关系。\n\n以下是 user 文档的简单结构：\n\n```text\n\n{\n   "_id":ObjectId("52ffc33cd85242f436000001"),\n   "name": "Tom Hanks",\n   "contact": "987654321",\n   "dob": "01-01-1991"\n}\n```\n\n以下是 address 文档的简单结构：\n\n```text\n\n{\n   "_id":ObjectId("52ffc4a5d85242602e000000"),\n   "building": "22 A, Indiana Apt",\n   "pincode": 123456,\n   "city": "Los Angeles",\n   "state": "California"\n} \n```\n\n## 嵌入式关系\n\n使用嵌入式方法，我们可以把用户地址嵌入到用户的文档中：\n\n```text\n\n{\n   "_id":ObjectId("52ffc33cd85242f436000001"),\n   "contact": "987654321",\n   "dob": "01-01-1991",\n   "name": "Tom Benzamin",\n   "address": [\n      {\n         "building": "22 A, Indiana Apt",\n         "pincode": 123456,\n         "city": "Los Angeles",\n         "state": "California"\n      },\n      {\n         "building": "170 A, Acropolis Apt",\n         "pincode": 456789,\n         "city": "Chicago",\n         "state": "Illinois"\n      }]\n} \n```\n\n以上数据保存在单一的文档中，可以比较容易的获取和维护数据。\n你可以这样查询用户的地址：\n\n```text\n\n>db.users.findOne({"name":"Tom Benzamin"},{"address":1})\n```\n\n注意：以上查询中 db 和 users 表示数据库和集合。\n\n这种数据结构的缺点是，如果用户和用户地址在不断增加，数据量不断变大，会影响读写性能。\n\n## 引用式关系\n\n引用式关系是设计数据库时经常用到的方法，这种方法把用户数据文档和用户地址数据文档分开，通过引用文档的 id 字段来建立关系。\n\n```text\n\n{\n   "_id":ObjectId("52ffc33cd85242f436000001"),\n   "contact": "987654321",\n   "dob": "01-01-1991",\n   "name": "Tom Benzamin",\n   "address_ids": [\n      ObjectId("52ffc4a5d85242602e000000"),\n      ObjectId("52ffc4a5d85242602e000001")\n   ]\n}\n```\n\n以上实例中，用户文档的 address_ids 字段包含用户地址的对象id（ObjectId）数组。\n\n我们可以读取这些用户地址的对象id（ObjectId）来获取用户的详细地址信息。\n\n这种方法需要两次查询，第一次查询用户地址的对象id（ObjectId），第二次通过查询的id获取用户的详细地址信息。\n\n```text\n\n>var result = db.users.findOne({"name":"Tom Benzamin"},{"address_ids":1})\n>var addresses = db.address.find({"_id":{"$in":result["address_ids"]}})\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-relationships.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-relationships','MongoDB 关系 - MongoDB 教程','MongoDB 的关系表示多个文档之间在逻辑上的相互联系。 文档间可以通过嵌入和引用来建立联系。 MongoDB 中的关系可以是： 接下来我们来考虑下用户与用户地址的关系。',0,'PUBLISHED',6610,290,195,38,'2025-07-30 00:00:00','2025-07-30 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631030,1,'MongoDB 数据库引用','在上一章节MongoDB关系中我们提到了MongoDB的引用来规范数据结构文档。 MongoDB 引用有两种： 考虑这样的一个场景，我们在不同的集合中 addresshome, addressoffice, addressmailing, 等存储不同的地址（住址，办公室地址，邮件地址等）。 这样，我们在调用不同地址时，也需要指定集合，一个文档从多个集合引用文档，我们应该使用 DBRefs。','# MongoDB 数据库引用\n\n在上一章节MongoDB关系中我们提到了MongoDB的引用来规范数据结构文档。\n\nMongoDB 引用有两种：\n\n- 手动引用（Manual References）\n- DBRefs\n\n## DBRefs vs 手动引用\n\n考虑这样的一个场景，我们在不同的集合中 (address_home, address_office, address_mailing, 等)存储不同的地址（住址，办公室地址，邮件地址等）。\n\n这样，我们在调用不同地址时，也需要指定集合，一个文档从多个集合引用文档，我们应该使用 DBRefs。\n\n## 使用 DBRefs\n\nDBRef的形式：\n\n```text\n\n{ $ref : , $id : , $db :  }\n```\n\n三个字段表示的意义为：\n\n- $ref：集合名称\n- $id：引用的id\n- $db:数据库名称，可选参数\n-\n\n以下实例中用户数据文档使用了 DBRef, 字段 address：\n\n```text\n\n{\n   "_id":ObjectId("53402597d852426020000002"),\n   "address": {\n   "$ref": "address_home",\n   "$id": ObjectId("534009e4d852427820000002"),\n   "$db": "runoob"},\n   "contact": "987654321",\n   "dob": "01-01-1991",\n   "name": "Tom Benzamin"\n}\n```\n\naddress DBRef 字段指定了引用的地址文档是在 runoob 数据库下的 address_home 集合，id 为 534009e4d852427820000002。\n\n以下代码中，我们通过指定  $ref 参数（address_home 集合）来查找集合中指定id的用户地址信息：\n\n```text\n\n>var user = db.users.findOne({"name":"Tom Benzamin"})\n>var dbRef = user.address\n>db[dbRef.$ref].findOne({"_id":(dbRef.$id)})\n```\n\n以上实例返回了 address_home 集合中的地址数据：\n\n```text\n\n{\n   "_id" : ObjectId("534009e4d852427820000002"),\n   "building" : "22 A, Indiana Apt",\n   "pincode" : 123456,\n   "city" : "Los Angeles",\n   "state" : "California"\n}\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-database-references.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-database-references','MongoDB 数据库引用 - MongoDB 教程','在上一章节MongoDB关系中我们提到了MongoDB的引用来规范数据结构文档。 MongoDB 引用有两种： 考虑这样的一个场景，我们在不同的集合中 addresshome, addressoffice, addressmailing, ...',0,'PUBLISHED',6747,297,200,39,'2025-07-31 00:00:00','2025-07-31 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631031,1,'MongoDB 覆盖索引查询','官方的MongoDB的文档中说明，覆盖查询是以下的查询： 由于所有出现在查询中的字段是索引的一部分， MongoDB 无需在整个数据文档中检索匹配查询条件和返回使用相同索引的查询结果。 因为索引存在于RAM中，从索引中获取数据比通过扫描文档读取数据要快得多。','# MongoDB 覆盖索引查询\n\n官方的MongoDB的文档中说明，覆盖查询是以下的查询：\n\n- 所有的查询字段是索引的一部分\n- 所有的查询返回字段在同一个索引中\n\n由于所有出现在查询中的字段是索引的一部分，\nMongoDB 无需在整个数据文档中检索匹配查询条件和返回使用相同索引的查询结果。\n\n因为索引存在于RAM中，从索引中获取数据比通过扫描文档读取数据要快得多。\n\n## 使用覆盖索引查询\n\n为了测试覆盖索引查询，使用以下 users 集合:\n\n```text\n\n{\n   "_id": ObjectId("53402597d852426020000002"),\n   "contact": "987654321",\n   "dob": "01-01-1991",\n   "gender": "M",\n   "name": "Tom Benzamin",\n   "user_name": "tombenzamin"\n}\n```\n\n我们在 users 集合中创建联合索引，字段为  gender 和 user_name :\n\n```text\n\n>db.users.createIndex({gender:1,user_name:1})\n```\n\n注：5.0 之前版本可以使用 db.collection.ensureIndex() ，但 ensureIndex() 在 5.0 版本后已被移除，使用 createIndex() 代替。\n\n现在，该索引会覆盖以下查询：\n\n```text\n\n>db.users.find({gender:"M"},{user_name:1,_id:0})\n```\n\n也就是说，对于上述查询，MongoDB的不会去数据库文件中查找。相反，它会从索引中提取数据，这是非常快速的数据查询。\n\n由于我们的索引中不包括 _id 字段，_id在查询中会默认返回，我们可以在MongoDB的查询结果集中排除它。\n\n下面的实例没有排除_id，查询就不会被覆盖：\n\n```text\n\n>db.users.find({gender:"M"},{user_name:1})\n```\n\n最后，如果是以下的查询，不能使用覆盖索引查询：\n\n- 所有索引字段是一个数组\n- 所有索引字段是一个子文档\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-covered-queries.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-covered-queries','MongoDB 覆盖索引查询 - MongoDB 教程','官方的MongoDB的文档中说明，覆盖查询是以下的查询： 由于所有出现在查询中的字段是索引的一部分， MongoDB 无需在整个数据文档中检索匹配查询条件和返回使用相同索引的查询结果。 因为索引存在于RAM中，从索引中获取数据比通过扫描文档...',0,'PUBLISHED',6884,304,205,40,'2025-08-01 00:00:00','2025-08-01 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631032,1,'MongoDB 查询分析','MongoDB 查询分析可以确保我们所建立的索引是否有效，是查询语句性能分析的重要工具。 MongoDB 查询分析常用函数有：explain 和 hint。 explain 操作提供了查询信息，使用索引及查询统计等。有利于我们对索引的优化。 接下来我们在 users  集合中创建 gender 和 username 的索引：','# MongoDB 查询分析\n\nMongoDB 查询分析可以确保我们所建立的索引是否有效，是查询语句性能分析的重要工具。\n\nMongoDB 查询分析常用函数有：explain() 和 hint()。\n\n## 使用 explain()\n\nexplain 操作提供了查询信息，使用索引及查询统计等。有利于我们对索引的优化。\n\n接下来我们在 users  集合中创建 gender 和 user_name 的索引：\n\n```text\n\n>db.users.ensureIndex({gender:1,user_name:1})\n```\n\n现在在查询语句中使用 explain ：\n\n```text\n\n>db.users.find({gender:"M"},{user_name:1,_id:0}).explain()\n```\n\n以上的 explain()  查询返回如下结果：\n\n```text\n\n{\n   "cursor" : "BtreeCursor gender_1_user_name_1",\n   "isMultiKey" : false,\n   "n" : 1,\n   "nscannedObjects" : 0,\n   "nscanned" : 1,\n   "nscannedObjectsAllPlans" : 0,\n   "nscannedAllPlans" : 1,\n   "scanAndOrder" : false,\n   "indexOnly" : true,\n   "nYields" : 0,\n   "nChunkSkips" : 0,\n   "millis" : 0,\n   "indexBounds" : {\n      "gender" : [\n         [\n            "M",\n            "M"\n         ]\n      ],\n      "user_name" : [\n         [\n            {\n               "$minElement" : 1\n            },\n            {\n               "$maxElement" : 1\n            }\n         ]\n      ]\n   }\n}\n```\n\n现在，我们看看这个结果集的字段：\n\n- indexOnly: 字段为 true ，表示我们使用了索引。\n- cursor：因为这个查询使用了索引，MongoDB 中索引存储在B树结构中，所以这是也使用了 BtreeCursor 类型的游标。如果没有使用索引，游标的类型是 BasicCursor。这个键还会给出你所使用的索引的名称，你通过这个名称可以查看当前数据库下的system.indexes集合（系统自动创建，由于存储索引信息，这个稍微会提到）来得到索引的详细信息。\n- n：当前查询返回的文档数量。\n- nscanned/nscannedObjects：表明当前这次查询一共扫描了集合中多少个文档，我们的目的是，让这个数值和返回文档的数量越接近越好。\n- millis：当前查询所需时间，毫秒数。\n- indexBounds：当前查询具体使用的索引。\n\n## 使用 hint()\n\n虽然MongoDB查询优化器一般工作的很不错，但是也可以使用 hint 来强制 MongoDB 使用一个指定的索引。\n\n这种方法某些情形下会提升性能。 一个有索引的 collection 并且执行一个多字段的查询(一些字段已经索引了)。\n\n如下查询实例指定了使用 gender  和 user_name  索引字段来查询：\n\n```text\n\n>db.users.find({gender:"M"},{user_name:1,_id:0}).hint({gender:1,user_name:1})\n```\n\n可以使用 explain() 函数来分析以上查询：\n\n```text\n\n>db.users.find({gender:"M"},{user_name:1,_id:0}).hint({gender:1,user_name:1}).explain()\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-analyzing-queries.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-analyzing-queries','MongoDB 查询分析 - MongoDB 教程','MongoDB 查询分析可以确保我们所建立的索引是否有效，是查询语句性能分析的重要工具。 MongoDB 查询分析常用函数有：explain 和 hint。 explain 操作提供了查询信息，使用索引及查询统计等。有利于我们对索引的优化。...',0,'PUBLISHED',7021,311,210,41,'2025-08-02 00:00:00','2025-08-02 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631033,1,'MongoDB 原子操作','mongodb不支持事务，所以，在你的项目中应用时，要注意这点。无论什么设计，都不要要求mongodb保证数据的完整性。 但是mongodb提供了许多原子操作，比如文档的保存，修改，删除等，都是原子操作。 所谓原子操作就是要么这个文档保存到Mongodb，要么没有保存到Mongodb，不会出现查询到的文档没有保存完整的情况。 考虑下面的例子，图书馆的书籍及结账信息。','# MongoDB 原子操作\n\nmongodb不支持事务，所以，在你的项目中应用时，要注意这点。无论什么设计，都不要要求mongodb保证数据的完整性。\n\n但是mongodb提供了许多原子操作，比如文档的保存，修改，删除等，都是原子操作。\n\n所谓原子操作就是要么这个文档保存到Mongodb，要么没有保存到Mongodb，不会出现查询到的文档没有保存完整的情况。\n\n## 原子操作数据模型\n\n考虑下面的例子，图书馆的书籍及结账信息。\n\n实例说明了在一个相同的文档中如何确保嵌入字段关联原子操作（update：更新）的字段是同步的。\n\n```text\n\nbook = {\n          _id: 123456789,\n          title: "MongoDB: The Definitive Guide",\n          author: [ "Kristina Chodorow", "Mike Dirolf" ],\n          published_date: ISODate("2010-09-24"),\n          pages: 216,\n          language: "English",\n          publisher_id: "oreilly",\n          available: 3,\n          checkout: [ { by: "joe", date: ISODate("2012-10-15") } ]\n        }\n```\n\n你可以使用  db.collection.findAndModify() 方法来判断书籍是否可结算并更新新的结算信息。\n\n在同一个文档中嵌入的 available  和 checkout 字段来确保这些字段是同步更新的:\n\n```text\n\ndb.books.findAndModify ( {\n   query: {\n            _id: 123456789,\n            available: { $gt: 0 }\n          },\n   update: {\n             $inc: { available: -1 },\n             $push: { checkout: { by: "abc", date: new Date() } }\n           }\n} )\n```\n\n## 原子操作常用命令\n\n#### $set\n\n用来指定一个键并更新键值，若键不存在并创建。\n\n```text\n{ $set : { field : value } }\n```\n\n#### $unset\n\n用来删除一个键。\n\n```text\n{ $unset : { field : 1} }\n```\n\n#### $inc\n\n$inc可以对文档的某个值为数字型（只能为满足要求的数字）的键进行增减的操作。\n\n```text\n{ $inc : { field : value } }\n```\n\n#### $push\n\n用法：\n\n```text\n\n{ $push : { field : value } }\n```\n\n把value追加到field里面去，field一定要是数组类型才行，如果field不存在，会新增一个数组类型加进去。\n\n#### $pushAll\n\n同$push,只是一次可以追加多个值到一个数组字段内。\n\n```text\n{ $pushAll : { field : value_array } }\n```\n\n#### $pull\n\n从数组field内删除一个等于value值。\n\n```text\n{ $pull : { field : _value } }\n```\n\n#### $addToSet\n\n增加一个值到数组内，而且只有当这个值不在数组内才增加。\n\n#### $pop\n\n删除数组的第一个或最后一个元素\n\n```text\n{ $pop : { field : 1 } }\n```\n\n#### $rename\n\n修改字段名称\n\n```text\n{ $rename : { old_field_name : new_field_name } }\n```\n\n#### $bit\n\n位操作，integer类型\n\n```text\n{$bit : { field : {and : 5}}}\n```\n\n#### 偏移操作符\n\n```text\n\n> t.find() { "_id" : ObjectId("4b97e62bf1d8c7152c9ccb74"), "title" : "ABC", "comments" : [ { "by" : "joe", "votes" : 3 }, { "by" : "jane", "votes" : 7 } ] }\n \n> t.update( {\'comments.by\':\'joe\'}, {$inc:{\'comments.$.votes\':1}}, false, true )\n \n> t.find() { "_id" : ObjectId("4b97e62bf1d8c7152c9ccb74"), "title" : "ABC", "comments" : [ { "by" : "joe", "votes" : 4 }, { "by" : "jane", "votes" : 7 } ] }\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-atomic-operations.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-atomic-operations','MongoDB 原子操作 - MongoDB 教程','mongodb不支持事务，所以，在你的项目中应用时，要注意这点。无论什么设计，都不要要求mongodb保证数据的完整性。 但是mongodb提供了许多原子操作，比如文档的保存，修改，删除等，都是原子操作。 所谓原子操作就是要么这个文档保存到...',0,'PUBLISHED',7158,318,215,42,'2025-08-03 00:00:00','2025-08-03 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631034,1,'MongoDB 高级索引','考虑以下文档集合（users ）: 以上文档包含了 address 子文档和 tags 数组。 假设我们基于标签来检索用户，为此我们需要对集合中的数组 tags 建立索引。 在数组中创建索引，需要对数组中的每个字段依次建立索引。所以在我们为数组 tags 创建索引时，会为 music、cricket、blogs三个值建立单独的索引。','# MongoDB 高级索引\n\n考虑以下文档集合（users ）:\n\n```text\n\n{\n   "address": {\n      "city": "Los Angeles",\n      "state": "California",\n      "pincode": "123"\n   },\n   "tags": [\n      "music",\n      "cricket",\n      "blogs"\n   ],\n   "name": "Tom Benzamin"\n}\n```\n\n以上文档包含了 address 子文档和 tags 数组。\n\n## 索引数组字段\n\n假设我们基于标签来检索用户，为此我们需要对集合中的数组 tags 建立索引。\n\n在数组中创建索引，需要对数组中的每个字段依次建立索引。所以在我们为数组 tags 创建索引时，会为 music、cricket、blogs三个值建立单独的索引。\n\n使用以下命令创建数组索引：\n\n```text\n\n>db.users.ensureIndex({"tags":1})\n```\n\n创建索引后，我们可以这样检索集合的 tags 字段：\n\n```text\n\n>db.users.find({tags:"cricket"})\n```\n\n为了验证我们使用使用了索引，可以使用 explain 命令：\n\n```text\n\n>db.users.find({tags:"cricket"}).explain()\n```\n\n以上命令执行结果中会显示 "cursor" : "BtreeCursor tags_1" ，则表示已经使用了索引。\n\n## 索引子文档字段\n\n假设我们需要通过city、state、pincode字段来检索文档，由于这些字段是子文档的字段，所以我们需要对子文档建立索引。\n\n为子文档的三个字段创建索引，命令如下：\n\n```text\n\n>db.users.ensureIndex({"address.city":1,"address.state":1,"address.pincode":1})\n```\n\n一旦创建索引，我们可以使用子文档的字段来检索数据：\n\n```text\n\n>db.users.find({"address.city":"Los Angeles"})   \n```\n\n查询表达不一定遵循指定的索引的顺序，mongodb 会自动优化。所以上面创建的索引将支持以下查询：\n\n```text\n\n>db.users.find({"address.state":"California","address.city":"Los Angeles"}) \n```\n\n同样支持以下查询：\n\n```text\n\n>db.users.find({"address.city":"Los Angeles","address.state":"California","address.pincode":"123"})\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-advanced-indexing.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-advanced-indexing','MongoDB 高级索引 - MongoDB 教程','考虑以下文档集合（users ）: 以上文档包含了 address 子文档和 tags 数组。 假设我们基于标签来检索用户，为此我们需要对集合中的数组 tags 建立索引。 在数组中创建索引，需要对数组中的每个字段依次建立索引。所以在我们为...',0,'PUBLISHED',7295,325,220,43,'2025-08-04 00:00:00','2025-08-04 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631035,1,'MongoDB 索引限制','每个索引占据一定的存储空间，在进行插入，更新和删除操作时也需要对索引进行操作。所以，如果你很少对集合进行读取操作，建议不使用索引。 由于索引是存储在内存RAM中,你应该确保该索引的大小不超过内存的限制。 如果索引的大小大于内存的限制，MongoDB会删除一些索引，这将导致性能下降。 索引不能被以下的查询使用：','# MongoDB 索引限制\n\n## 额外开销\n\n每个索引占据一定的存储空间，在进行插入，更新和删除操作时也需要对索引进行操作。所以，如果你很少对集合进行读取操作，建议不使用索引。\n\n## 内存(RAM)使用\n\n由于索引是存储在内存(RAM)中,你应该确保该索引的大小不超过内存的限制。\n\n如果索引的大小大于内存的限制，MongoDB会删除一些索引，这将导致性能下降。\n\n## 查询限制\n\n索引不能被以下的查询使用：\n\n- 正则表达式及非操作符，如 $nin, $not, 等。\n- 算术运算符，如 $mod, 等。\n- $where 子句\n\n所以，检测你的语句是否使用索引是一个好的习惯，可以用explain来查看。\n\n## 索引键限制\n\n从2.6版本开始，如果现有的索引字段的值超过索引键的限制，MongoDB中不会创建索引。\n\n## 插入文档超过索引键限制\n\n如果文档的索引字段值超过了索引键的限制，MongoDB不会将任何文档转换成索引的集合。与mongorestore和mongoimport工具类似。\n\n## 最大范围\n\n- 集合中索引不能超过64个\n- 索引名的长度不能超过128个字符\n- 一个复合索引最多可以有31个字段\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-indexing-limitations.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-indexing-limitations','MongoDB 索引限制 - MongoDB 教程','每个索引占据一定的存储空间，在进行插入，更新和删除操作时也需要对索引进行操作。所以，如果你很少对集合进行读取操作，建议不使用索引。 由于索引是存储在内存RAM中,你应该确保该索引的大小不超过内存的限制。 如果索引的大小大于内存的限制，Mon...',0,'PUBLISHED',7432,332,225,44,'2025-08-05 00:00:00','2025-08-05 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631036,1,'MongoDB ObjectId','在前面几个章节中我们已经使用了MongoDB 的对象 IdObjectId。 在本章节中，我们将了解的ObjectId的结构。 ObjectId 是一个12字节 BSON  类型数据，有以下格式： MongoDB中存储的文档必须有一个"id"键。这个键的值可以是任何类型的，默认是个ObjectId对象。','# MongoDB ObjectId\n\n在前面几个章节中我们已经使用了MongoDB 的对象 Id(ObjectId)。\n\n在本章节中，我们将了解的ObjectId的结构。\n\nObjectId 是一个12字节 BSON  类型数据，有以下格式：\n\n- 前4个字节表示时间戳\n- 接下来的3个字节是机器标识码\n- 紧接的两个字节由进程id组成（PID）\n- 最后三个字节是随机数。\n\nMongoDB中存储的文档必须有一个"_id"键。这个键的值可以是任何类型的，默认是个ObjectId对象。\n\n在一个集合里面，每个文档都有唯一的"_id"值，来确保集合里面每个文档都能被唯一标识。\n\nMongoDB采用ObjectId，而不是其他比较常规的做法（比如自动增加的主键）的主要原因，因为在多个\n服务器上同步自动增加主键值既费力还费时。\n\n## 创建新的ObjectId\n\n使用以下代码生成新的ObjectId：\n\n```text\n\n>newObjectId = ObjectId()\n```\n\n上面的语句返回以下唯一生成的id：\n\n```text\n\nObjectId("5349b4ddd2781d08c09890f3")\n```\n\n你也可以使用生成的id来取代MongoDB自动生成的ObjectId：\n\n```text\n\n>myObjectId = ObjectId("5349b4ddd2781d08c09890f4")\n```\n\n## 创建文档的时间戳\n\n由于 ObjectId 中存储了 4 个字节的时间戳，所以你不需要为你的文档保存时间戳字段，你可以通过 getTimestamp  函数来获取文档的创建时间:\n\n```text\n\n>ObjectId("5349b4ddd2781d08c09890f4").getTimestamp()\n```\n\n以上代码将返回 ISO 格式的文档创建时间：\n\n```text\n\nISODate("2014-04-12T21:49:17Z")\n```\n\n## ObjectId 转换为字符串\n\n在某些情况下，您可能需要将ObjectId转换为字符串格式。你可以使用下面的代码：\n\n```text\n\n>new ObjectId().str\n```\n\n以上代码将返回Guid格式的字符串：：\n\n```text\n\n5349b4ddd2781d08c09890f3\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-objectid.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-objectid','MongoDB ObjectId - MongoDB 教程','在前面几个章节中我们已经使用了MongoDB 的对象 IdObjectId。 在本章节中，我们将了解的ObjectId的结构。 ObjectId 是一个12字节 BSON  类型数据，有以下格式： MongoDB中存储的文档必须有一个"id...',0,'PUBLISHED',7569,339,230,45,'2025-08-06 00:00:00','2025-08-06 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631037,1,'MongoDB Map Reduce','Map-Reduce是一种计算模型，简单的说就是将大批量的工作（数据）分解（MAP）执行，然后再将结果合并成最终结果（REDUCE）。 MongoDB提供的Map-Reduce非常灵活，对于大规模数据分析也相当实用。 以下是MapReduce的基本语法： 使用 MapReduce 要实现两个函数 Map 函数和 Reduce 函数,Map 函数调用 emitkey, value,','# MongoDB Map Reduce\n\nMap-Reduce是一种计算模型，简单的说就是将大批量的工作（数据）分解（MAP）执行，然后再将结果合并成最终结果（REDUCE）。\n\nMongoDB提供的Map-Reduce非常灵活，对于大规模数据分析也相当实用。\n\n### MapReduce 命令\n\n以下是MapReduce的基本语法：\n\n```text\n\n>db.collection.mapReduce(\n   function() {emit(key,value);},  //map 函数\n   function(key,values) {return reduceFunction},   //reduce 函数\n   {\n      out: collection,\n      query: document,\n      sort: document,\n      limit: number\n   }\n)\n```\n\n使用 MapReduce 要实现两个函数 Map 函数和 Reduce 函数,Map 函数调用 emit(key, value),\n遍历 collection 中所有的记录, 将 key 与 value 传递给 Reduce 函数进行处理。\n\nMap 函数必须调用 emit(key, value) 返回键值对。\n\n参数说明:\n\n- map ：映射函数 (生成键值对序列,作为 reduce 函数参数)。\n- reduce 统计函数，reduce函数的任务就是将key-values变成key-value，也就是把values数组变成一个单一的值value。。\n- out 统计结果存放集合 (不指定则使用临时集合,在客户端断开后自动删除)。\n- query 一个筛选条件，只有满足条件的文档才会调用map函数。（query。limit，sort可以随意组合）\n- sort 和limit结合的sort排序参数（也是在发往map函数前给文档排序），可以优化分组机制\n- limit 发往map函数的文档数量的上限（要是没有limit，单独使用sort的用处不大）\n\n以下实例在集合 orders 中查找 status:"A" 的数据，并根据 cust_id 来分组，并计算 amount 的总和。\n\n![图片](https://static.runoob.com/images/map-reduce.bakedsvg.svg)\n\n## 使用 MapReduce\n\n考虑以下文档结构存储用户的文章，文档存储了用户的 user_name 和文章的 status 字段：\n\n```text\n\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "mark",\n   "status":"active"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "mark",\n   "status":"active"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "mark",\n   "status":"active"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "mark",\n   "status":"active"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "mark",\n   "status":"disabled"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "runoob",\n   "status":"disabled"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "runoob",\n   "status":"disabled"\n})\nWriteResult({ "nInserted" : 1 })\n>db.posts.insert({\n   "post_text": "菜鸟教程，最全的技术文档。",\n   "user_name": "runoob",\n   "status":"active"\n})\nWriteResult({ "nInserted" : 1 })\n```\n\n现在，我们将在 posts 集合中使用 mapReduce 函数来选取已发布的文章(status:"active")，并通过user_name分组，计算每个用户的文章数：\n\n```text\n\n>db.posts.mapReduce( \n   function() { emit(this.user_name,1); }, \n   function(key, values) {return Array.sum(values)}, \n      {  \n         query:{status:"active"},  \n         out:"post_total" \n      }\n)\n```\n\n以上 mapReduce 输出结果为：\n\n```text\n\n{\n        "result" : "post_total",\n        "timeMillis" : 23,\n        "counts" : {\n                "input" : 5,\n                "emit" : 5,\n                "reduce" : 1,\n                "output" : 2\n        },\n        "ok" : 1\n}\n```\n\n结果表明，共有 5 个符合查询条件（status:"active"）的文档，\n在map函数中生成了 5 个键值对文档，最后使用reduce函数将相同的键值分为 2 组。\n\n具体参数说明：\n\n- result：储存结果的collection的名字,这是个临时集合，MapReduce的连接关闭后自动就被删除了。\n- timeMillis：执行花费的时间，毫秒为单位\n- input：满足条件被发送到map函数的文档个数\n- emit：在map函数中emit被调用的次数，也就是所有集合中的数据总量\n- output：结果集合中的文档个数（count对调试非常有帮助）\n- ok：是否成功，成功为1\n- err：如果失败，这里可以有失败原因，不过从经验上来看，原因比较模糊，作用不大\n\n使用 find 操作符来查看 mapReduce 的查询结果：\n\n```text\n\n> var map=function() { emit(this.user_name,1); }\n> var reduce=function(key, values) {return Array.sum(values)}\n> var options={query:{status:"active"},out:"post_total"}\n> db.posts.mapReduce(map,reduce,options)\n{ "result" : "post_total", "ok" : 1 }\n> db.post_total.find();\n```\n\n以上查询显示如下结果:\n\n```text\n\n{ "_id" : "mark", "value" : 4 }\n{ "_id" : "runoob", "value" : 1 }\n```\n\n用类似的方式，MapReduce可以被用来构建大型复杂的聚合查询。\n\nMap函数和Reduce函数可以使用 JavaScript 来实现，使得MapReduce的使用非常灵活和强大。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-map-reduce.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-map-reduce','MongoDB Map Reduce - MongoDB 教程','Map-Reduce是一种计算模型，简单的说就是将大批量的工作（数据）分解（MAP）执行，然后再将结果合并成最终结果（REDUCE）。 MongoDB提供的Map-Reduce非常灵活，对于大规模数据分析也相当实用。 以下是MapReduc...',0,'PUBLISHED',7706,346,235,46,'2025-08-07 00:00:00','2025-08-07 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631038,1,'MongoDB 全文检索','全文检索对每一个词建立一个索引，指明该词在文章中出现的次数和位置，当用户查询时，检索程序就根据事先建立的索引进行查找，并将查找的结果反馈给用户的检索方式。 这个过程类似于通过字典中的检索字表查字的过程。 MongoDB 从 2.4 版本开始支持全文检索，目前支持15种语言的全文索引。 MongoDB 在 2.6 版本以后是默认开启全文检索的，如果你使用之前的版本，你需要使用以下代码来启用全文检索:','# MongoDB 全文检索\n\n全文检索对每一个词建立一个索引，指明该词在文章中出现的次数和位置，当用户查询时，检索程序就根据事先建立的索引进行查找，并将查找的结果反馈给用户的检索方式。\n\n这个过程类似于通过字典中的检索字表查字的过程。\n\nMongoDB 从 2.4 版本开始支持全文检索，目前支持15种语言的全文索引。\n\n- danish\n- dutch\n- english\n- finnish\n- french\n- german\n- hungarian\n- italian\n- norwegian\n- portuguese\n- romanian\n- russian\n- spanish\n- swedish\n- turkish\n\n## 启用全文检索\n\nMongoDB 在 2.6 版本以后是默认开启全文检索的，如果你使用之前的版本，你需要使用以下代码来启用全文检索:\n\n```text\n\n>db.adminCommand({setParameter:true,textSearchEnabled:true})\n```\n\n或者使用命令：\n\n```text\n\nmongod --setParameter textSearchEnabled=true\n```\n\n## 创建全文索引\n\n考虑以下 posts 集合的文档数据，包含了文章内容（post_text）及标签(tags)：\n\n```text\n\n{\n   "post_text": "enjoy the mongodb articles on Runoob",\n   "tags": [\n      "mongodb",\n      "runoob"\n   ]\n}\n```\n\n我们可以对 post_text 字段建立全文索引，这样我们可以搜索文章内的内容：\n\n```text\n\n>db.posts.ensureIndex({post_text:"text"})\n```\n\n## 使用全文索引\n\n现在我们已经对 post_text 建立了全文索引，我们可以搜索文章中的关键词 runoob：\n\n```text\n\n>db.posts.find({$text:{$search:"runoob"}})\n```\n\n以下命令返回了如下包含 runoob 关键词的文档数据：\n\n```text\n\n{ \n   "_id" : ObjectId("53493d14d852429c10000002"), \n   "post_text" : "enjoy the mongodb articles on Runoob", \n   "tags" : [ "mongodb", "runoob" ]\n}\n```\n\n如果你使用的是旧版本的 MongoDB，你可以使用以下命令：\n\n```text\n\n>db.posts.runCommand("text",{search:"runoob"})\n```\n\n使用全文索引可以提高搜索效率。\n\n## 删除全文索引\n\n删除已存在的全文索引，可以使用 find 命令查找索引名：\n\n```text\n\n>db.posts.getIndexes()\n```\n\n通过以上命令获取索引名，本例的索引名为post_text_text，执行以下命令来删除索引：\n\n```text\n\n>db.posts.dropIndex("post_text_text")\n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-text-search.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-text-search','MongoDB 全文检索 - MongoDB 教程','全文检索对每一个词建立一个索引，指明该词在文章中出现的次数和位置，当用户查询时，检索程序就根据事先建立的索引进行查找，并将查找的结果反馈给用户的检索方式。 这个过程类似于通过字典中的检索字表查字的过程。 MongoDB 从 2.4 版本开始...',0,'PUBLISHED',7843,353,240,47,'2025-08-08 00:00:00','2025-08-08 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631039,1,'MongoDB 正则表达式','正则表达式是使用单个字符串来描述、匹配一系列符合某个句法规则的字符串。 许多程序设计语言都支持利用正则表达式进行字符串操作。 MongoDB 使用 $regex 操作符来设置匹配字符串的正则表达式。 MongoDB使用PCRE Perl Compatible Regular Expression 作为正则表达式语言。','# MongoDB 正则表达式\n\n正则表达式是使用单个字符串来描述、匹配一系列符合某个句法规则的字符串。\n\n许多程序设计语言都支持利用正则表达式进行字符串操作。\n\nMongoDB 使用 $regex 操作符来设置匹配字符串的正则表达式。\n\nMongoDB使用PCRE (Perl Compatible Regular Expression) 作为正则表达式语言。\n\n不同于全文检索，我们使用正则表达式不需要做任何配置。\n\n考虑以下 posts 集合的文档结构，该文档包含了文章内容和标签：\n\n```text\n\n{\n   "post_text": "enjoy the mongodb articles on runoob",\n   "tags": [\n      "mongodb",\n      "runoob"\n   ]\n}\n```\n\n## 使用正则表达式\n\n以下命令使用正则表达式查找包含 runoob 字符串的文章：\n\n```text\n\n>db.posts.find({post_text:{$regex:"runoob"}})\n```\n\n以上查询也可以写为：\n\n```text\n\n>db.posts.find({post_text:/runoob/})\n```\n\n## 不区分大小写的正则表达式\n\n如果检索需要不区分大小写，我们可以设置 $options 为 $i。\n\n以下命令将查找不区分大小写的字符串 runoob：\n\n```text\n\n>db.posts.find({post_text:{$regex:"runoob",$options:"$i"}})\n```\n\n集合中会返回所有包含字符串 runoob 的数据，且不区分大小写：\n\n```text\n\n{\n   "_id" : ObjectId("53493d37d852429c10000004"),\n   "post_text" : "hey! this is my post on  runoob", \n   "tags" : [ "runoob" ]\n} \n```\n\n## 数组元素使用正则表达式\n\n我们还可以在数组字段中使用正则表达式来查找内容。\n这在标签的实现上非常有用，如果你需要查找包含以 run 开头的标签数据(ru 或 run 或 runoob)，\n你可以使用以下代码：\n\n```text\n\n>db.posts.find({tags:{$regex:"run"}})\n```\n\n## 优化正则表达式查询\n\n- 如果你的文档中字段设置了索引，那么使用索引相比于正则表达式匹配查找所有的数据查询速度更快。\n- 如果正则表达式是前缀表达式，所有匹配的数据将以指定的前缀字符串为开始。例如：\n  如果正则表达式为  ^tut  ，查询语句将查找以 tut 为开头的字符串。\n\n这里面使用正则表达式有两点需要注意：\n\n正则表达式中使用变量。一定要使用eval将组合的字符串进行转换，不能直接将字符串拼接后传入给表达式。否则没有报错信息，只是结果为空！实例如下：\n\n```text\nvar name=eval("/" + 变量值key +"/i");\n```\n\n以下是模糊查询包含title关键词, 且不区分大小写:\n\n```text\n\ntitle:eval("/"+title+"/i")    // 等同于 title:{$regex:title,$Option:"$i"}   \n```\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-regular-expression.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-regular-expression','MongoDB 正则表达式 - MongoDB 教程','正则表达式是使用单个字符串来描述、匹配一系列符合某个句法规则的字符串。 许多程序设计语言都支持利用正则表达式进行字符串操作。 MongoDB 使用 $regex 操作符来设置匹配字符串的正则表达式。 MongoDB使用PCRE Perl C...',0,'PUBLISHED',7980,360,245,48,'2025-08-09 00:00:00','2025-08-09 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631040,1,'MongoDB 管理工具','RockMongo是PHP5写的一个MongoDB管理工具。 通过 Rockmongo 你可以管理 MongoDB服务，数据库，集合，文档，索引等等。 它提供了非常人性化的操作。类似 phpMyAdmin（PHP开发的MySql管理工具）。 Rockmongo 下载地址：https://github.com/iwind/rockmongohttps://github.com/iwind/rockmongo','# MongoDB 管理工具: Rockmongo\n\nRockMongo是PHP5写的一个MongoDB管理工具。\n\n通过 Rockmongo 你可以管理 MongoDB服务，数据库，集合，文档，索引等等。\n\n它提供了非常人性化的操作。类似 phpMyAdmin（PHP开发的MySql管理工具）。\n\nRockmongo 下载地址：[https://github.com/iwind/rockmongo](https://github.com/iwind/rockmongo)\n\n![图片](/api/uploads/files/runoob/mongodb/rockmongo-03d727496b.png)\n\n## 简介\n\n主要特征：\n\n- 使用宽松的[New BSD License](https://www.opensource.org/licenses/bsd-license.php)协议\n- 速度快，安装简单\n- 支持多语言（目前提供中文、英文、日文、巴西葡萄牙语、法语、德语、俄语、意大利语）\n- 系统\n  \n  - 可以配置多个主机，每个主机可以有多个管理员\n  - 需要管理员密码才能登入操作，确保数据库的安全性\n- 服务器\n  \n  - 服务器信息 (WEB服务器, PHP, PHP.ini相关指令 ...)\n  - 状态\n  - 数据库信息\n- 数据库\n  \n  - 查询，创建和删除\n  - 执行命令和Javascript代码\n  - 统计信息\n- 集合（相当于表）\n  \n  - 强大的查询工具\n  - 读数据，写数据，更改数据，复制数据，删除数据\n  - 查询、创建和删除索引\n  - 清空数据\n  - 批量删除和更改数据\n  - 统计信息\n- GridFS\n  \n  - 查看分块\n  - 下载文件\n\n## 安装\n\n### 需求\n\n- 一个能运行PHP的Web服务器，比如Apache Httpd, Nginx ...\n- PHP - 需要PHP v5.1.6或更高版本，需要支持SESSION\n  \n  - 为了能连接MongoDB，你需要安装[php_mongo](https://www.runoob.com/mongodb/mongodb-install-php-driver.html)扩展\n\n### 快速安装\n\n- [下载安装包](https://github.com/iwind/rockmongo)\n- 解压到你的网站目录下\n- 用编辑器打开config.php，修改host, port, admins等参数\n- 在浏览器中访问index.php，比如说：http://localhost/rockmongo/index.php\n- 使用用户名和密码登录，默认为"admin"和"admin"\n- 开始玩转MongoDB!\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/working-with-rockmongo.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-working-with-rockmongo','MongoDB 管理工具 - MongoDB 教程','RockMongo是PHP5写的一个MongoDB管理工具。 通过 Rockmongo 你可以管理 MongoDB服务，数据库，集合，文档，索引等等。 它提供了非常人性化的操作。类似 phpMyAdmin（PHP开发的MySql管理工具）。...',0,'PUBLISHED',8117,367,250,49,'2025-08-10 00:00:00','2025-08-10 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631041,1,'MongoDB GridFS','GridFS 用于存储和恢复那些超过16M（BSON文件限制）的文件如：图片、音频、视频等。 GridFS 也是文件存储的一种方式，但是它是存储在MonoDB的集合中。 GridFS 可以更好的存储大于16M的文件。 GridFS 会将大文件对象分割成多个小的chunk文件片段,一般为256k/个,每个chunk将作为MongoDB的一个文档document被存储在chunks集合中。','# MongoDB GridFS\n\nGridFS 用于存储和恢复那些超过16M（BSON文件限制）的文件(如：图片、音频、视频等)。\n\nGridFS 也是文件存储的一种方式，但是它是存储在MonoDB的集合中。\n\nGridFS 可以更好的存储大于16M的文件。\n\nGridFS 会将大文件对象分割成多个小的chunk(文件片段),一般为256k/个,每个chunk将作为MongoDB的一个文档(document)被存储在chunks集合中。\n\nGridFS 用两个集合来存储一个文件：fs.files与fs.chunks。\n\n每个文件的实际内容被存在chunks(二进制数据)中,和文件有关的meta数据(filename,content_type,还有用户自定义的属性)将会被存在files集合中。\n\n以下是简单的  fs.files 集合文档：\n\n```text\n\n{\n   "filename": "test.txt",\n   "chunkSize": NumberInt(261120),\n   "uploadDate": ISODate("2014-04-13T11:32:33.557Z"),\n   "md5": "7b762939321e146569b07f72c62cca4f",\n   "length": NumberInt(646)\n}\n```\n\n以下是简单的 fs.chunks 集合文档：\n\n```text\n\n{\n   "files_id": ObjectId("534a75d19f54bfec8a2fe44b"),\n   "n": NumberInt(0),\n   "data": "Mongo Binary Data"\n}\n```\n\n## GridFS 添加文件\n\n现在我们使用 GridFS 的 put 命令来存储 mp3 文件。\n调用 MongoDB  安装目录下bin的 mongofiles.exe工具。\n\n打开命令提示符，进入到MongoDB的安装目录的bin目录中，找到mongofiles.exe，并输入下面的代码：\n\n```text\n\n>mongofiles.exe -d gridfs put song.mp3\n```\n\n-d gridfs 指定存储文件的数据库名称，如果不存在该数据库，MongoDB会自动创建。如果不存在该数据库，MongoDB会自动创建。Song.mp3 是音频文件名。\n\n使用以下命令来查看数据库中文件的文档：\n\n```text\n\n>db.fs.files.find()\n```\n\n以上命令执行后返回以下文档数据：\n\n```text\n\n{\n   _id: ObjectId(\'534a811bf8b4aa4d33fdf94d\'), \n   filename: "song.mp3", \n   chunkSize: 261120, \n   uploadDate: new Date(1397391643474), md5: "e4f53379c909f7bed2e9d631e15c1c41",\n   length: 10401959 \n}\n```\n\n我们可以看到  fs.chunks  集合中所有的区块，以下我们得到了文件的 _id 值，我们可以根据这个 _id 获取区块(chunk)的数据：\n\n```text\n\n>db.fs.chunks.find({files_id:ObjectId(\'534a811bf8b4aa4d33fdf94d\')})\n```\n\n以上实例中，查询返回了 40 个文档的数据，意味着mp3文件被存储在40个区块中。\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-gridfs.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-gridfs','MongoDB GridFS - MongoDB 教程','GridFS 用于存储和恢复那些超过16M（BSON文件限制）的文件如：图片、音频、视频等。 GridFS 也是文件存储的一种方式，但是它是存储在MonoDB的集合中。 GridFS 可以更好的存储大于16M的文件。 GridFS 会将大文...',0,'PUBLISHED',8254,374,255,50,'2025-08-11 00:00:00','2025-08-11 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631042,1,'MongoDB 固定集合','MongoDB 固定集合（Capped Collections）是性能出色且有着固定大小的集合，对于大小固定，我们可以想象其就像一个环形队列，当集合空间用完后，再插入的元素就会覆盖最初始的头部的元素！ 我们通过createCollection来创建一个固定集合，且capped选项设置为true： 还可以指定文档个数,加上max:1000属性： 判断集合是否为固定集合:','# MongoDB 固定集合（Capped Collections）\n\nMongoDB 固定集合（Capped Collections）是性能出色且有着固定大小的集合，对于大小固定，我们可以想象其就像一个环形队列，当集合空间用完后，再插入的元素就会覆盖最初始的头部的元素！\n\n## 创建固定集合\n\n我们通过createCollection来创建一个固定集合，且capped选项设置为true：\n\n```text\n\n>db.createCollection("cappedLogCollection",{capped:true,size:10000})\n```\n\n还可以指定文档个数,加上max:1000属性：\n\n```text\n\n>db.createCollection("cappedLogCollection",{capped:true,size:10000,max:1000})\n```\n\n判断集合是否为固定集合:\n\n```text\n\n>db.cappedLogCollection.isCapped()\n```\n\n如果需要将已存在的集合转换为固定集合可以使用以下命令：\n\n```text\n\n>db.runCommand({"convertToCapped":"posts",size:10000})\n```\n\n以上代码将我们已存在的 posts 集合转换为固定集合。\n\n## 固定集合查询\n\n固定集合文档按照插入顺序储存的,默认情况下查询就是按照插入顺序返回的,也可以使用$natural调整返回顺序。\n\n```text\n\n>db.cappedLogCollection.find().sort({$natural:-1})\n```\n\n## 固定集合的功能特点\n\n可以插入及更新,但更新不能超出collection的大小,否则更新失败,不允许删除,但是可以调用drop()删除集合中的所有行,但是drop后需要显式地重建集合。\n\n在32位机子上一个cappped collection的最大值约为482.5M,64位上只受系统文件大小的限制。\n\n## 固定集合属性及用法\n\n### 属性\n\n- 属性1:对固定集合进行插入速度极快\n- 属性2:按照插入顺序的查询输出速度极快\n- 属性3:能够在插入最新数据时,淘汰最早的数据\n\n### 用法\n\n- 用法1:储存日志信息\n- 用法2:缓存一些少量的文档\n\n 其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-capped-collections.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-capped-collections','MongoDB 固定集合 - MongoDB 教程','MongoDB 固定集合（Capped Collections）是性能出色且有着固定大小的集合，对于大小固定，我们可以想象其就像一个环形队列，当集合空间用完后，再插入的元素就会覆盖最初始的头部的元素！ 我们通过createCollectio...',0,'PUBLISHED',8391,381,260,51,'2025-08-12 00:00:00','2025-08-12 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
INSERT INTO `blog_article` (`id`,`author_id`,`title`,`summary`,`content`,`cover_url`,`category`,`offline_reason`,`featured`,`featured_at`,`slug`,`seo_title`,`seo_description`,`warn_flag`,`status`,`view_count`,`like_count`,`favorite_count`,`comment_count`,`published_at`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES (631043,1,'MongoDB 自动增长','MongoDB 没有像 SQL 一样有自动增长的功能， MongoDB 的 id 是系统自动生成的12字节唯一标识。 但在某些情况下，我们可能需要实现 ObjectId 自动增长功能。 由于 MongoDB 没有实现这个功能，我们可以通过编程的方式来实现，以下我们将在','# MongoDB 自动增长\n\nMongoDB 没有像 SQL 一样有自动增长的功能，\nMongoDB 的 _id 是系统自动生成的12字节唯一标识。\n\n但在某些情况下，我们可能需要实现 ObjectId 自动增长功能。\n\n由于 MongoDB 没有实现这个功能，我们可以通过编程的方式来实现，以下我们将在\n counters 集合中实现_id字段自动增长。\n\n## 使用 counters 集合\n\n考虑以下 products 文档。我们希望 _id 字段实现\n从  1,2,3,4 到 n 的自动增长功能。\n\n```text\n\n{\n  "_id":1,\n  "product_name": "Apple iPhone",\n  "category": "mobiles"\n}\n```\n\n为此，创建 counters 集合，序列字段值可以实现自动长：\n\n```text\n\n>db.createCollection("counters")\n```\n\n现在我们向 counters 集合中插入以下文档，使用 productid 作为 key:\n\n```text\n\n{\n  "_id":"productid",\n  "sequence_value": 0\n}\n```\n\nsequence_value 字段是序列通过自动增长后的一个值。\n\n使用以下命令插入 counters 集合的序列文档中：\n\n```text\n\n>db.counters.insert({_id:"productid",sequence_value:0})\n```\n\n## 创建 Javascript 函数\n\n现在，我们创建函数 getNextSequenceValue  来作为序列名的输入，\n指定的序列会自动增长 1 并返回最新序列值。在本文的实例中序列名为 productid\n。\n\n```text\n\n>function getNextSequenceValue(sequenceName){\n   var sequenceDocument = db.counters.findAndModify(\n      {\n         query:{_id: sequenceName },\n         update: {$inc:{sequence_value:1}},\n         "new":true\n      });\n   return sequenceDocument.sequence_value;\n}\n```\n\n## 使用 Javascript 函数\n\n接下来我们将使用 getNextSequenceValue 函数创建一个新的文档，\n并设置文档 _id 自动为返回的序列值：\n\n```text\n\n>db.products.insert({\n   "_id":getNextSequenceValue("productid"),\n   "product_name":"Apple iPhone",\n   "category":"mobiles"})\n\n>db.products.insert({\n   "_id":getNextSequenceValue("productid"),\n   "product_name":"Samsung S3",\n   "category":"mobiles"})\n```\n\n就如你所看到的，我们使用 getNextSequenceValue 函数来设置 _id 字段。\n\n为了验证函数是否有效，我们可以使用以下命令读取文档：\n\n```text\n\n>db.products.find()\n```\n\n以上命令将返回以下结果，我们发现 _id 字段是自增长的：\n\n```text\n\n{ "_id" : 1, "product_name" : "Apple iPhone", "category" : "mobiles"}\n\n{ "_id" : 2, "product_name" : "Samsung S3", "category" : "mobiles" }\n```\n  其他扩展\n\n---\n\n原文链接：https://www.runoob.com/mongodb/mongodb-autoincrement-sequence.html\n','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800','MongoDB',NULL,0,NULL,'runoob-mongodb-mongodb-autoincrement-sequence','MongoDB 自动增长 - MongoDB 教程','MongoDB 没有像 SQL 一样有自动增长的功能， MongoDB 的 id 是系统自动生成的12字节唯一标识。 但在某些情况下，我们可能需要实现 ObjectId 自动增长功能。 由于 MongoDB 没有实现这个功能，我们可以通过编...',0,'PUBLISHED',8528,388,265,52,'2025-08-13 00:00:00','2025-08-13 00:00:00','2026-05-10 17:47:24',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
