SET NAMES utf8mb4;
USE `my_blog`;
START TRANSACTION;



UPDATE `blog_article_tag` SET `deleted_at`='2026-05-10 17:47:24',`updated_at`='2026-05-10 17:47:24' WHERE `article_id` IN (631000, 631001, 631002, 631003, 631004, 631005, 631006, 631007, 631008, 631009, 631010, 631011, 631012, 631013, 631014, 631015, 631016, 631017, 631018, 631019, 631020, 631021, 631022, 631023, 631024, 631025, 631026, 631027, 631028, 631029, 631030, 631031, 631032, 631033, 631034, 631035, 631036, 631037, 631038, 631039, 631040, 631041, 631042, 631043);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-10 17:47:24',`updated_at`='2026-05-10 17:47:24' WHERE `column_id`=9600012;
UPDATE `blog_topic_article` SET `deleted_at`='2026-05-10 17:47:24',`updated_at`='2026-05-10 17:47:24' WHERE `topic_id`=9700012;

UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg INNER JOIN `blog_article` a ON a.`id` = atg.`article_id` WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`name` IN ('MongoDB', '数据库', 'NoSQL', '文档数据库');
UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE c.`id` = 9600012;
UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`id` = 9700012;
COMMIT;
